INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Draconic Ember', 0, 'Evocation', '1 action', '120 feet', 'V, S, M (Fractured Aether-Core — Fire)', 'Instantaneous', 'You snap your fingers, tracing a spark-sigil. A mote of draconic flame bolts toward a creature within range. Make a ranged spell attack. On a hit, the target takes 1d10 fire damage. The flame ignites flammable objects not being worn or carried. The sigil drawn in the air resembles your bloodline''s ancestral crest, burning briefly before the ember launches.', 'The spell''s damage increases by 1d10 at 5th, 11th, and 17th level.', ARRAY['sorcerer', 'wizard', 'artificer', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'fire-bolt']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Caustic Spittle', 0, 'Conjuration', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Acid)', 'Instantaneous', 'You trace the sigil of the Venom-Dragon across your lips and spit a globule of caustic aether-bile. Choose one creature within range or two creatures within 5 feet of each other. Each target must succeed on a Dexterity saving throw or take 1d6 acid damage. The bile hisses and smokes where it lands, etching faint draconic runes into stone before fading.', 'The spell''s damage increases by 1d6 at 5th, 11th, and 17th level.', ARRAY['sorcerer', 'wizard', 'artificer', 'druid']::text[], ARRAY['solis-grave', 'srd-ref', 'acid-splash']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Iron-Scale Ward', 0, 'Abjuration', '1 action', 'Self', 'V, S, M (Fractured Aether-Core — Earth)', '1 round', 'You trace the sigil of the Iron Dragon across your own flesh, and the ghostly shimmer of draconic scales ripples over your skin. Until the end of your next turn, you have resistance against bludgeoning, piercing, and slashing damage dealt by weapon attacks. The sigil glows faintly beneath your skin, visible as faintly luminous scale patterns when struck.', NULL, ARRAY['sorcerer', 'wizard', 'warlock', 'cleric', 'bard', 'artificer', 'sovereign', 'fighter', 'rogue']::text[], ARRAY['solis-grave', 'srd-ref', 'blade-ward']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Grave-Cold Grasp', 0, 'Necromancy', '1 action', '120 feet', 'V, S, M (Fractured Aether-Core — Void)', '1 round', 'You utter a syllable of the Old Tongue reserved for the dead, and a spectral draconic claw of chill aether reaches from the underworld to clutch at a creature within range. Make a ranged spell attack. On a hit, the target takes 1d8 necrotic damage and cannot regain hit points until the start of your next turn. If the target is undead, it has disadvantage on attack rolls against you until the end of your next turn. The claw is bleached white, as though drained of all warmth by ages spent below.', 'The spell''s damage increases by 1d8 at 5th, 11th, and 17th level.', ARRAY['sorcerer', 'warlock', 'wizard', 'blood_hunter', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'chill-touch']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wyrm-Wisp', 0, 'Evocation', '1 action', '120 feet', 'V, S, M (Fractured Aether-Core — Fire or Wild)', 'Concentration, up to 1 minute', 'You trace four small wing-sigils in the air, and four faint draconic spirits manifest as floating flame-orbs. They resemble tiny hovering wyrms, each shedding dim light in a 10-foot radius. As a bonus action, you can command the wisps to drift up to 60 feet. Each wisp winks out if it passes beyond 120 feet from you. The wisps emit a soft, rhythmic hum that echo-channelers believe is the lullaby of a long-dead Star Dragon.', NULL, ARRAY['bard', 'sorcerer', 'wizard', 'druid']::text[], ARRAY['solis-grave', 'srd-ref', 'dancing-lights']::text[], FALSE, TRUE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wild-Blood Sign', 0, 'Transmutation', '1 action', '30 feet', 'V, S, M (Fractured Aether-Core — Wild)', 'Instantaneous', 'You whisper the Old Tongue names of the Primordial Dragons — those ancient wyrms who became the land itself — and nature responds with a minor sign. You create one of the following effects: a harmless sensory effect (the scent of petrichor, a distant draconic rumble), an instant lighting or snuffing of a small flame, a brief whisper of weather prediction for the next 24 hours, or the blooming or wilting of a small plant. The effect feels ancient and instinctual, as though the world''s blood remembers its creators.', NULL, ARRAY['druid', 'barbarian']::text[], ARRAY['solis-grave', 'srd-ref', 'druidcraft']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether Lance', 0, 'Evocation', '1 action', '120 feet', 'V, S, M (Fractured Aether-Core — Wild)', 'Instantaneous', 'You trace the sigil of the Void-Dragon and a beam of crackling aether energy erupts from your finger. The raw, untethered power of your bloodline — stripped of element, pure force of will — screams across the battlefield. Make a ranged spell attack. On a hit, the target takes 1d10 force damage. The beam''s color shifts between every hue of dragon breath known to the Old Tongue.', 'The spell creates more beams at higher levels: two beams at 5th level, three at 11th, and four at 17th. You can direct the beams at the same target or different ones. Make a separate attack roll for each beam.', ARRAY['warlock', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'eldritch-blast']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Bloodline Whisper', 0, 'Divination', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Wild)', 'Concentration, up to 1 minute', 'You touch a willing creature and speak a single word of ancestral encouragement in the Old Tongue. A faint echo of your draconic forebears offers a moment of precognitive insight. Once within the duration, the target can add 1d4 to one ability check of its choice. The whisper feels like a warm talon resting gently on the back of the mind — many casters describe it as hearing their grandmother''s voice.', NULL, ARRAY['cleric', 'druid', 'bard', 'artificer', 'sovereign', 'monk', 'barbarian']::text[], ARRAY['solis-grave', 'srd-ref', 'guidance']::text[], FALSE, TRUE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sovereign''s Glow', 0, 'Evocation', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Fire or Radiant)', '1 hour', 'You touch an object and trace the sigil of the Sun Dragon upon it. The object sheds bright aether-light in a 20-foot radius and dim light for an additional 20 feet. The light is the color of the caster''s bloodline flame — crimson, azure, pale gold, or void-black. Any creature within the bright light who conceals their bloodline feels an uncomfortable warmth, as if being watched. The spell ends if cast again or dismissed as an action.', NULL, ARRAY['bard', 'cleric', 'sorcerer', 'wizard', 'artificer', 'sovereign', 'monk']::text[], ARRAY['solis-grave', 'srd-ref', 'light']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Spectral Claw', 0, 'Conjuration', '1 action', '30 feet', 'V, S, M (Fractured Aether-Core — Wild)', '1 minute', 'You trace the sigil of a grasping talon, and a floating, semi-transparent draconic claw manifests at a point within range. The claw lasts for the duration and can be moved up to 30 feet as an action. It can manipulate objects, open unlocked doors, pour vials, or retrieve items — but cannot attack, activate magical items, or carry more than 10 pounds. The claw''s shape echoes your bloodline: crimson and hooked for fire lineages, pale and slender for rime, shadow-wreathed for void.', NULL, ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'artificer', 'rogue', 'fighter']::text[], ARRAY['solis-grave', 'srd-ref', 'mage-hand']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Scale-Knit', 0, 'Transmutation', '1 minute', 'Touch', 'V, S, M (Fractured Aether-Core — Earth)', 'Instantaneous', 'You trace the sigil of renewal — two linked crescents forming a scale pattern — upon a broken object. A single break or tear up to 1 foot in any dimension seals with a faint aetheric shimmer, as if the object''s own essence remembers wholeness. The repair leaves no scar, though discerning eyes can spot a faint optical distortion along the mend. In draconic legend, this sigil was gifted to mortals by the Gem-Dragon who first taught craft to the world.', NULL, ARRAY['bard', 'cleric', 'druid', 'sorcerer', 'wizard', 'artificer']::text[], ARRAY['solis-grave', 'srd-ref', 'mending']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Old-Tongue Whisper', 0, 'Transmutation', '1 action', '120 feet', 'V, S, M (Fractured Aether-Core — Wild)', '1 round', 'You point a finger at a creature within range while whispering Old Tongue syllables. Your words travel on aether currents, inaudible to all but the intended recipient. The target hears the message as a whisper inside their mind, spoken in the voice of a dragon — resonant, ancient, and impossible to ignore. The target can reply with a whisper you alone hear. The message cannot pass through solid stone thicker than 1 foot, and the spell is blocked by active Inquisitor wards.', NULL, ARRAY['bard', 'sorcerer', 'wizard', 'rogue', 'fighter']::text[], ARRAY['solis-grave', 'srd-ref', 'message']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Mirage', 0, 'Illusion', '1 action', '30 feet', 'V, S, M (Fractured Aether-Core — Wild)', '1 minute', 'You trace a shimmering sigil in the air, and a wisp of aether coalesces into a simple illusion — either a sound or an image of an object no larger than a 5-foot cube. The illusion is as fragile as heat-haze over a dragon''s lair: physical interaction reveals it immediately, and any creature that examines it closely recognizes the faint, ever-shifting iridescence of unshaped aether. The Old Tongue contains ninety-seven words for ''illusion'' — each reflecting a different draconic philosophy on the nature of reality.', NULL, ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'rogue', 'fighter']::text[], ARRAY['solis-grave', 'srd-ref', 'minor-illusion']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Venom-Breath Sigil', 0, 'Conjuration', '1 action', '10 feet', 'V, S, M (Fractured Aether-Core — Poison)', 'Instantaneous', 'You trace the crest of the Venom-Dragon across your throat and exhale. A puff of toxic aether-gas — thick as a wyrm''s dying breath — clouds toward a creature you can see within range. The target must succeed on a Constitution saving throw or take 1d12 poison damage. The cloud''s color betrays your bloodline: emerald for forest-dragons, violet for deep-dragons, bone-white for carrion lineages.', 'The spell''s damage increases by 1d12 at 5th, 11th, and 17th level.', ARRAY['druid', 'sorcerer', 'warlock', 'wizard', 'blood_hunter']::text[], ARRAY['solis-grave', 'srd-ref', 'poison-spray']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Lesser Sigil-Craft', 0, 'Transmutation', '1 action', '10 feet', 'V, S, M (Fractured Aether-Core — Wild)', 'Up to 1 hour', 'You trace a rapid series of minor sigils — the first tricks any bloodline-child learns. Choose one of the following effects: create a harmless sensory effect (sparks from your fingertips, a brief draconic chord); light or snuff a candle-sized flame; clean or soil an object no larger than 1 cubic foot; warm, chill, or flavor nonliving material; make a small mark, symbol, or bloodline crest appear on a surface for 1 hour; or conjure a small trinket that fits in your palm and lasts until the end of your next turn. Casters with higher purity find their Lesser Sigil-Craft effects more vivid — a 50%+ purity caster''s illusory crests pulse with actual heat.', NULL, ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'fighter', 'rogue']::text[], ARRAY['solis-grave', 'srd-ref', 'prestidigitation']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Fang-Fire', 0, 'Conjuration', '1 action', 'Self', 'V, S, M (Fractured Aether-Core — Fire)', '10 minutes', 'You cup your palm and trace a spark-sigil within it. A flickering draconic flame kindles in your hand — warm as a hatchling''s first breath. The flame sheds bright light in a 10-foot radius and dim light for an additional 10 feet. As an action, you can hurl the flame at a creature within 30 feet; make a ranged spell attack, dealing 1d8 fire damage on a hit. The flame extinguishes when thrown, but rekindles if you trace the sigil again. Wild-Bloods use this flame to light campfires by speaking the Fire-Dragon''s name into the kindling.', 'The spell''s thrown damage increases by 1d8 at 5th, 11th, and 17th level.', ARRAY['druid', 'barbarian']::text[], ARRAY['solis-grave', 'srd-ref', 'produce-flame']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Frost-Wyrm''s Gaze', 0, 'Evocation', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Cold)', 'Instantaneous', 'You fix your gaze on a creature and trace the sigil of the Rime-Dragon. A beam of freezing aether — cold as the stare of the White Wyrm who sleeps beneath the northern ice — streaks toward the target. Make a ranged spell attack. On a hit, the target takes 1d8 cold damage and its speed is reduced by 10 feet until the start of your next turn. The ground beneath the beam''s path momentarily frosts over with delicate, draconic-scale patterns.', 'The spell''s damage increases by 1d8 at 5th, 11th, and 17th level.', ARRAY['sorcerer', 'wizard', 'artificer', 'sovereign', 'fighter', 'rogue']::text[], ARRAY['solis-grave', 'srd-ref', 'ray-of-frost']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Scale-Steel Resolve', 0, 'Abjuration', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Earth)', 'Concentration, up to 1 minute', 'You trace the sigil of the Adamant Dragon upon a willing creature. Its bloodline briefly awakens, hardening the creature''s connection to the material plane. Once within the duration, the target can add 1d4 to one saving throw of its choice. The target''s skin momentarily takes on a faint metallic sheen when it draws on this reserve — the chromatic flash of a dragon''s underbelly glimpsed through water.', NULL, ARRAY['cleric', 'druid', 'barbarian', 'monk']::text[], ARRAY['solis-grave', 'srd-ref', 'resistance']::text[], FALSE, TRUE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon-God''s Gaze', 0, 'Evocation', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Radiant)', 'Instantaneous', 'You utter one of the ninety-nine Names of the Dragon-Gods, and a column of searing radiance descends as though one of them has turned its eye upon a sinner. A creature you can see within range must succeed on a Dexterity saving throw or take 1d8 radiant damage. The target gains no benefit from cover for this saving throw. The light is not fire — it is the absolute attention of divinity, and it burns only what it judges. Inquisitors recognize this spell by the eye-shaped afterimage it leaves on the ground.', 'The spell''s damage increases by 1d8 at 5th, 11th, and 17th level.', ARRAY['cleric', 'sovereign', 'monk']::text[], ARRAY['solis-grave', 'srd-ref', 'sacred-flame']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Fang-Staff', 0, 'Transmutation', '1 bonus action', 'Touch', 'V, S, M (Fractured Aether-Core — Earth or Wild)', '1 minute', 'You trace the sigil of the Primal Fang upon a wooden club or quarterstaff. The wood hardens with draconic essence — the weapon becomes magical, and you can use your spellcasting ability modifier instead of Strength for attack and damage rolls. On a hit, the weapon deals 1d8 bludgeoning damage (becoming a d8 if smaller). The wood darkens, its grain shifting into a pattern reminiscent of dragonbone. Druids of the Wild-Blood consider this the first spell taught to every acolyte.', NULL, ARRAY['druid', 'barbarian']::text[], ARRAY['solis-grave', 'srd-ref', 'shillelagh']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Storm-Wyrm''s Touch', 0, 'Evocation', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Lightning)', 'Instantaneous', 'Your hand crackles with the lightning of a Storm-Dragon''s breath as you trace a jagged sigil in the air and lunge. Make a melee spell attack. On a hit, the target takes 1d8 lightning damage and cannot take reactions until the start of its next turn. You have advantage on the attack roll if the target is wearing metal armor. The crackling discharge arcs across the target''s armor like tiny serpents — the Storm-Wyrm''s children, according to sailor folklore.', 'The spell''s damage increases by 1d8 at 5th, 11th, and 17th level.', ARRAY['sorcerer', 'wizard', 'artificer', 'fighter', 'rogue']::text[], ARRAY['solis-grave', 'srd-ref', 'shocking-grasp']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Timeless Breath', 0, 'Necromancy', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Radiant)', 'Instantaneous', 'You exhale a whisper of the Eternal Dragon''s breath — the one legend says sleeps at the center of all time — onto a living creature that has 0 hit points. The creature becomes stable. The spell has no effect on constructs or undead. Those revived by Timeless Breath often report a fleeting vision: a vast, coiled dragon of impossible size, one eye open and glowing with patient, infinite calm.', NULL, ARRAY['cleric', 'blood_hunter', 'monk']::text[], ARRAY['solis-grave', 'srd-ref', 'spare-the-dying']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon-Awe', 0, 'Transmutation', '1 action', '30 feet', 'V, S, M (Fractured Aether-Core — Radiant)', 'Up to 1 minute', 'Your voice resonates with the latent authority of your bloodline, carrying the weight of ancient wyrms. You create one of the following effects within range: your voice booms three times as loud for up to 1 minute; flames within the area flicker and change color to match your bloodline hue; the ground tremors faintly like the footfall of something vast; an unopened door or window flies open or slams shut; your eyes blaze with draconic iridescence for 1 minute; or you project a brief roar — the kind that, in the Old Tongue, precedes the word for ''kneel.''', NULL, ARRAY['cleric', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'thaumaturgy']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Predator''s Mark', 0, 'Divination', '1 action', '30 feet', 'V, S, M (Fractured Aether-Core — Wild)', 'Concentration, up to 1 round', 'You fix your draconic gaze on a creature within range and trace the sigil of the Hunt. Your bloodline — ancient predator instinct distilled — guides your next strike. On your next turn, you gain advantage on your first attack roll against the target, provided the spell hasn''t ended. The target feels a prickling at the back of its neck, as though a wyrm circles unseen overhead, choosing the moment to dive.', NULL, ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'fighter', 'rogue']::text[], ARRAY['solis-grave', 'srd-ref', 'true-strike']::text[], FALSE, TRUE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Blade Sigil', 0, 'Evocation', '1 action', 'Self (5-foot radius)', 'V, S, M (Fractured Aether-Core — Fire)', 'Instantaneous', 'You trace a blade-sigil along your weapon''s edge, and the weapon wreathes in aether-fire — the color of your bloodline''s flame. As part of casting, make a melee weapon attack against a creature within 5 feet. On a hit, the target suffers the attack''s normal effects, and draconic fire leaps from the target to a second creature you can see within 5 feet. The second creature takes fire damage equal to your spellcasting ability modifier. Martial Archons and Dragon-Heirs favor this spell — it was first taught to mortal warriors by a Crimson Dragon who admired their courage.', 'The second creature''s fire damage increases by 1d8 at 5th, 11th, and 17th level, plus your spellcasting ability modifier.', ARRAY['sorcerer', 'warlock', 'wizard', 'sovereign', 'fighter', 'rogue']::text[], ARRAY['solis-grave', 'homebrew', 'green-flame-blade']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Thunderclaw Strike', 0, 'Evocation', '1 action', 'Self (5-foot radius)', 'V, S, M (Fractured Aether-Core — Thunder)', '1 round', 'You trace a resonant sigil along your weapon, and it hums with contained thunder-aether — the roar of a Storm-Dragon trapped in steel. As part of casting, make a melee weapon attack against a creature within 5 feet. On a hit, the target suffers the attack''s normal effects and is sheathed in crackling thunder-aether. If the target willingly moves 5 feet or more before your next turn, the sigil detonates: the target takes 1d8 thunder damage. The sigil''s hum is audible to anyone within 10 feet — a warning the wise learn to recognize.', 'The detonation damage increases by 1d8 at 5th, 11th, and 17th level.', ARRAY['sorcerer', 'warlock', 'wizard', 'sovereign', 'fighter', 'rogue']::text[], ARRAY['solis-grave', 'homebrew', 'booming-blade']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Crimson Lash', 0, 'Necromancy', '1 action', 'Self (15-foot cone)', 'V, S, M (Fractured Aether-Core — Blood)', 'Instantaneous', 'You draw a line across your palm with a blade, flick the welling blood into the air, and trace a barb-sigil through it. The blood crystallizes into a barbed lash of crimson aether that whips through a 15-foot cone. Each creature in the cone must make a Dexterity saving throw or take 1d6 slashing damage. You take 1 necrotic damage when you cast this spell; this damage cannot be reduced and does not trigger concentration saves from the spell itself. Crimson Oath hunters call this their ''first lesson'' — the day they learn their own blood is the sharpest weapon.', 'The spell''s damage increases by 1d6 at 5th, 11th, and 17th level.', ARRAY['blood_hunter']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Tithe Dart', 0, 'Necromancy', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Blood)', 'Instantaneous', 'You prick your thumb on the edge of your Aether-Core, and a single droplet of blood crystallizes into a needle-sharp dart of seeking crimson aether. Make a ranged spell attack against a creature within range. On a hit, the target takes 1d4 piercing damage plus 1d4 necrotic damage. You take 1 necrotic damage when you cast this spell; this damage cannot be reduced. The dart veers slightly mid-flight — those with draconic blood instinctively flinch as it passes, recognizing the signature of a hunter.', 'The piercing and necrotic damage each increase by 1d4 at 5th, 11th, and 17th level.', ARRAY['blood_hunter']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Spark-Wire', 0, 'Evocation', '1 action', '30 feet', 'V, S, M (Fractured Aether-Core — Lightning)', 'Instantaneous', 'You flick a thin copper wire from a wrist-mounted gadget and the wire unspools through the air, guided by a lightning-sigil you trace with your other hand. The wire delivers a jolt of stored aether-electricity to a creature within range. Make a ranged spell attack. On a hit, the target takes 1d6 lightning damage and must succeed on a Constitution saving throw or its speed is halved until the start of your next turn. Aether-Smiths who favor this spell call it their ''handshake'' — the first prototype every apprentice builds.', 'The spell''s damage increases by 1d6 at 5th, 11th, and 17th level.', ARRAY['artificer']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Core Pulse', 0, 'Evocation', '1 action', 'Self (10-foot cube originating from you)', 'V, S, M (Fractured Aether-Core — Thunder or Wild)', 'Instantaneous', 'You overcharge your equipped Aether-Core by slamming your palm against it and shouting a resonant syllable of the Old Tongue. A pulse of concussive aether radiates from you in a 10-foot cube. Each creature in the area other than you must succeed on a Strength saving throw or be pushed 5 feet directly away from you and take 1d4 thunder damage. The core vents a brief plume of shimmering exhaust — the same color as the dragon whose essence it holds.', 'The spell''s damage increases by 1d4 at 5th, 11th, and 17th level, and the push distance increases by 5 feet at 11th level.', ARRAY['artificer']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Sense', 0, 'Divination', '1 action', 'Self (60-foot radius)', 'V, S, M (Fractured Aether-Core — Blood)', 'Concentration, up to 1 minute', 'You close your eyes and focus inward, listening to the rhythm of your own draconic blood. That rhythm extends outward, resonating with the aether in other living creatures. For the duration, you sense the presence and location of any creature with draconic blood (purity 1% or higher) within 60 feet. You also discern their purity bracket (Tainted, Lesser Blood, Half-Sovereign, etc.) but not their identity. Creatures with 0% purity are invisible to this sense. This spell was developed by the Dragon-Heirs of the Obsidian Court to sniff out hidden bloodlines — and hidden hunters.', NULL, ARRAY['sovereign', 'blood_hunter']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, TRUE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sovereign''s Hiss', 0, 'Enchantment', '1 action', '30 feet', 'V, S', 'Instantaneous', 'You speak a single, sharp syllable of the Old Tongue — the sound a dragon makes when its patience has run dry. A creature of your choice within range must succeed on a Wisdom saving throw or be wracked with instinctual dread: it has disadvantage on its next attack roll against you before the end of its next turn. The syllable lingers in the air like frost-breath on winter glass. Even those who understand no Old Tongue recognize the meaning: ''remember your place.''', NULL, ARRAY['sovereign']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, FALSE, 0, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Bloodline Benediction', 1, 'Enchantment', '1 action', '30 feet', 'V, S, M (Fractured Aether-Core — Radiant)', 'Concentration, up to 1 minute', 'You trace the sigil of the Celestial Dragon and utter a blessing in the Old Tongue, awakening the latent draconic essence in up to three creatures of your choice within range. Each target gains a +1d4 bonus to attack rolls and saving throws for the duration. This is not prayer — it is blood speaking to blood, older than any god. The sigil traced in the air leaves a faint golden afterimage visible only to those currently under its effect.', 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.', ARRAY['cleric', 'paladin', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'bless']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wyrm''s Exhalation', 1, 'Evocation', '1 action', 'Self (15-foot cone)', 'V, S, M (Fractured Aether-Core — Fire)', 'Instantaneous', 'You trace the fire-dragon''s breath-sigil across your throat and roar. A sheet of draconic flame erupts from your outstretched hands in a 15-foot cone. Each creature in the area must make a Dexterity saving throw; a creature takes 3d6 fire damage on a failed save, or half as much on a successful one. The flames are the exact hue of your bloodline — a knowledgeable observer can identify your lineage by the color alone. Flammable objects in the area ignite unless worn or carried.', 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.', ARRAY['sorcerer', 'wizard', 'sovereign', 'druid']::text[], ARRAY['solis-grave', 'srd-ref', 'burning-hands']::text[], FALSE, FALSE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sovereign''s Word', 1, 'Enchantment', '1 action', '30 feet', 'V, S, M (Fractured Aether-Core — Radiant)', '1 hour', 'You speak a humanoid''s name in the Old Tongue, lacing it with the subtle authority of your bloodline. The target must make a Wisdom saving throw; if it fails, it regards you as a friendly acquaintance for the duration. The effect ends if you or your companions do anything harmful to it. When the spell ends, the creature knows it was influenced by draconic compulsion — it felt the weight of a wyrm''s presence behind your words. Creatures with 50%+ purity have advantage on the save; they recognize the Old Tongue for what it is.', 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.', ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'charm-person']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Old-Tongue Edict', 1, 'Enchantment', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Radiant)', '1 round', 'You speak a single, irreducible word of command in the Old Tongue — the language dragons used to shape the first world. A creature of your choice within range must succeed on a Wisdom saving throw or follow the command on its next turn. Choose from: Approach, Drop, Flee, Grovel, Halt, or Kneel. The command is not heard as sound but as a pressure in the target''s blood — an ancestral instinct to obey that predates mammalian evolution.', 'When you cast this spell using a spell slot of 2nd level or higher, you can affect one additional creature for each slot level above 1st. The creatures must be within 30 feet of each other when targeted.', ARRAY['cleric', 'paladin', 'warlock', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'command']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Bloodline Lexicon', 1, 'Divination', '1 action', 'Self', 'V, S, M (Fractured Aether-Core — Wild)', '1 hour', 'You draw a circle-sigil on your forehead and whisper the Old Tongue word for ''understand.'' Your bloodline awakens its genetic memory of the first language — the tongue all mortal speech descended from. For the duration, you understand the literal meaning of any spoken language you hear and any written language you see, provided you are touching the text. You must be in physical contact with the surface of the writing or the speaker. This spell is a ritual of the Lore-Keepers, who use it to translate lost bloodline records.', NULL, ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'comprehend-languages']::text[], TRUE, FALSE, 10, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sanguine Mending', 1, 'Evocation', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Radiant or Wild)', 'Instantaneous', 'You place your palm on a creature and trace the sigil of the Life-Dragon — the legendary wyrm said to have shed blood to create the first mortal race. Warm aether flows through your veins into theirs. The target regains hit points equal to 1d8 + your spellcasting ability modifier. The touch leaves a faint, temporary scale-pattern glow on the skin where the wound was — a mark that fades within the hour. Undead and constructs are unaffected; the Life-Dragon''s gift is for the living.', 'When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d8 for each slot level above 1st.', ARRAY['bard', 'cleric', 'druid', 'paladin', 'ranger', 'artificer', 'blood_hunter']::text[], ARRAY['solis-grave', 'srd-ref', 'cure-wounds']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Sense', 1, 'Divination', '1 action', 'Self (30-foot radius)', 'V, S, M (Fractured Aether-Core — Wild)', 'Concentration, up to 10 minutes', 'You trace the sigil of the All-Seeing Dragon — an ancient wyrm of legend whose thousand eyes watched the forging of every plane — over your own eyes. For the duration, you sense the presence of magic within 30 feet. If you detect magic, you can use an action to see a faint aura around any visible creature or object that bears magic, and you identify which draconic element the magic is associated with (fire, lightning, void, radiant, etc.). Active Inquisitor wards appear as a sickly gray static in your aether-vision.', NULL, ARRAY['bard', 'cleric', 'druid', 'paladin', 'ranger', 'sorcerer', 'warlock', 'wizard', 'artificer', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'detect-magic']::text[], TRUE, TRUE, 10, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Glamour', 1, 'Illusion', '1 action', 'Self', 'V, S, M (Fractured Aether-Core — Wild)', '1 hour', 'You trace a shroud-sigil around your body, and a shimmer of aether wraps you in an illusory guise. You appear as any humanoid of your size, including clothing and equipment, up to 1 foot taller or shorter. The illusion doesn''t hold up to physical inspection — a creature touching you feels the real you beneath. To those with the Aether-Sense spell active, the glamour appears as a translucent second skin, like a dragonfly''s wing draped over you. Fugitive casters in Inquisitor-patrolled cities favor this spell above all others.', NULL, ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'disguise-self']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Primal-Scale Snare', 1, 'Conjuration', '1 action', '90 feet', 'V, S, M (Fractured Aether-Core — Earth or Wild)', 'Concentration, up to 1 minute', 'You trace the sigil of the Root-Dragon — one of the Primordials who became the first forests — upon the ground. Grasping vines and roots, their surfaces ridged with scale-like bark patterns, erupt from the earth in a 20-foot square centered on a point within range. Each creature in the area must succeed on a Strength saving throw or be restrained. A restrained creature can use its action to make a Strength check against your spell save DC, freeing itself on a success. The vines pulse slowly, as though breathing — a heartbeat left behind by the world''s oldest dragon.', NULL, ARRAY['druid', 'ranger']::text[], ARRAY['solis-grave', 'srd-ref', 'entangle']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon-Glow Brand', 1, 'Evocation', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Fire or Radiant)', 'Concentration, up to 1 minute', 'You trace a flare-sigil and hurl a sphere of iridescent draconic light to a point within range. Each creature in a 20-foot cube within that point must make a Dexterity saving throw or be outlined in shimmering light — the color of your bloodline''s flame — for the duration. Affected creatures shed dim light in a 10-foot radius and cannot benefit from invisibility. Attack rolls against them have advantage. The light outlines the creature''s skeleton in faintly glowing lines, as though their bones momentarily recall a draconic shape.', NULL, ARRAY['bard', 'druid', 'artificer', 'ranger']::text[], ARRAY['solis-grave', 'srd-ref', 'faerie-fire']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wyrm-Wing Cushion', 1, 'Transmutation', '1 reaction (taken when you or a creature within 60 feet of you falls)', '60 feet', 'V, S, M (Fractured Aether-Core — Air)', '1 minute', 'You trace the sigil of the Wind-Dragon in a swift, panicked arc. A cushion of shimmering aether — visible as a brief, translucent pair of spectral dragon wings — envelops up to five falling creatures within range. Their rate of descent slows to 60 feet per round for the duration. If they land before the spell ends, they take no falling damage and land on their feet. The wings dissipate on landing, leaving behind the faint scent of ozone and a lingering warmth.', NULL, ARRAY['bard', 'sorcerer', 'wizard', 'artificer']::text[], ARRAY['solis-grave', 'srd-ref', 'feather-fall']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Lesser Wyrm-Ling', 1, 'Conjuration', '1 hour', '10 feet', 'V, S, M (Fractured Aether-Core — Wild, plus herbs and incense worth 10 GC)', 'Instantaneous', 'You trace the sigil of a hatchling and speak the Old Tongue name of a tiny draconic spirit. The spirit assumes the form of a Tiny celestial, fey, or fiend — whatever shape your bloodline''s patron-dragon favors — and manifests within range. It acts independently but always obeys your commands. In combat, it shares your initiative and takes its own turn. The spirit is intelligent, speaks one language of your choice in the rasping tones of a baby dragon, and can deliver touch spells on your behalf. When reduced to 0 hit points, it disperses into a puff of iridescent aether smoke. You may resummon it by casting this spell again. Archon Casters record these spirits'' true names in their grimoires.', NULL, ARRAY['wizard', 'warlock']::text[], ARRAY['solis-grave', 'srd-ref', 'find-familiar']::text[], TRUE, FALSE, 10, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Breath-Shroud', 1, 'Conjuration', '1 action', '120 feet', 'V, S, M (Fractured Aether-Core — Water or Air)', 'Concentration, up to 1 hour', 'You trace the sigil of the Fog-Dragon and exhale slowly. A thick, obscuring mist — like the breath of a sleeping wyrm — billows from a point within range, forming a 20-foot-radius sphere. The sphere spreads around corners, and its area is heavily obscured. It lasts for the duration or until dispersed by a strong wind. The mist carries a faint, ancient scent: brine and thunder and something reptilian, as though the air remembers what it was before dragons breathed life into the world.', 'When you cast this spell using a spell slot of 2nd level or higher, the radius of the sphere increases by 20 feet for each slot level above 1st.', ARRAY['druid', 'ranger', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'fog-cloud']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sovereign''s Bolt', 1, 'Evocation', '1 action', '120 feet', 'V, S, M (Fractured Aether-Core — Radiant)', '1 round', 'You trace a lance-sigil and hurl a bolt of concentrated draconic radiance at a creature within range. Make a ranged spell attack. On a hit, the target takes 4d6 radiant damage and is wreathed in a corona of lingering aether-light until the end of your next turn. The next attack roll made against the target before the corona fades has advantage. The bolt travels in a straight line, burning a brief, eye-shaped afterimage into the air — the mark of the Dragon-Gods'' attention.', 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.', ARRAY['cleric', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'guiding-bolt']::text[], FALSE, FALSE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Life-Sigil Hymn', 1, 'Evocation', '1 bonus action', '60 feet', 'V, S, M (Fractured Aether-Core — Radiant or Wild)', 'Instantaneous', 'You trace a brief, three-note sigil in the air — each note a syllable of the Life-Dragon''s name — and a pulse of warm aether arcs to a creature within range. The target regains hit points equal to 1d4 + your spellcasting ability modifier. The spell can be cast as a bonus action, making it invaluable in the chaos of battle. The target hears a faint, harmonic chord when the aether strikes — the same chord that Lore-Keepers say echoed when the first dragon drew breath.', 'When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d4 for each slot level above 1st.', ARRAY['bard', 'cleric', 'druid']::text[], ARRAY['solis-grave', 'srd-ref', 'healing-word']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wyrm-Fire Heart', 1, 'Enchantment', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Fire)', 'Concentration, up to 1 minute', 'You trace the heart-sigil — an ancient symbol shaped like a dragon''s cardiac chamber — on a willing creature''s chest. Their heart burns with borrowed draconic courage. The target gains temporary hit points equal to your spellcasting ability modifier at the start of each of its turns for the duration, and it is immune to the frightened condition. When the spell ends, the target loses any remaining temporary hit points. The target''s heartbeat is audible to anyone within 5 feet — a deep, rhythmic drum like the pacing of a caged wyrm.', NULL, ARRAY['bard', 'paladin']::text[], ARRAY['solis-grave', 'srd-ref', 'heroism']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Reading', 1, 'Divination', '1 minute', 'Touch', 'V, S, M (Fractured Aether-Core — Wild, plus a pearl worth 100 GC that the spell consumes)', 'Instantaneous', 'You touch an object and trace the sigil of Knowing over it. The pearl — crushed to powder and sprinkled on the object — dissolves into aether-threads that weave through its history. You learn the object''s magical properties, how to use them, whether it requires attunement, how many charges it has (if any), and whether any spells are affecting it. You also learn which draconic element the item''s creator''s bloodline was attuned to. This is not divination in the conventional sense — the object''s own aether-memory speaks to you.', NULL, ARRAY['bard', 'wizard', 'artificer', 'cleric']::text[], ARRAY['solis-grave', 'srd-ref', 'identify']::text[], TRUE, FALSE, 10, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Rend', 1, 'Necromancy', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Void)', 'Instantaneous', 'You trace the rend-sigil — a jagged claw-mark that smolders black — and rake your hand through the target''s life-force. Make a melee spell attack. On a hit, the target takes 3d10 necrotic damage, and you feel a brief, intoxicating surge of stolen vitality through your veins. The wound left behind is bloodless but black-veined, as though the target''s own draconic blood (however thin) recoils from the violation. This spell is forbidden by the Citadel and taught only in the hidden Orders of the Crimson Oath.', 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d10 for each slot level above 1st.', ARRAY['cleric', 'warlock', 'blood_hunter']::text[], ARRAY['solis-grave', 'srd-ref', 'inflict-wounds']::text[], FALSE, FALSE, 10, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon-Leg Surge', 1, 'Transmutation', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Earth)', '1 minute', 'You trace the leaping-sigil — two crescents like a dragon''s hind-legs coiled to spring — on a willing creature''s calves. The target''s muscles surge with aether-imbued power. For the duration, the target''s jump distance is tripled. The target''s legs momentarily shimmer with a faint scale pattern when they jump, and their landing produces a sound deeper than their weight should allow — a muffled thud that echoes the landings of things much larger.', NULL, ARRAY['druid', 'ranger', 'sorcerer', 'wizard', 'artificer']::text[], ARRAY['solis-grave', 'srd-ref', 'jump']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Scale-Stride', 1, 'Transmutation', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Air)', '1 hour', 'You trace the stride-sigil — a flowing, elongated mark like a dragon''s gait stretched across a landscape — on a willing creature. The target''s speed increases by 10 feet for the duration. The aether that suffuses their legs leaves faintly luminous footprints for moments after each step, visible only in darkness. Striders of the wild orders use this spell to cover vast distances, leaving behind trails that rival the patrol routes of young dragons.', NULL, ARRAY['bard', 'druid', 'ranger', 'wizard', 'artificer']::text[], ARRAY['solis-grave', 'srd-ref', 'longstrider']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Scale Shroud', 1, 'Abjuration', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Earth)', '8 hours', 'You trace the armor-sigil across your body, and a translucent layer of shimmering draconic scales — invisible to the naked eye but solid to weapons — wraps around you. Until the spell ends, the target''s base AC becomes 13 + its Dexterity modifier if not wearing armor. The spell ends if the target dons armor or is dismissed as an action. When struck, faint scale-pattern ripples flash across the target''s skin, visible in that split second as the color of the caster''s bloodline.', NULL, ARRAY['sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'mage-armor']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sigil Dart', 1, 'Evocation', '1 action', '120 feet', 'V, S, M (Fractured Aether-Core — Force or Wild)', 'Instantaneous', 'You trace three small dart-sigils in rapid succession, and three crystalline darts of pure aether-force shoot from your fingertip. Each dart unerringly strikes a creature of your choice within range, dealing 1d4 + 1 force damage. The darts can be directed at one target or spread among several. They leave faint, smoking trails in the air that smell of ozone and rust, and their impacts sound like ice cracking — the sound, according to legend, of the Void-Dragon hatching from the shell of the old universe.', 'When you cast this spell using a spell slot of 2nd level or higher, you create one additional dart for each slot level above 1st.', ARRAY['sorcerer', 'wizard', 'fighter', 'rogue']::text[], ARRAY['solis-grave', 'srd-ref', 'magic-missile']::text[], FALSE, FALSE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sanctified Blood-Ward', 1, 'Abjuration', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Radiant, plus a pinch of iron filings consumed by the spell)', 'Concentration, up to 10 minutes', 'You trace a warding circle-sigil on a willing creature and scatter iron filings that hang suspended in the air, forming a protective ring. Until the spell ends, aberrations, celestials, elementals, fey, fiends, and undead have disadvantage on attack rolls against the target. The target also cannot be charmed, frightened, or possessed by them. The warding circle glows with the steady, patient light of a dragon guarding its hoard. The iron filings were chosen for their symbolic resonance — dragons loathe the taste of cold iron, and so do the things that hunt in the spaces between planes.', NULL, ARRAY['cleric', 'paladin', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'protection-from-evil-and-good']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Cleansing Flame Sigil', 1, 'Transmutation', '1 action', '10 feet', 'V, S, M (Fractured Aether-Core — Fire)', 'Instantaneous', 'You trace the flame of purification — a dragon''s tongue-sigil — over food and drink within a 5-foot-radius sphere. All nonmagical food and drink within the area is purified and rendered free of poison and disease. A faint wisp of chromatic smoke rises from the purified items, and for a moment, the food tastes as though it has been warmed by a dragon''s breath — rich, savory, faintly spiced. Ordained of the Citadel perform this rite before every communal meal.', NULL, ARRAY['cleric', 'druid', 'paladin']::text[], ARRAY['solis-grave', 'srd-ref', 'purify-food-and-drink']::text[], TRUE, FALSE, 10, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wyrm-Rest', 1, 'Abjuration', '1 bonus action', '30 feet', 'V, S, M (Fractured Aether-Core — Radiant)', '1 minute', 'You trace a stillness-sigil over a creature within range. The aether around them thickens into a protective shimmer. Until the spell ends, any creature who targets the warded creature with an attack or harmful spell must first make a Wisdom saving throw. On a failure, the attacker must choose a new target or lose the attack or spell. The spell ends if the warded creature makes an attack, casts a spell that affects an enemy, or deals damage to another creature. The shimmer takes the form of a coiled dragon, tail-to-snout, encircling the warded creature protectively.', NULL, ARRAY['cleric', 'paladin']::text[], ARRAY['solis-grave', 'srd-ref', 'sanctuary']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Scale-Reflex', 1, 'Abjuration', '1 reaction (taken when you are hit by an attack or targeted by the magic missile spell)', 'Self', 'V, S, M (Fractured Aether-Core — Earth)', '1 round', 'You trace a defensive sigil in a blur of instinct. An invisible barrier of hardened aether — like a patch of dragon-scale made manifest — flashes into existence and intercepts the incoming attack. Until the start of your next turn, you gain a +5 bonus to AC, including against the triggering attack, and you take no damage from the Sigil Dart spell. The barrier appears as a brief, translucent scale-shield of your bloodline''s color, visible only in the instant of impact.', NULL, ARRAY['sorcerer', 'wizard', 'fighter', 'rogue']::text[], ARRAY['solis-grave', 'srd-ref', 'shield']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aegis of the Bloodline', 1, 'Abjuration', '1 bonus action', '60 feet', 'V, S, M (Fractured Aether-Core — Earth or Radiant)', 'Concentration, up to 10 minutes', 'You trace the aegis-sigil — a dragon''s profile in silhouette, facing outward — and hurl it at a creature within range. A shimmering draconic field encases the target. The target gains a +2 bonus to AC for the duration. When the aegis absorbs a blow, a brief, musical tone rings out — the note varies by bloodline, and some Ordained claim to identify a stranger''s lineage by the pitch of their aegis.', NULL, ARRAY['cleric', 'paladin']::text[], ARRAY['solis-grave', 'srd-ref', 'shield-of-faith']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Phantom-Wyrm', 1, 'Illusion', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Wild)', 'Concentration, up to 10 minutes', 'You trace an image-sigil and a phantom wyrm — no larger than a horse, no smaller than a cat — materializes in a 15-foot cube within range. It is purely visual, has no substance, and makes no sound. The image looks and moves convincingly: a draconic form of your design, scaled and winged, breathing silent, illusory flame. Physical interaction reveals it as illusion. You can move the image up to 30 feet as an action. Inquisitors train to spot Phantom-Wyrms; they know real dragons do not blink at the same rhythm as illusions.', NULL, ARRAY['bard', 'sorcerer', 'wizard', 'warlock']::text[], ARRAY['solis-grave', 'srd-ref', 'silent-image']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wyrm-Lull', 1, 'Enchantment', '1 action', '90 feet', 'V, S, M (Fractured Aether-Core — Air)', '1 minute', 'You trace a gentle, looping sigil — the same one dragon-mothers use to calm their hatchlings — and hum a low, resonant chord in the Old Tongue. Creatures within a 20-foot-radius sphere centered on a point within range fall into a magical slumber, provided they have 5d8 hit points or fewer (rolled when the spell is cast). Creatures are affected in ascending order of current hit points, and the spell ends for a creature if it takes damage or someone uses an action to shake it awake. Creatures with 25%+ purity have advantage on the saving throw; their blood recognizes the lullaby and fights it. Undead and creatures immune to charm are unaffected.', 'When you cast this spell using a spell slot of 2nd level or higher, the hit point pool increases by 2d8 for each slot level above 1st.', ARRAY['bard', 'sorcerer', 'wizard']::text[], ARRAY['solis-grave', 'srd-ref', 'sleep']::text[], FALSE, FALSE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Feral-Kin Tongue', 1, 'Divination', '1 action', 'Self', 'V, S, M (Fractured Aether-Core — Wild)', '10 minutes', 'You trace the beast-sigil — a stylized dragon''s claw print — on your throat. For the duration, you can comprehend and verbally communicate with beasts. The knowledge and awareness of beasts is limited by their intelligence, but they will speak to you willingly, recognizing in your voice the echo of the Primordial Dragons who created all living things. Most beasts speak in simple images and emotions; a wolf might show you ''fur-that-walks-upright-with-metal-stick'' rather than ''a guard with a spear.''', NULL, ARRAY['bard', 'druid', 'ranger', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'speak-with-animals']::text[], TRUE, FALSE, 10, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Drake''s Mockery', 1, 'Enchantment', '1 action', '30 feet', 'V, S, M (Fractured Aether-Core — Wild)', 'Concentration, up to 1 minute', 'You trace a mock-sigil — a crude caricature of a dragon''s face with its tongue out — and speak a string of absurdities in the Old Tongue that somehow translate into the target''s deepest insecurities. A creature you can see within range must succeed on a Wisdom saving throw or fall into a fit of uncontrollable, incapacitating laughter and fall prone. At the end of each of its turns and each time it takes damage, the target can make another Wisdom saving throw. The spell ends on a success. Creatures with Intelligence 4 or less are immune. Dragons consider this spell profoundly offensive — it was first created by a Lore-Keeper who survived a red wyrm''s monologue.', NULL, ARRAY['bard', 'warlock', 'wizard']::text[], ARRAY['solis-grave', 'srd-ref', 'tashas-hideous-laughter']::text[], FALSE, TRUE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Thunder-Wyrm''s Roar', 1, 'Evocation', '1 action', 'Self (15-foot cube originating from you)', 'V, S, M (Fractured Aether-Core — Thunder)', 'Instantaneous', 'You trace the roar-sigil — a jagged, expanding spiral — and roar with the voice of the Thunder-Wyrm. A wave of thunderous aether erupts from you in a 15-foot cube. Each creature other than you in the area must make a Constitution saving throw. On a failure, a creature takes 2d8 thunder damage and is pushed 10 feet directly away from you. On a success, it takes half damage and isn''t pushed. Unsecured objects in the area are automatically pushed 10 feet. The roar echoes through the aether for miles; any dragon within 50 miles hears it — and may answer.', 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d8 for each slot level above 1st.', ARRAY['bard', 'druid', 'sorcerer', 'wizard']::text[], ARRAY['solis-grave', 'srd-ref', 'thunderwave']::text[], FALSE, FALSE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Phantom Attendant', 1, 'Conjuration', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Wild)', '1 hour', 'You trace the servant-sigil — a stylized talon holding a cup — and a shimmering, invisible draconic spirit manifests at a point within range. The attendant is shapeless, invisible, and mindless; it performs simple tasks at your command: fetching objects, opening doors, cleaning, folding, mending, pouring, stoking fires. It cannot attack, and it dissipates if it takes any damage or moves more than 60 feet from you. Lore-Keepers use Phantom Attendants to organize vast archives of bloodline records; the spirits never complain about the dust.', NULL, ARRAY['bard', 'warlock', 'wizard']::text[], ARRAY['solis-grave', 'srd-ref', 'unseen-servant']::text[], TRUE, FALSE, 10, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sanguine Geas', 1, 'Necromancy', '1 action', '30 feet', 'V, S, M (Fractured Aether-Core — Blood)', 'Concentration, up to 1 minute', 'You slice your palm open with a ritual blade (taking 1d6 slashing damage that cannot be reduced) and trace a binding-sigil in your own blood. A creature you can see within range must make a Wisdom saving throw. On a failure, the creature is under a lesser blood-geas for the duration: you may speak a single command as a bonus action on each of your turns, which the target must follow to the best of its ability unless the command is directly self-destructive. Each time the target takes damage, it may repeat the saving throw. The geas appears as faint crimson strands connecting your bleeding palm to the target''s temples — visible only to those with active Blood-Sense or Aether-Sense.', 'When you cast this spell using a spell slot of 2nd level or higher, the duration increases by 1 minute for each slot level above 1st.', ARRAY['blood_hunter']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, TRUE, 10, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Core Overload', 1, 'Evocation', '1 reaction (taken when a creature within 5 feet of you hits you with a melee attack)', 'Self (5-foot radius)', 'V, S, M (Fractured Aether-Core — Lightning)', 'Instantaneous', 'You slam your palm against your Aether-Core, overloading its safety governor. The core vents violently, discharging a crackling burst of aether-lightning. The attacking creature must make a Dexterity saving throw. On a failure, it takes 2d8 lightning damage and is dazed — its next attack roll before the end of its next turn has disadvantage. On a success, it takes half damage and is not dazed. The core''s venting produces a sharp crack and a puff of acrid smoke that smells of copper and burnt scale. Aether-Smiths who overuse this spell find their cores degrade faster than expected.', 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d8 for each slot level above 1st.', ARRAY['artificer']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, FALSE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Bloodline Surge', 1, 'Transmutation', '1 bonus action', 'Self', 'V, S, M (Fractured Aether-Core — Blood)', 'Concentration, up to 1 minute', 'You slam your fist against your chest and roar a single syllable of the Old Tongue — the word dragons use to demand their blood obey. Your purity surges. For the duration, your effective purity increases by 10%, reducing your Spell Safety DC accordingly, and you gain a +1d4 bonus to spell attack rolls. However, your veins burn with unstable power: when the spell ends, you suffer 2d6 psychic damage as Aether Burn from the backlash. This damage cannot be reduced. This spell cannot raise your purity above 100%. Dragon-Heirs consider Bloodline Surge the mark of a true Sovereign — the willingness to burn for power.', 'When you cast this spell using a spell slot of 2nd level or higher, the purity bonus increases by +5% and the spell attack bonus increases by +1 for each slot level above 1st, but the backlash damage increases by 1d6 for each additional slot level.', ARRAY['sovereign']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, TRUE, 10, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sworn Retribution', 1, 'Evocation', '1 reaction (taken when a creature within 30 feet of you that you can see damages an ally of yours)', '30 feet', 'V, S, M (Fractured Aether-Core — Radiant)', 'Instantaneous', 'You speak the Oath-Word — a single syllable in the Old Tongue that binds all Oath-Sworn to their vows — and your bloodline answers with righteous fury. The triggering creature is marked by a burning sigil that hovers above its head, visible to all. Until the end of your next turn, your weapon attacks against the marked creature deal an additional 1d8 radiant damage. The mark''s shape reflects your Oath: a scale for Devotion, a fang for Vengeance, a claw for Conquest. The creature feels the weight of the Oath pressing on its soul — a suffocating heat that intensifies the closer you get.', NULL, ARRAY['paladin']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, FALSE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Hunter''s Aether-Mark', 1, 'Divination', '1 bonus action', '90 feet', 'V, S, M (Fractured Aether-Core — Wild)', '8 hours', 'You trace the tracking-sigil — a spiraling claw-mark that narrows to a point — and hurl it at a creature you can see. The sigil sinks into the target''s aether-signature like a thorn. For the duration, you always know the direction and approximate distance to the marked creature, provided it is on the same plane of existence. The mark cannot be removed except by a Remove Curse spell or similar magic, but it fades naturally when the duration expires. A marked creature with 25%+ purity may feel a faint itch between the shoulder blades — the ancestral memory of being hunted by dragons.', 'When you cast this spell using a spell slot of 3rd level or higher, the duration extends to 24 hours (3rd-4th), 7 days (5th-6th), or until dispelled (7th+).', ARRAY['ranger', 'blood_hunter']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Draconic Vigor', 2, 'Abjuration', '1 action', '30 feet', 'V, S, M (Fractured Aether-Core — Law)', '8 hours', 'You trace the sigil of endurance — a coiled dragon — in the air before three creatures, breathing the Old Tongue word vorthûn (“unbroken”). Their blood quickens with ancestral resilience, their veins briefly shimmering with faint draconic light. Each target‘s maximum hit points increase by 5 for the duration, and their current hit points rise to match. This is not healing but bloodline fortification — the dragon within refusing to yield.', 'At 3rd level or higher, each target’s hit point maximum increases by an additional 5 per spell level above 2nd.', ARRAY['cleric', 'paladin', 'artificer', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'aid']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Mask', 2, 'Transmutation', '1 action', 'Self', 'V, S, M (Fractured Aether-Core — Flesh)', 'Concentration, up to 1 hour', 'You press a Fractured Flesh-Core to your sternum and whisper the Old Tongue phrase sheth-kar vey’n (“I am another”). Your bloodline sigil warps, rewriting your physical form. You may adopt draconic features — slit pupils, scaled forearms, taloned fingers — or reshape your entire appearance including height, build, and voice. You cannot change creature type, but you can mimic the appearance of any humanoid. Those who examine you closely may notice a faint shimmer where the Old Tongue words still crawl beneath your skin. Inquisitors call this spell Wyrm-Deceit, and those caught using it face the pyre.', NULL, ARRAY['sorcerer', 'wizard', 'warlock', 'artificer', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'alter-self']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Scale-Courier', 2, 'Conjuration', '1 action', '30 feet', 'V, S, M (Fractured Aether-Core — Wild)', '24 hours', 'You place a message against the Fractured Wild-Core and trace the sigil of the Winged Herald — a tiny dragon in flight. An aetherial construct takes form: a fist-sized draconic wisp with parchment wings and ember eyes. You whisper your destination and message; the Scale-Courier flits away at impossible speed, finding its target by blood-scent across any distance on the same plane. Upon arrival it speaks your words in your voice, then dissolves into harmless sparks. If the target’s bloodline is suppressed, dormant, or severed, the courier circles confusedly and returns.', 'At 3rd level or higher, the courier’s flight speed increases, allowing it to reach targets on adjacent planes by 5th level.', ARRAY['bard', 'druid', 'ranger']::text[], ARRAY['solis-grave', 'srd-ref', 'animal-messenger']::text[], TRUE, FALSE, 10, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Seal', 2, 'Abjuration', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Law)', 'Until dispelled', 'You press a Fractured Law-Core against a door, chest, or portal and speak the Old Tongue command keth-varôs (“none shall pass”). The core embeds itself into the surface, crackling with a lattice of draconic sigils. The object becomes magically locked; the DC to pick or break it increases by 10. Only those whose blood resonates with the sigil pattern you designate — or those whose purity exceeds yours — may open it without shattering the seal. A shattered seal screams, audible to any dragon-blood within 300 feet.', 'At 3rd level or higher, the DC to bypass the seal increases by 2 per spell level above 2nd.', ARRAY['wizard', 'artificer', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'arcane-lock']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon-Eye Reading', 2, 'Divination', '1 minute', 'Self', 'V, S, M (Fractured Aether-Core — Wild)', 'Instantaneous', 'You scatter the dust of a Fractured Wild-Core over a polished surface — still water, obsidian, or blood — and intone the Old Tongue query-phrase veyr’an sheth’kar? (“what comes?”). The dust writhes, forming the eye of a distant dragon ancestor that peers through time’s veil. You receive an omen about a specific course of action planned within 30 minutes: Weal (fortune), Woe (danger), Weal and Woe (mixed), or Nothing (fate is silent). Each casting after the first before a long rest beckons the Eye deeper; the Spell Safety DC increases by +3 per repeated casting. The dragon ancestors do not appreciate being pestered.', NULL, ARRAY['cleric', 'druid', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'augury']::text[], TRUE, FALSE, 10, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Drake-Hide', 2, 'Transmutation', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Flesh)', 'Concentration, up to 1 hour', 'You trace the sigil of the Iron-Scaled Drake across a willing creature’s skin and speak the Old Tongue word vrak’sul (“armored flesh”). The target’s skin hardens into a lattice of semi-translucent scales, shimmering faintly with their bloodline’s color — crimson for fire lines, silver for storm lines, black for void lines. Their AC cannot drop below 16 for the duration. The transformation is visible to others; Inquisitors recognize it as a bloodline manifestation and will demand the caster’s certification papers.', NULL, ARRAY['druid', 'ranger', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'barkskin']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sense-Theft', 2, 'Necromancy', '1 action', '30 feet', 'V, S, M (Fractured Aether-Core — Void)', '1 minute', 'You crush a Fractured Void-Core between thumb and forefinger while hissing the Old Tongue curse vel’shath mir (“see nothing”). Black mist coils from your hand and streaks toward a creature’s face. The target must succeed on a Constitution saving throw or be blinded or deafened (your choice) for the duration. The effect manifests as a writhing film of void-stuff over their eyes or ears — visible to all. A creature afflicted by this spell sees not darkness but the yawning emptiness between stars, which many describe as infinitely worse.', 'At 3rd level or higher, you can target one additional creature per spell level above 2nd.', ARRAY['bard', 'cleric', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'blindness-deafness']::text[], FALSE, FALSE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Shimmer', 2, 'Illusion', '1 action', 'Self', 'V, S, M (Fractured Aether-Core — Shadow)', 'Concentration, up to 1 minute', 'You draw the Fractured Shadow-Core across your chest in a zigzag pattern and exhale the Old Tongue word vish’tal (“between”). Your bloodline sigil stutters, projecting you fractionally out of phase with the material world. Your image becomes blurred, shifting and wavering as though seen through heat haze. Attack rolls against you have disadvantage unless the attacker can see through illusions. The effect is anchored to your bloodline — suppressing your purity suppresses the shimmer. Sovereigns use this to walk through crowds unnoticed; Inquisitors have learned to watch for the telltale afterimage.', NULL, ARRAY['sorcerer', 'wizard', 'artificer', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'blur']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sovereign’s Brand', 2, 'Evocation', '1 bonus action', 'Self', 'V, M (Fractured Aether-Core — Law)', 'Concentration, up to 1 minute', 'You slam a Fractured Law-Core against the grip of your weapon and roar the Old Tongue oath keth-ragnar vorn! (“by the First Flame, be marked!”). Draconic fire wreathes your weapon, inscribing your bloodline sigil along the blade in searing light. The next time you strike a creature, the sigil transfers to their flesh, burning bright as a brand. For the duration, the target sheds dim light in a 5-foot radius, cannot become invisible, and any attack you make against them deals an additional 2d6 radiant damage. If the target dies while branded, the sigil detonates in a harmless flash visible to dragon-blood within 500 feet — a declaration of kill-right.', 'At 3rd level or higher, the initial and ongoing radiant damage increases by 1d6 per spell level above 2nd.', ARRAY['paladin']::text[], ARRAY['solis-grave', 'srd-ref', 'branding-smite']::text[], FALSE, TRUE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Still the Blood', 2, 'Enchantment', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Law)', 'Concentration, up to 1 minute', 'You speak the Old Tongue lullaby sul-nir vorthûn (“calm, unbroken”) while weaving your bloodline sigil in slow, soothing arcs. Each creature of your choice within a 20-foot-radius sphere must make a Charisma saving throw. On failure, their draconic blood — whether dormant or active — is temporarily placated, suppressing extreme emotions. A creature so affected becomes indifferent toward creatures it was hostile toward, and cannot take violent actions. The effect ends if the target is attacked or harmed. This spell is banned by the Inquisition in most Citadel precincts; it is considered bloodline coercion.', 'At 3rd level or higher, the radius increases by 10 feet per spell level above 2nd.', ARRAY['bard', 'cleric', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'calm-emotions']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Eternal Ember', 2, 'Evocation', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Fire)', 'Until dispelled', 'You press a Fractured Fire-Core to an object — a torch, a lantern, a brazier — and speak the Old Tongue phrase ignar’sheth vor (“fire that never dies”). The core fuses into the object, which ignites with a warm, steady flame that produces no heat unless you will it, consumes no fuel, and cannot be extinguished by wind, water, or smothering. The light is the exact color of your bloodline’s draconic fire — gold for Law, crimson for Cinder, silver for Storm. The flame can be covered to hide the light, but it never truly dies. Many Sump-dwellers trade dearly for an Eternal Ember; it is the only light that asks nothing in return.', NULL, ARRAY['cleric', 'wizard', 'artificer', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'continual-flame']::text[], FALSE, FALSE, 10, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Void-Wing Shroud', 2, 'Evocation', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Void)', 'Concentration, up to 10 minutes', 'You shatter a Fractured Void-Core above your head and spread your arms wide, invoking the Old Tongue phrase vel’sul karôs (“the deep claims this place”). The shards expand into a 15-foot-radius sphere of absolute, magical darkness. No light — mundane or magical — can illuminate the area, and creatures within are effectively blinded. The darkness does not simply obscure light; it eats it, swallowing torchlight and spells alike. Those inside report hearing distant wingbeats. This is the inherited magic of Void-blooded dragons, and it terrifies even the Inquisition.', 'At 3rd level or higher, the radius increases by 5 feet per spell level above 2nd.', ARRAY['sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'darkness']::text[], FALSE, TRUE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Hunt-Sight', 2, 'Transmutation', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Shadow)', '8 hours', 'You press a Fractured Shadow-Core to a willing creature’s closed eyes and whisper the Old Tongue word veyr’kar (“true sight”). The core dissolves, its essence seeping into the target’s irises, which flicker with a faint amber glow for the duration. The target gains darkvision out to 60 feet — but unlike mundane night-sight, this is draconic perception, allowing them to see heat signatures in monochrome red. To those without the spell active, the target’s eyes appear to have vertical slit pupils for the duration. Inquisitors trained to spot this call it “wyrm-eye” and consider it probable cause.', 'At 3rd level or higher, the range increases by 30 feet per spell level above 2nd.', ARRAY['druid', 'ranger', 'sorcerer', 'wizard', 'artificer', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'darkvision']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Mind-Peel', 2, 'Divination', '1 action', 'Self', 'V, S, M (Fractured Aether-Core — Mind)', 'Concentration, up to 1 minute', 'You touch the Fractured Mind-Core to your temple and speak the Old Tongue phrase sheth’mir vorn (“I read the unwritten”). A cold pulse spreads through your skull as your bloodline attunes to the surface thoughts of those around you. For the duration, you can perceive the shallow mental impressions of any creature within 30 feet, even if you cannot see them. You may also focus on one creature to probe deeper, forcing a Wisdom saving throw; on failure, you pluck a desire, fear, or secret from their mind. The target feels a distinct warmth behind their eyes — the dragon, looking. Those with higher purity resist more easily, their bloodline instinctively guarding their mind.', NULL, ARRAY['bard', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'detect-thoughts']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Surge', 2, 'Transmutation', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Flesh)', 'Concentration, up to 1 hour', 'You clutch a Fractured Flesh-Core and draw your bloodline sigil directly onto the target’s skin with its edge, chanting the Old Tongue litany of the six aspects: vrak’sul, mir’thal, vor’nir, sheth’kar, sul’dan, keth’ragnar. The target’s blood surges with ancestral power, magnifying one of six aspects — draconic might, feline grace, ursine constitution, serpentine cunning, owlish wisdom, or regal presence. They gain advantage on ability checks using the chosen attribute. The sigil glows visibly through clothing for the duration, a pulsing tattoo of power and danger.', 'At 3rd level or higher, you can target one additional creature per spell level above 2nd.', ARRAY['artificer', 'bard', 'cleric', 'druid', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'enhance-ability']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Titan-Blood', 2, 'Transmutation', '1 action', '30 feet', 'V, S, M (Fractured Aether-Core — Flesh)', 'Concentration, up to 1 minute', 'You speak the Old Tongue words of scale — gran’sul (“grow”) or mir’sul (“shrink”) — while tracing a spiraling sigil toward your target with a Fractured Flesh-Core. The target’s body responds to the blood-command, their skeleton groaning or compressing as the ancient proportions of the Great Dragons — who were as large as mountains and as small as embers — temporarily overwrite their form. A creature or object you enlarge doubles in all dimensions and multiplies its weight by eight; one you reduce halves in dimensions and divides weight by eight. Those who survive this spell often speak of phantom limb pains for weeks.', 'At 3rd level or higher, the size multiplier increases — at 4th level a creature can grow to Gargantuan or shrink to Fine.', ARRAY['sorcerer', 'wizard', 'artificer', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'enlarge-reduce']::text[], FALSE, TRUE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Summon Blood-Mount', 2, 'Conjuration', '10 minutes', '30 feet', 'V, S, M (Fractured Aether-Core — Flesh)', 'Instantaneous', 'You draw a wide circle in the ground with a Fractured Flesh-Core, tracing the sigil of the Loyal Drake, and cut your palm — letting a drop of blood fall into the circle’s center. The blood steams and expands, forming a loyal steed woven from Aether and your own bloodline memory: a horse-sized drake with leathery wings (flightless unless you have 50%+ purity), obsidian scales, and eyes that match your own. The Blood-Mount serves you absolutely, understands Old Tongue commands, and fights alongside you if needed. It is not a true creature but a blood-manifestation; when it dies, it dissolves into a pool of warm blood that smells faintly of your ancestry.', 'At 3rd level or higher, the Blood-Mount gains +1 AC and +10 hit points per spell level above 2nd.', ARRAY['paladin', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'find-steed']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Sight', 2, 'Divination', '1 action', '120 feet', 'V, S, M (Fractured Aether-Core — Wild)', 'Instantaneous', 'You hold a Fractured Wild-Core before one eye like a lens and speak the Old Tongue word veyr’snâr (“see the hidden”). The core pulses once, discharging a wave of perception that ripples through the area. For an instant, any mechanical trap, alchemical snare, or magical ward within range glimmers with an aether-blue outline visible only to you — the core revealing where the weave has been disturbed. This spell does not detect natural hazards, but it reveals sigil-locked doors, Inquisitor alarm wards, and buried Aether-Core mines. The flash is brief; you must commit what you see to memory or lose it.', NULL, ARRAY['cleric', 'druid', 'ranger', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'find-traps']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Cinder-Blade', 2, 'Evocation', '1 bonus action', 'Self', 'V, S, M (Fractured Aether-Core — Fire)', 'Concentration, up to 10 minutes', 'You break a Fractured Fire-Core in your grip and roar the Old Tongue blade-name ignar’shek vor (“flame fang, come”). The core’s shards ignite and elongate into a scimitar-shaped blade of roaring draconic fire in your hand. The Cinder-Blade sheds bright light in a 10-foot radius, dim light for 20 feet, and deals 3d6 fire damage on a hit. It leaves no wound — only ash and cauterized flesh. You can use your spellcasting ability instead of Strength for attack and damage rolls. The blade answers to your bloodline alone; if another attempts to wield it, the fire turns on them.', 'At 3rd level or higher, the damage increases by 1d6 per two spell levels above 2nd.', ARRAY['druid', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'flame-blade']::text[], FALSE, TRUE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Rolling Cinder', 2, 'Conjuration', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Fire)', 'Concentration, up to 1 minute', 'You hurl a Fractured Fire-Core to an unoccupied space on the ground and call the Old Tongue phrase ignar’dan vor (“dragon’s eye, wake”). The core erupts into a 5-foot-diameter sphere of churning draconic fire — a miniature sun with a vertical slit-pupil at its center. The Rolling Cinder sheds bright light for 20 feet and dim light for 40. As a bonus action, you can command it to roll up to 30 feet; it ignites flammable objects and ramming into a creature deals 2d6 fire damage (Dexterity save for half). Those who stare into its pupil swear they see something staring back.', 'At 3rd level or higher, the damage increases by 1d6 per spell level above 2nd.', ARRAY['druid', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'flaming-sphere']::text[], FALSE, TRUE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Death-Stilling', 2, 'Necromancy', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Death)', '10 days', 'You rest a Fractured Death-Core on a corpse’s forehead and hum the Old Tongue dirge sul’nir mir’sheth (“rest, unborn”). The core’s cold seeps into the body, halting decay, preventing reanimation, and extending the window for spells like Death-Defy (Revivify) by the full 10 days. The corpse’s blood — regardless of purity — congeals into a thin crystalline layer just beneath the skin, visible as a faint shimmer. In Solis-Grave culture, this is a final dignity: to be preserved not by prayer but by blood-right. The Inquisition considers it unsanctioned if performed by anyone but an Ordained.', NULL, ARRAY['cleric', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'gentle-repose']::text[], TRUE, FALSE, 10, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wing-Gust', 2, 'Evocation', '1 action', 'Self (60-foot line)', 'V, S, M (Fractured Aether-Core — Storm)', 'Concentration, up to 1 minute', 'You sweep your arms forward as if beating wings and exhale the Old Tongue word vayr’shul (“blow”) through a Fractured Storm-Core held to your lips. A line of howling draconic wind 60 feet long and 10 feet wide blasts from you for the duration. Creatures in the line must make a Strength saving throw or be pushed 15 feet. The wind disperses gas, vapor, and fog, and extinguishes unprotected flames. For the duration, you can change the direction of the line as a bonus action. Archons describe this spell as “borrowing the wings of your great-grandfather.”', 'At 3rd level or higher, the line’s length increases by 10 feet per spell level above 2nd.', ARRAY['druid', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'gust-of-wind']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Forge-Touch', 2, 'Transmutation', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Fire)', 'Concentration, up to 1 minute', 'You point a Fractured Fire-Core at a metal object — a sword, a suit of armor, an Inquisitor’s helm — and speak the Old Tongue word for “smith”: gra’nôk. The metal instantly heats to a cherry-red glow, dealing 2d8 fire damage to any creature in physical contact with it at the moment of casting. If the creature is holding or wearing the heated object and does not drop or doff it, it takes the damage again at the end of each of your subsequent turns as a bonus action. Aether-Smiths use this spell as both a forging tool and a weapon; it can soften metal to be reshaped or turn a warrior’s own plate into a death trap.', 'At 3rd level or higher, the damage increases by 1d8 per spell level above 2nd.', ARRAY['artificer', 'bard', 'druid', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'heat-metal']::text[], FALSE, TRUE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wyrm’s Grasp', 2, 'Enchantment', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Law)', 'Concentration, up to 1 minute', 'You extend your hand, fingers curled like talons, and speak the Old Tongue command keth’shath vorn (“you are held”) while fixing a Fractured Law-Core on your target. The target must succeed on a Wisdom saving throw or be paralyzed as their bloodline — dormant or active — is overridden by a stronger draconic command. The magic does not freeze their muscles; it commands their blood to stillness, pooling icy and disobedient in their veins. While paralyzed, the target is conscious and aware, their eyes tracking movement with a terror known only to prey pinned by a dragon’s gaze.', 'At 3rd level or higher, you can target one additional creature per spell level above 2nd. Each target must be within 30 feet of the others.', ARRAY['bard', 'cleric', 'druid', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'hold-person']::text[], FALSE, TRUE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Veil', 2, 'Illusion', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Shadow)', 'Concentration, up to 1 hour', 'You crush a Fractured Shadow-Core over a creature’s head and whisper the Old Tongue word vish’tal mir (“between seen”). The core’s shadow-stuff cascades over them, bending light around their form. They become invisible until they attack or cast a spell. The invisibility is not perfect — a creature with a strong bloodline (purity 50%+) can make a Wisdom (Perception) check as an action to detect a faint shimmer, like heat rising from sun-baked stone. Inquisitors train their hounds to scent the lingering Shadow-Core residue.', 'At 3rd level or higher, you can target one additional creature per spell level above 2nd.', ARRAY['artificer', 'bard', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'invisibility']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wyrm’s Unlocking', 2, 'Transmutation', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Wild)', 'Instantaneous', 'You tap a Fractured Wild-Core against any solid surface and speak the Old Tongue phrase vorn’shek keth? (“barrier, what barrier?”). A deep, resonant click echoes from the targeted lock, manacle, or door — the sound of ancestral dragon authority overriding mortal craftsmanship. Any non-magical lock opens; any arcane lock (including Aether-Seal) is suppressed for 10 minutes. The unlocking is accompanied by a faint draconic roar, audible up to 300 feet. This is the most frequently-prosecuted spell in Citadel courts; possession of a Wild-Core and intent to unlock is enough for conviction.', NULL, ARRAY['bard', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'knock']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Cleanse', 2, 'Abjuration', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Law)', 'Instantaneous', 'You press a Fractured Law-Core to the afflicted creature and speak the Old Tongue purification: sul’vorn sheth’nar (“let the blood remember itself”). The core pulses with soft gold light as it forces the target’s bloodline to reject foreign contamination. This ends one of the following: blinded, deafened, paralyzed, or poisoned condition, or one disease. It does not remove curses — those are embedded deeper than blood. The target experiences a brief, vivid memory of a dragon ancestor, as if the blood itself is reminding them what they are.', NULL, ARRAY['artificer', 'bard', 'cleric', 'druid', 'paladin', 'ranger', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'lesser-restoration']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon-Lift', 2, 'Transmutation', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Storm)', 'Concentration, up to 10 minutes', 'You sweep a Fractured Storm-Core upward while speaking the Old Tongue word vayr’sul (“rise”). A column of shimmering aether envelops one willing creature, and they feel the phantom weight of draconic wings settle across their shoulders. They ascend vertically up to 20 feet and hover there, able to move only by pushing or pulling along fixed surfaces. The magic does not grant flight — it merely denies gravity — but to the unblooded, it looks like ascension. Inquisitors have a standing order: any non-Ordained seen levitating is to be detained or shot down.', 'At 3rd level or higher, you can target one additional creature per spell level above 2nd.', ARRAY['sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'levitate']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Seek', 2, 'Divination', '1 action', 'Self', 'V, S, M (Fractured Aether-Core — Wild)', 'Concentration, up to 10 minutes', 'You hold a Fractured Wild-Core in your open palm and speak the name or description of an object, followed by the Old Tongue phrase veyr’shek karôs? (“where lies the thing?”). The core trembles, then tugs your hand like a compass needle, guiding you toward the nearest matching object within 1,000 feet that you have seen before. The pull is subtle — a warmth in the right direction — and grows stronger as you approach. This is not true divination but bloodline resonance: your ancestors hoarded treasures; they never forgot where a single coin was buried.', 'At 3rd level or higher, the range increases by 500 feet per spell level above 2nd.', ARRAY['bard', 'cleric', 'druid', 'paladin', 'ranger', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'locate-object']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Whispering Sigil', 2, 'Illusion', '1 minute', 'Touch', 'V, S, M (Fractured Aether-Core — Mind)', 'Until dispelled', 'You trace your bloodline sigil onto a surface with a Fractured Mind-Core and speak the Old Tongue phrase mir’shek vorn (“remember these words”) followed by a message of up to 25 words. The core’s residue sinks into the material, invisible until triggered. You set the trigger condition — someone touches the sigil, speaks a certain name, enters a bloodline into the room. When triggered, a spectral dragon mouth manifests over the sigil and delivers your message in your voice. The mouth then fades, and the sigil goes dormant for 10 minutes before resetting. Spies call these “dragon’s teeth” — scattered everywhere, waiting to bite.', 'At 3rd level or higher, the message length doubles, and you can specify that the sigil only activates for creatures of a minimum purity threshold.', ARRAY['artificer', 'bard', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'magic-mouth']::text[], TRUE, FALSE, 10, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Splintered Self', 2, 'Illusion', '1 action', 'Self', 'V, S, M (Fractured Aether-Core — Shadow)', '1 minute', 'You spin a Fractured Shadow-Core around yourself in a blur while whispering the Old Tongue phrase sheth’vish vorn mir (“I am many, see none”). Three illusory duplicates splinter from your form — each a perfect copy, shifting and overlapping so that an attacker cannot distinguish the real from the false. Each duplicate has its own bloodline sigil flickering faintly; only yours burns true. When an attack would hit you, roll a d20; on a 6+ for three duplicates, 8+ for two, or 11+ for one, the attack hits a duplicate instead, destroying it. Creatures with high purity (75%+) can see through the ruse more easily.', NULL, ARRAY['sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'mirror-image']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Smoke-Shift', 2, 'Conjuration', '1 bonus action', 'Self', 'V, M (Fractured Aether-Core — Shadow)', 'Instantaneous', 'You crush a Fractured Shadow-Core in your fist and utter the Old Tongue word vish’tal vorn (“between here”). Your body dissolves into a plume of silver-black smoke smelling faintly of your draconic heritage — sulfur for red lines, ozone for storm lines, cold nothing for void lines. You reappear up to 30 feet away in an unoccupied space you can see, the smoke coalescing back into form. In the instant of transit, you exist neither here nor there, and cannot be targeted or affected. This is the most-practiced escape spell among Archons; more have survived Inquisitor raids thanks to Smoke-Shift than any other magic.', NULL, ARRAY['sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'misty-step']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Argent Beam', 2, 'Evocation', '1 action', '120 feet', 'V, S, M (Fractured Aether-Core — Light)', 'Concentration, up to 1 minute', 'You hold a Fractured Light-Core to the sky and speak the Old Tongue word selûn’vayr (“moonlight, descend”). A pillar of silver-white radiance 5 feet wide and 40 feet high descends from above, regardless of ceilings or barriers — it phases through solid matter to reach its designated point. The beam burns with the cold light of the pale moon, dealing 2d10 radiant damage to any creature that enters it for the first time on a turn or starts its turn there (Constitution save for half). Shapechangers struck by the beam are forced into their natural form. The light is the inherited echo of a Silver Dragon who once placed the moon in the sky, or so the Lore-Keepers sing.', 'At 3rd level or higher, the damage increases by 1d10 per spell level above 2nd.', ARRAY['druid', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'moonbeam']::text[], FALSE, TRUE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Ghost-Scale', 2, 'Abjuration', '1 action', 'Self (30-foot radius)', 'V, S, M (Fractured Aether-Core — Shadow)', 'Concentration, up to 1 hour', 'You press a Fractured Shadow-Core to your heart and hum the Old Tongue lullaby of the unseen hunter: vish’kar sul’dan (“unseen, patient, still”). A veil of shadow and silence settles over you and up to five creatures you choose within 30 feet. For the duration, you leave no tracks, make no sound, and gain a +10 bonus to Dexterity (Stealth) checks. The magic works by projecting a faint draconic camouflage — the inherited talent of Shadow Wyrmlings who hunted by erasing their own presence. To the mundane eye, you simply aren’t there. A creature with 75%+ purity can make a Wisdom (Perception) check as an action to notice the faint shimmer.', NULL, ARRAY['druid', 'ranger', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'pass-without-trace']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Healing Chant', 2, 'Evocation', '10 minutes', '30 feet', 'V, M (Fractured Aether-Core — Light)', 'Instantaneous', 'You kneel and place a Fractured Light-Core at the center of a circle of up to six creatures, then begin the Old Tongue healing chant: sul’vorn sheth’mir, vrak’sul vorthûn (“let blood remember wholeness, let flesh be unbroken”). Over ten minutes, the core pulses with steady, rhythmic light — like a heartbeat — and each creature in the circle regains 2d8 + your spellcasting ability modifier hit points. This is not prayer but blood-song, the same draconic vocalization a mother dragon uses to heal her clutch. The Inquisition permits Ordained to cast this; anyone else is practicing “unsanctioned blood-healing.”', 'At 3rd level or higher, the healing increases by 1d8 per spell level above 2nd.', ARRAY['cleric', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'prayer-of-healing']::text[], FALSE, FALSE, 10, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Venom Ward', 2, 'Abjuration', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Flesh)', '1 hour', 'You press a Fractured Flesh-Core to a creature’s chest and speak the Old Tongue word vorn’ven sul (“poison, be still”). The core pulses once, and a faint lattice of scales appears across the target’s skin — visible only at certain angles — before fading. For the duration, the target has resistance to poison damage and advantage on saving throws against being poisoned. If they were already poisoned, the condition is neutralized for the duration. The magic works by commanding the target’s blood to recognize venom as foreign and reject it, the same instinct that made ancient dragons immune to every serpent’s bite.', NULL, ARRAY['artificer', 'cleric', 'druid', 'paladin', 'ranger', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'protection-from-poison']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sapping Bolt', 2, 'Necromancy', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Death)', 'Concentration, up to 1 minute', 'You point a Fractured Death-Core at a creature and speak the Old Tongue curse vrak’sul mir (“flesh, weaken”). A black beam streaked with marrow-white light leaps from the core to the target, who must make a Constitution saving throw. On failure, the target’s muscles wither as their bloodline is momentarily drained — they deal only half damage with weapon attacks using Strength for the duration. The target can repeat the saving throw at the end of each of its turns, ending the effect on success. The beam leaves no visible wound, but the target’s veins darken visibly beneath the skin for the duration.', 'At 3rd level or higher, the target has disadvantage on the initial saving throw if you cast this spell using a spell slot one level higher than the target’s maximum spell slot level.', ARRAY['sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'ray-of-enfeeblement']::text[], FALSE, TRUE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Pocket', 2, 'Transmutation', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Wild)', '1 hour', 'You trace a spiraling sigil on a length of rope with a Fractured Wild-Core and speak the Old Tongue phrase karôs vish’tal (“place between”). The rope rises, its top end anchoring to an invisible point in the air — a pocket of folded space, a dragon’s trick of hoarding a den where there should be none. Up to eight creatures can climb the rope into the extradimensional space, which hangs suspended. The entrance is invisible from outside. From inside, the entrance appears as a faint shimmer. When the spell ends, creatures inside fall. This was originally a roost-spell used by Dragon-Lords to sleep safely above their treasure hoards.', NULL, ARRAY['artificer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'rope-trick']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Tri-Fire Bolt', 2, 'Evocation', '1 action', '120 feet', 'V, S, M (Fractured Aether-Core — Fire)', 'Instantaneous', 'You snap a Fractured Fire-Core into three shards and hurl them while snarling the Old Tongue phrase ignar’shek vor, ignar’shek vor, ignar’shek vor! (“flame fang, come — three times!”). Each shard ignites mid-flight into a brilliant bolt of draconic fire, streaking toward targets you designate. Make a ranged spell attack for each bolt, dealing 2d6 fire damage on a hit. The bolts can target a single creature or multiple. The fire burns with your bloodline’s color — crimson, gold, silver, or void-black. Flammable objects ignite on hit. Experienced Archons can curve the bolts around cover with a slight wrist-twist.', 'At 3rd level or higher, you create one additional bolt per spell level above 2nd.', ARRAY['sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'scorching-ray']::text[], FALSE, FALSE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Unveil the Hidden', 2, 'Divination', '1 action', 'Self', 'V, S, M (Fractured Aether-Core — Light)', '1 hour', 'You hold a Fractured Light-Core before your eyes and speak the Old Tongue word veyr’shek vish’tal (“see the between”). Your irises flicker silver as the core’s essence attunes your sight to the aetheric spectrum. For the duration, you see invisible creatures and objects as if they were faintly glowing, and you perceive ethereal beings within 120 feet. Any creature hiding its bloodline (Dormancy) appears to you with their true purity visible as a faint aura — red for active, grey for suppressed, black for severed. The Inquisition considers casting this in Citadel precincts without authorization a third-degree offense.', NULL, ARRAY['artificer', 'bard', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'see-invisibility']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sonic Rupture', 2, 'Evocation', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Storm)', 'Instantaneous', 'You crush a Fractured Storm-Core against a hard surface and scream the Old Tongue roar vayr’kath vorn! (“sky-break!”). A thunderous detonation erupts from a point you choose within range, rolling outward in a 10-foot-radius sphere. Each creature in the area must make a Constitution saving throw, taking 3d8 thunder damage on failure or half on success. Creatures made of stone, crystal, or metal have disadvantage. The shockwave is visibly draconic — witnesses report seeing a spectral dragon’s maw open at the point of detonation. Unsecured objects within the area are flung 10 feet.', 'At 3rd level or higher, the damage increases by 1d8 per spell level above 2nd.', ARRAY['bard', 'cleric', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'shatter']::text[], FALSE, FALSE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sound-Death', 2, 'Illusion', '1 action', '120 feet', 'V, S, M (Fractured Aether-Core — Void)', 'Concentration, up to 10 minutes', 'You hold a Fractured Void-Core to your lips and breathe the Old Tongue command sul’vayr mir (“silence, now”). A 20-foot-radius sphere of absolute silence manifests at a point you choose. No sound can be created within or pass through the sphere; creatures inside are effectively deafened and immune to thunder damage. The sphere is not visible, but those who enter it feel an oppressive weight — the same suffocating quiet of the Void between stars, where even dragons dare not roar. Verbal spell components cannot be spoken within the sphere.', 'At 3rd level or higher, the radius increases by 5 feet per spell level above 2nd.', ARRAY['bard', 'cleric', 'ranger', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'silence']::text[], TRUE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Blade', 2, 'Evocation', '1 bonus action', '60 feet', 'V, S, M (Fractured Aether-Core — Law)', '1 minute', 'You toss a Fractured Law-Core into the air and speak the Old Tongue blade-rite: shek’vorn keth’nar (“blade of judgment, attend”). The core hangs midair and unfolds into a floating spectral weapon shaped like a dragon’s talon, a fang, or a scaled fist — depending on your bloodline. As a bonus action on subsequent turns, you can move the blade up to 20 feet and make a melee spell attack against a creature within 5 feet of it, dealing 1d8 + your spellcasting ability modifier force damage. The blade is made of pure aetheric law and bypasses all damage resistance.', 'At 3rd level or higher, the damage increases by 1d8 per two spell levels above 2nd.', ARRAY['cleric', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'spiritual-weapon']::text[], FALSE, FALSE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon’s Command', 2, 'Enchantment', '1 action', '30 feet', 'V, M (Fractured Aether-Core — Mind)', 'Concentration, up to 8 hours', 'You fix a Fractured Mind-Core on a creature and speak a short, reasonable-sounding command in the Old Tongue — sheth’kar vorn (“you will do this”). The target must make a Wisdom saving throw. On failure, they follow the command to the best of their ability for the duration. The command must sound reasonable; asking the target to harm themselves or obviously walk into a deathtrap automatically negates the spell. This is not charm — it is draconic authority asserting itself over another’s bloodline. Lesser-blooded creatures (purity below 25%) make the save with disadvantage. The Inquisition considers this a form of bloodline domination and prosecutes it as attempted slavery.', 'At 3rd level or higher, the duration increases — 24 hours at 5th level, 30 days at 7th level, 1 year at 9th level.', ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'suggestion']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Oath Link', 2, 'Abjuration', '1 action', 'Touch', 'V, S, M (Fractured Aether-Core — Law)', '1 hour', 'You and a willing creature each grasp one half of a Fractured Law-Core, pull it apart, and speak the Old Tongue vow in unison: keth’vorn vrak’sul, mir’shek vorn’sul (“my blood is yours, your wound is mine”). The core halves embed in each of your chests, glowing faintly through clothing. For the duration, the target gains +1 to AC and saving throws, and has resistance to all damage. However, whenever the target takes damage, you take the same amount as psychic feedback. The link is visible — a thin, glowing filament of aetheric light connects the two core halves. Breaking the link requires severing the filament with a dispel or by moving more than 100 feet apart. Oath-Sworn paladins use this to protect their charges; the ritual is the foundation of their order.', 'At 3rd level or higher, the AC and saving throw bonus increases by +1 per two spell levels above 2nd.', ARRAY['cleric', 'paladin', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'warding-bond']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Silk-Grasp', 2, 'Conjuration', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Wild)', 'Concentration, up to 1 hour', 'You throw a Fractured Wild-Core at a point and speak the Old Tongue phrase shek’var vorn’shath (“threads, bind them”). The core bursts into a 20-foot cube of sticky, semi-translucent webbing — not spider silk but crystallized aether-threads that smell faintly of draconic musk. The webs anchor to all surfaces and are difficult terrain. Each creature that starts its turn in the webs or enters them must succeed on a Dexterity saving throw or be restrained. A creature can use its action to make a Strength check against your spell save DC to break free. The webs are flammable; any fire damage destroys a 5-foot cube and deals 2d4 fire damage to creatures within.', 'At 3rd level or higher, the cube size increases by 5 feet per spell level above 2nd.', ARRAY['artificer', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'web']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Verity Circle', 2, 'Enchantment', '1 action', '60 feet', 'V, S, M (Fractured Aether-Core — Law)', '10 minutes', 'You draw a 15-foot-radius circle on the ground with a Fractured Law-Core and intone the Old Tongue truth-invocation: vorn’shek sheth’mir, vel’sul mir’shek (“speak true, or the void sees”). The circle’s boundary ignites with pale draconic flame. Any creature that enters or starts its turn in the circle must make a Charisma saving throw. On failure, they cannot knowingly speak a lie while within the circle. They may refuse to answer, or speak in half-truths, but outright falsehoods catch in their throat like swallowed glass. An affected creature is aware of the compulsion. This spell is the centerpiece of Citadel judicial proceedings — all testimony before an Ordained magistrate is given within a Verity Circle.', 'At 3rd level or higher, the duration increases to 1 hour at 4th level, 24 hours at 7th level, and the target cannot refuse to answer direct questions at 9th level.', ARRAY['bard', 'cleric', 'paladin', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'zone-of-truth']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Crimson Lash', 2, 'Necromancy', '1 bonus action', 'Self', 'V, S, M (Fractured Aether-Core — Blood)', 'Concentration, up to 1 minute', 'You slice your palm with a Fractured Blood-Core and speak the Old Tongue curse vrak’sul shek’vorn (“my blood, become my blade”). The blood that wells from the wound does not fall — it elongates into a 10-foot crimson lash that floats beside you, crackling with your own life force. As a bonus action on subsequent turns, you can strike a creature within 10 feet. Make a melee spell attack; on a hit, the target takes 2d6 necrotic damage, and you regain hit points equal to half the damage dealt. Each time you deal damage with the lash, you take 1d4 necrotic damage that cannot be reduced — the hemocraft tax. The lash leaves whip-like scars that never fully fade, recognized by other Crimson Oaths as a blood-sibling’s mark.', 'At 3rd level or higher, the lash’s reach increases by 5 feet and the damage increases by 1d6 per spell level above 2nd.', ARRAY['blood_hunter', 'warlock']::text[], ARRAY['solis-grave', 'homebrew', 'blood-hunter-curse']::text[], FALSE, TRUE, 10, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Bolt Gadget', 2, 'Evocation', '1 action', 'Self (60-foot line)', 'V, S, M (Fractured Aether-Core — Storm)', 'Instantaneous', 'You slot a Fractured Storm-Core into a handheld device — a gauntlet-mounted launcher, a modified crossbow, or a wand of coiled copper wire — and pull the trigger while incanting the Old Tongue ignition phrase vayr’shek gran’sul (“lightning, grow”). The gadget crackles, vibrates violently, and discharges a 60-foot line of arcing aetheric lightning. Each creature in the line must make a Dexterity saving throw, taking 3d6 lightning damage on failure or half on success. The device smokes and hisses after firing; the Aether-Core is not consumed unless the spell fizzles. Aether-Smiths are constantly iterating on the design, with some models featuring rifled barrels, focusing lenses, or safety catches that rarely work.', 'At 3rd level or higher, the damage increases by 1d6 per spell level above 2nd.', ARRAY['artificer']::text[], ARRAY['solis-grave', 'homebrew', 'artificer-gadget']::text[], FALSE, FALSE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon’s Authority', 2, 'Enchantment', '1 action', '30 feet', 'V, S, M (Fractured Aether-Core — Law)', 'Instantaneous', 'You raise a Fractured Law-Core like a scepter and speak a single Old Tongue command — keth! (stop), sheth! (kneel), vayr! (flee), or mir! (speak) — and your bloodline asserts itself over another’s. Choose a creature within range; it must succeed on a Wisdom saving throw or obey the command on its next turn. Creatures with lower purity than you make the save with disadvantage. Creatures with higher purity are immune. This is the raw power of a Dragon-Heir — not learned magic but inherited authority. A Sovereign child could command a room of Blanks before they could walk. The Inquisition cannot prosecute this spell because, by law, a Sovereign IS the law.', 'At 3rd level or higher, you can target one additional creature per spell level above 2nd. All targets must be within 30 feet of each other.', ARRAY['sovereign', 'paladin']::text[], ARRAY['solis-grave', 'homebrew', 'sovereign-bloodline']::text[], FALSE, FALSE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Oathbound Strike', 2, 'Evocation', '1 bonus action', 'Self', 'V, M (Fractured Aether-Core — Law)', 'Concentration, up to 1 minute', 'You recite the first line of your sworn oath in Old Tongue and crack a Fractured Law-Core against your breastplate, where it shatters in a burst of pale flame that engulfs your weapon. For the duration, your weapon attacks deal an additional 1d6 radiant damage, and when you strike a creature, a spectral chain of golden light briefly tethers them to you. The target cannot take the Disengage action against you and must make a Wisdom saving throw each time it tries to move more than 30 feet away from you or be pulled back to the edge of that range. This is the mark of an Oath-Sworn — you have declared this enemy under judgment, and there is nowhere they can flee that your oath will not find them.', 'At 3rd level or higher, the radiant damage increases by 1d6 per two spell levels above 2nd.', ARRAY['paladin']::text[], ARRAY['solis-grave', 'homebrew', 'paladin-oath']::text[], FALSE, TRUE, 10, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Predator’s Mark', 2, 'Divination', '1 bonus action', '90 feet', 'V, S, M (Fractured Aether-Core — Flesh)', 'Concentration, up to 1 hour', 'You prick your finger on the edge of a Fractured Flesh-Core and smear your blood across your eyelids while whispering the Old Tongue hunter’s vow: veyr’shath vorn’sul (“my eyes, your trail”). Choose a creature you can see; for the duration, you always know the direction and approximate distance to that creature as long as it is on the same plane. You have advantage on Wisdom (Survival) and Wisdom (Perception) checks related to tracking or finding the marked creature, and your weapon attacks against it score a critical hit on a roll of 19-20. Striders call this “painting the prey” — once marked, no river, no storm, no Aether-Shroud can wash the scent from their blood.', 'At 3rd level or higher, the critical hit range increases to 18-20 at 5th level.', ARRAY['ranger', 'blood_hunter']::text[], ARRAY['solis-grave', 'homebrew', 'ranger-tracking']::text[], FALSE, TRUE, 10, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Raise the Hollow', 3, 'Necromancy', '1 minute', '10 feet', 'V, S, M (Intact Aether-Core — Death)', 'Instantaneous', 'You kneel before a pile of bones or a corpse and press an Intact Death-Core into its chest cavity, reciting the Old Tongue rite of the Hollow King: vrak’sul mir’sheth, vorn’sul vel’shath (“dead flesh, rise hollow”). The core sinks into the remains and reignites them with a pale, cold flame — not life, but animation. You create a skeleton or zombie under your control for 24 hours. The Hollow has no soul, no bloodline, no will; it is a shell animated by the Aether-Core within, obeying your verbal commands. When destroyed or the duration ends, the core shatters and the remains collapse. Only the most desperate or most corrupted casters raise the Hollow. The Inquisition burns anyone caught doing so — caster and Hollow together.', 'At 4th level or higher, you create or reassert control over one additional Hollow per spell level above 3rd.', ARRAY['cleric', 'wizard', 'warlock', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'animate-dead']::text[], FALSE, FALSE, 25, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Vital Radiance', 3, 'Evocation', '1 action', 'Self (30-foot radius)', 'V, S, M (Intact Aether-Core — Light)', 'Concentration, up to 1 minute', 'You press an Intact Light-Core over your heart and breathe the Old Tongue phrase sul’vorn vrak’nir (“life, flow outward”). The core dissolves into warm golden light radiating from your chest in a 30-foot aura. On each of your turns as a bonus action, you can direct the radiance to heal one creature within the aura (including yourself) for 2d6 hit points. The light carries the faint scent of your draconic ancestry — smoke for fire lines, petrichor for storm lines, old stone for earth. This spell was developed by Ordained combat medics during the Purge Wars, when triage required healing multiple wounded while holding a defensive line. The Inquisition licenses it only to certified battlefield clerics.', 'At 4th level or higher, the healing increases by 1d6 per spell level above 3rd.', ARRAY['cleric', 'druid', 'paladin', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'aura-of-vitality']::text[], FALSE, TRUE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon’s Beacon', 3, 'Abjuration', '1 action', '30 feet', 'V, S, M (Intact Aether-Core — Light)', 'Concentration, up to 1 minute', 'You hold an Intact Light-Core aloft and roar the Old Tongue rally-cry vorthûn keth’ragnar! (“unbroken, the First Flame!”). The core erupts in a pillar of golden light 30 feet high, visible for miles. Choose up to six creatures within range; they are bathed in the beacon’s light and filled with ancestral resolve. For the duration, they have advantage on Wisdom saving throws and Death saving throws, and any healing they receive is maximized. The beacon is not subtle — every dragon-blood within 10 miles feels a faint warmth and knows the direction of the light. This spell is the Ordained’s battlefield standard; when the Dragon’s Beacon rises, even the dying fight on.', NULL, ARRAY['cleric', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'beacon-of-hope']::text[], FALSE, TRUE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wyrm’s Malediction', 3, 'Necromancy', '1 action', 'Touch', 'V, S, M (Intact Aether-Core — Void)', 'Concentration, up to 1 minute', 'You touch a creature with an Intact Void-Core and whisper their name in Old Tongue, followed by the curse-formula: sheth’vel mir’sul vrak’nir (“may your blood betray you”). The target must succeed on a Wisdom saving throw or be cursed for the duration. You choose one affliction: disadvantage on an ability score’s checks and saves, disadvantage on attack rolls against you, the target must make a Wisdom save at the start of each turn or waste its action, or your attacks deal an extra 1d8 necrotic damage to them. A creature can only suffer one Wyrm’s Malediction at a time. The curse manifests as a faint black sigil, visible only to those with active purity, branded on the target’s shadow.', 'At 4th level or higher, the duration increases — 10 minutes at 5th level, 1 hour at 7th level, and you may choose a second affliction at 9th level.', ARRAY['bard', 'cleric', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'bestow-curse']::text[], FALSE, TRUE, 25, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Phase-Step', 3, 'Transmutation', '1 action', 'Self', 'V, S, M (Intact Aether-Core — Shadow)', '1 minute', 'You press an Intact Shadow-Core to your chest and speak the Old Tongue phrase vish’tal vish’tal vorn (“between between here”), repeating it until the words blur together. For the duration, at the end of each of your turns, roll a d20. On an 11 or higher, you vanish from the material plane and reappear in the Ethereal Plane until the start of your next turn, at which point you return in the same spot or the nearest unoccupied space. You can still see the material world as a grey haze, but you cannot affect or be affected by anything on it except force damage and effects that specifically reach into the Ethereal. This is the maddening gift of Void-blooded dragons, who learned to exist in two places at once.', NULL, ARRAY['artificer', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'blink']::text[], FALSE, FALSE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Storm-Call', 3, 'Conjuration', '1 action', '120 feet', 'V, S, M (Intact Aether-Core — Storm)', 'Concentration, up to 10 minutes', 'You raise an Intact Storm-Core to the sky and roar the Old Tongue invocation vayr’gran sul’dan vor! (“great storm, answer my blood!”). A roiling storm-cloud 60 feet high and 120 feet wide forms above you, crackling with your bloodline’s elemental color. On each of your turns as an action, you call down a bolt of draconic lightning to strike a point beneath the cloud, dealing 3d10 lightning damage to each creature within 5 feet (Dexterity save for half). If cast outdoors during a storm, the damage increases to 4d10. The cloud follows you, and you can call lightning even through ceilings and barriers. Striders call this “borrowing the sky’s fury.”', 'At 4th level or higher, the damage increases by 1d10 per spell level above 3rd.', ARRAY['druid', 'sorcerer', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'call-lightning']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Far-Sight', 3, 'Divination', '10 minutes', '1 mile', 'V, S, M (Intact Aether-Core — Mind)', 'Concentration, up to 10 minutes', 'You sit cross-legged, place an Intact Mind-Core at the center of your forehead, and enter the Old Tongue trance veyr’sul karôs (“send my sight to that place”). Your consciousness detaches from your body and arrives at a familiar location or an obvious place within range — a dragon’s roost, a Sovereign’s throne room, the last campfire you slept beside. You see and hear as if you were there. You cannot interact, and your body remains senseless where you left it, vulnerable. Skilled casters learn to leave an Aether-Blade or a guardian construct to watch their physical form during Far-Sight. Inquisitor counter-intelligence agents are trained to detect the faint shimmer of a Far-Sight sensor.', 'At 4th level or higher, the range doubles per spell level above 3rd.', ARRAY['bard', 'cleric', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'clairvoyance']::text[], FALSE, TRUE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Beast-Summoning', 3, 'Conjuration', '1 action', '60 feet', 'V, S, M (Intact Aether-Core — Flesh)', 'Concentration, up to 1 hour', 'You hurl an Intact Flesh-Core to the ground and speak the Old Tongue summons vrak’nir gran’sul, vorn’sul karôs (“wild things, come to this place”). The core sinks into the earth and pulses, sending out a draconic call that only beasts can hear. 1d3 creatures of challenge rating 1 or lower, or one creature of challenge rating 2 or lower, answer the call — materializing from aether, drawn by the scent of dragon-blood. They are not tamed but instinctively loyal, obeying your verbal commands in Old Tongue. The creatures are temporary flesh-forms, not true animals; when the spell ends, they dissolve into smoke that smells faintly of your bloodline.', 'At 4th level or higher, the CR of summoned creatures increases — CR 2 or lower for multiple, CR 3 for single at 5th level, scaling upward.', ARRAY['druid', 'ranger', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'conjure-animals']::text[], FALSE, TRUE, 25, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Nullify', 3, 'Abjuration', '1 reaction, which you take when you see a creature within 60 feet casting a spell', '60 feet', 'S, M (Intact Aether-Core — Law)', 'Instantaneous', 'You snap an Intact Law-Core in two with a sharp gesture — no words, just the crack of the core and the assertion of your bloodline against another’s. The triggering spell, if it is 3rd level or lower, is nullified. If it is 4th level or higher, make an ability check using your spellcasting ability (DC 10 + the spell’s level); on success, the spell is nullified. The nullification manifests as a brief, visible collision of two draconic sigils in the air — yours vs. theirs — before both shatter. This is the ultimate expression of bloodline authority: “Your magic is lesser.” The core is not consumed on a successful nullification, but it is consumed if you fail the ability check.', 'At 4th level or higher, you automatically nullify spells of the same level as the slot used or lower without an ability check.', ARRAY['sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'counterspell']::text[], FALSE, FALSE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Sustain', 3, 'Conjuration', '1 action', '30 feet', 'V, S, M (Intact Aether-Core — Flesh)', 'Instantaneous', 'You press an Intact Flesh-Core into the earth and speak the Old Tongue phrase vrak’sul gran’nir, sul’vorn sheth’mir (“flesh grow, blood sustain”). The ground trembles as the core’s essence transmutes soil and stone into food and water — 45 pounds of nutrient-dense, grey-scaled fruit and 30 gallons of clean, cool water. The fruit tastes faintly metallic and of your bloodline (Cinder-blooded create spicy fruit; Frost-blooded create cool, crisp fruit), but sustains a humanoid for a full day per pound. This is draconic survival magic, developed by Wild-Bloods who withdrew into the deep wilds during the Purge Wars. The Inquisition has never ruled on whether Blood-Sustain fruit is “blood-magic contraband” — perhaps because too many Citadel granaries are empty.', NULL, ARRAY['artificer', 'cleric', 'druid', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'create-food-and-water']::text[], FALSE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon’s Radiance', 3, 'Evocation', '1 action', '60 feet', 'V, S, M (Intact Aether-Core — Light)', '1 hour', 'You raise an Intact Light-Core overhead and speak the Old Tongue dawn-word ignar’selûn gran (“great dragon’s sun”). The core flares into a sphere of brilliant draconic radiance 60 feet in radius, shedding true sunlight for the duration. The light is centered on the core, which floats where you designate (or in your hand). Creatures with sunlight sensitivity are affected, and any darkness — magical or otherwise — within the sphere is suppressed. The light is the exact warmth and hue of the long-vanished Sun Dragon who once lit the world, or so the Ordained claim. They also claim that the sun itself was a dragon’s egg. Whether this is metaphor or truth has been debated for three centuries.', 'At 4th level or higher, the radius increases by 30 feet per spell level above 3rd.', ARRAY['cleric', 'druid', 'paladin', 'ranger', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'daylight']::text[], FALSE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Spell-Shred', 3, 'Abjuration', '1 action', '120 feet', 'V, S, M (Intact Aether-Core — Law)', 'Instantaneous', 'You hurl an Intact Law-Core at a creature, object, or area of magical effect and roar the Old Tongue negation: vel’shath sheth’kar! (“come undone!”). The core detonates in a silent, colorless shockwave that shreds the aetheric weave. Any spell of 3rd level or lower on the target ends. For spells of 4th level or higher, make an ability check with your spellcasting ability (DC 10 + the spell’s level) to end them. This is the universal solvent of magic — the assertion that no spell endures against a stronger bloodline. Aether-Smiths describe the process as “un-spelling” and have developed spectacles that tint the normally-invisible shockwave in colors keyed to spell schools.', 'At 4th level or higher, you automatically end the effects of spells of the same level as the slot used or lower without an ability check.', ARRAY['artificer', 'bard', 'cleric', 'druid', 'paladin', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'dispel-magic']::text[], FALSE, FALSE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dread-Presence', 3, 'Illusion', '1 action', 'Self (30-foot cone)', 'V, S, M (Intact Aether-Core — Void)', 'Concentration, up to 1 minute', 'You crush an Intact Void-Core against your chest and release the draconic terror that slumbers in every bloodline. You don’t cast a spell — you unveil yourself. All creatures in a 30-foot cone must make a Wisdom saving throw or become frightened for the duration. While frightened, they must take the Dash action on each turn to move away from you by the safest route, unless there is nowhere to go. At the end of each turn, they may repeat the save. To the targets, you appear to briefly manifest aspects of your dragon ancestor — wings of shadow, eyes of molten gold, a voice that is yours and not yours. This is the closest most mortals will ever come to standing before a true dragon.', 'At 4th level or higher, the cone extends by 10 feet per spell level above 3rd.', ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'fear']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Cinder Burst', 3, 'Evocation', '1 action', '150 feet', 'V, S, M (Intact Aether-Core — Fire)', 'Instantaneous', 'You hurl an Intact Fire-Core at a point within range and speak the Old Tongue detonation: ignar’gran sheth’kar! (“great fire, become!”). A bead of compressed draconic flame streaks from your hand and blooms into a 20-foot-radius sphere of roaring fire. Each creature in the area must make a Dexterity saving throw, taking 8d6 fire damage on failure or half on success. The fire is not mundane — it is your bloodline’s ancestral flame, and it ignites flammable objects not by heat but by commanding their essence to burn. The explosion briefly forms the shape of a dragon’s skull before dissipating. Survivors often report the smell of their own singed bloodline for days afterward.', 'At 4th level or higher, the damage increases by 1d6 per spell level above 3rd.', ARRAY['sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'fireball']::text[], FALSE, FALSE, 25, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wing-Gift', 3, 'Transmutation', '1 action', 'Touch', 'V, S, M (Intact Aether-Core — Storm)', 'Concentration, up to 10 minutes', 'You trace the sigil of the Grand Flight across a creature’s shoulder blades with an Intact Storm-Core and speak the Old Tongue phrase vayr’sul vorn’shath (“sky, bear this one”). The core’s essence suffuses the target, manifesting as a pair of spectral draconic wings — translucent, shimmering, the color of their bloodline. The target gains a flying speed of 60 feet for the duration. The wings are not physical (the target’s clothing is not displaced), and they vanish if the target’s purity is suppressed. This is the most coveted gift a Dragon-Heir can bestow; to be Wing-Gifted is to be acknowledged as blood-kin. A Sovereign who grants Wing-Gift to a Blank is committing an act of political treason in most Citadel nations.', 'At 4th level or higher, you can target one additional creature per spell level above 3rd.', ARRAY['artificer', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'fly']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Mist-Form', 3, 'Transmutation', '1 action', 'Touch', 'V, S, M (Intact Aether-Core — Shadow)', 'Concentration, up to 1 hour', 'You press an Intact Shadow-Core to a willing creature and speak the Old Tongue dissolution: vrak’sul vish’tal vayr’sul (“flesh to mist to sky”). The creature’s body dissolves into a cloud of dark mist — the color of their bloodline — that can pass through narrow cracks, fly at 10 feet per round, and is resistant to nonmagical damage. They cannot attack, cast spells, or manipulate objects, but they can see and hear dimly. The mist smells faintly of dragon musk. Void-blooded casters find this spell unnervingly comfortable; others find the experience of being bodiless deeply disorienting. The Inquisition sneeringly calls it “the coward’s escape.”', NULL, ARRAY['sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'gaseous-form']::text[], FALSE, TRUE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Rune', 3, 'Abjuration', '1 hour', 'Touch', 'V, S, M (Intact Aether-Core — Law)', 'Until dispelled', 'You inscribe a draconic rune onto a surface using an Intact Law-Core as your stylus, weaving a stored spell into the inscription. During the casting, you channel a spell of 3rd level or lower into the rune, which holds it dormant until triggered. Set the trigger conditions — a creature steps on it, speaks a certain word, or opens a warded object. When triggered, the stored spell discharges. If the stored spell is an area effect, it centers on the triggering creature. If it targets a creature, it targets the triggerer. The rune is faintly visible to anyone with active purity; it appears as a glowing draconic character. Aether-Runes are legal for registered Archons to deploy on their own property; laying one in a public space is considered premeditated assault.', 'At 4th level or higher, you can store a spell of a level up to the slot used.', ARRAY['artificer', 'bard', 'cleric', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'glyph-of-warding']::text[], FALSE, FALSE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Quickened Blood', 3, 'Transmutation', '1 action', '30 feet', 'V, S, M (Intact Aether-Core — Storm)', 'Concentration, up to 1 minute', 'You crack an Intact Storm-Core and hurl the pieces at a willing creature while crying the Old Tongue racing-prayer vrak’sul vayr’sul gran! (“blood, fly faster!”). The core’s energy suffuses the target’s bloodstream, and they become a blur of motion. For the duration, the target’s speed doubles, they gain +2 AC, advantage on Dexterity saving throws, and they can take one additional action on their turns — Dash, Disengage, Hide, Use Object, or make a single weapon attack. When the spell ends, the target cannot move or take actions until the end of their next turn as the Quickened Blood recedes, leaving a wave of exhaustion. This is the fastest way to burn out a mortal heart.', 'At 4th level or higher, you can target one additional creature per spell level above 3rd.', ARRAY['artificer', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'haste']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Void’s Maw', 3, 'Conjuration', '1 action', '150 feet', 'V, S, M (Intact Aether-Core — Void)', 'Concentration, up to 1 minute', 'You tear open a fracture in reality with an Intact Void-Core, speaking the Old Tongue words of the Outer Dark: vel’shath gran, mir’sul sheth’kar (“great emptiness, see us”). A 20-foot-radius sphere of black, star-filled void opens at a point within range. The sphere is filled with the whispers of dead stars, and creatures within are blinded. The void is difficult terrain, and any creature that starts its turn there or enters for the first time on a turn takes 2d6 cold damage. Tentacles of living darkness lash out: any creature ending its turn in the Maw takes an additional 2d6 acid damage (Dexterity save to avoid). This is the signature spell of Void-blooded Penitents, who claim the Maw is the mouth of a slumbering Void-Dragon beyond the stars.', 'At 4th level or higher, the cold damage increases by 1d6 per spell level above 3rd.', ARRAY['warlock', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'hunger-of-hadar']::text[], FALSE, TRUE, 25, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Mesmerizing Weave', 3, 'Illusion', '1 action', '120 feet', 'V, S, M (Intact Aether-Core — Mind)', 'Concentration, up to 1 minute', 'You spin an Intact Mind-Core between your fingers and croon the Old Tongue lullaby of the Dream-Wyrm: sul’nir veyr’sul, mir’thal vish’tal (“still now, eyes to the between”). A 30-foot cube fills with twisting, iridescent patterns — your bloodline sigil, fragmented and multiplied into a hypnotic mandala of impossible colors. Each creature in the area that sees the pattern must make a Wisdom saving throw or become charmed and incapacitated with speed 0 for the duration. The creature stares, transfixed, at the weaving lights. The effect ends if the creature takes damage or is shaken awake. For centuries, Dragon-Lords used this spell to pacify rebellious cities without bloodshed — or so the histories claim.', NULL, ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'hypnotic-pattern']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Sanctuary', 3, 'Evocation', '1 minute', 'Self (10-foot-radius hemisphere)', 'V, S, M (Intact Aether-Core — Law)', '8 hours', 'You plant an Intact Law-Core in the ground and trace a 10-foot circle around it while murmuring the Old Tongue sanctuary prayer: karôs vorthûn, vel’shath mir sul (“a place unbroken, the void sees it not”). A dome of faintly shimmering draconic energy rises, invisible from outside but a warm, safe color from within. The dome keeps out weather, nonmagical projectiles, and any creature not present when cast. The atmosphere inside is dry and comfortable regardless of outside conditions. Up to nine creatures can rest inside. The dome does not block magic, but it contains the smell of your bloodline — a subtle deterrent to most beasts. Nomadic Wild-Bloods and fugitive Penitents both rely on the Aether-Sanctuary to survive the wilds.', 'At 4th level or higher, the radius increases by 5 feet per spell level above 3rd.', ARRAY['bard', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'leomunds-tiny-hut']::text[], TRUE, FALSE, 25, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Storm-Lance', 3, 'Evocation', '1 action', 'Self (100-foot line)', 'V, S, M (Intact Aether-Core — Storm)', 'Instantaneous', 'You thrust an Intact Storm-Core forward and scream the Old Tongue word vayr’gran vorn! (“great sky, strike!”). A bolt of draconic lightning 100 feet long and 5 feet wide erupts from your hand, blasting through everything in its path. Each creature in the line must make a Dexterity saving throw, taking 8d6 lightning damage on failure or half on success. The bolt leaves a scorched trench in the ground and ionizes the air, leaving the smell of ozone and a faint taste of copper in your mouth. Unlike natural lightning, the Storm-Lance curves slightly to hit as many targets as possible — the bloodline remembers how to hunt.', 'At 4th level or higher, the damage increases by 1d6 per spell level above 3rd.', ARRAY['sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'lightning-bolt']::text[], FALSE, FALSE, 25, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Binding Circle', 3, 'Abjuration', '1 minute', '10 feet', 'V, S, M (Intact Aether-Core — Law)', '1 hour', 'You inscribe a 10-foot-radius circle on the ground using an Intact Law-Core, speaking the Old Tongue binding rite: keth’shath sul, vorn’shek mir, vel’kar vorthûn (“hold still, speak none, remain bound”). Silver draconic sigils ignite along the circle’s circumference. Choose aberrations, celestials, elementals, fey, fiends, or undead — the circle wards against that type. Affected creatures cannot enter the circle, attack across it, or target those within. A trapped creature within the circle cannot leave by nonmagical means, has disadvantage on attacks against those outside, and must make a Charisma saving throw to use teleportation. The circle can also invert: trapping something inside instead of keeping it out. This is standard Inquisitor equipment for interrogating captured spellcasters.', 'At 4th level or higher, the duration increases — 2 hours at 4th, 8 hours at 5th, 24 hours at 7th.', ARRAY['cleric', 'paladin', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'magic-circle']::text[], FALSE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Grand Phantasm', 3, 'Illusion', '1 action', '120 feet', 'V, S, M (Intact Aether-Core — Mind)', 'Concentration, up to 10 minutes', 'You hold an Intact Mind-Core before you like a lens and project your imagination into the world, speaking the Old Tongue phrase mir’shek gran, sheth’kar vorn (“great image, become here”). You create an illusion of a creature, object, or terrain feature no larger than a 20-foot cube. The phantasm includes sight, sound, smell, and temperature — a dragon, a burning building, a bottomless chasm. It is so detailed that creatures must spend an action examining it (Investigation check against your spell DC) to discern its nature. Even then, the illusion persists; they simply know it is false. A Grand Phantasm of a dragon will cause real fear; a Grand Phantasm of a Sovereign will cause real deference. The mind believes what the bloodline projects.', 'At 4th level or higher, the illusion gains permanence at 6th level, requiring no concentration.', ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'major-image']::text[], FALSE, TRUE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Healing Roar', 3, 'Evocation', '1 bonus action', '60 feet', 'V, M (Intact Aether-Core — Light)', 'Instantaneous', 'You crush an Intact Light-Core and roar the Old Tongue rally: vorthûn! vorthûn! (“unbroken! unbroken!”). A wave of golden light bursts from you, washing over up to six creatures you can see. Each target regains hit points equal to 1d4 + your spellcasting ability modifier. The roar carries your draconic intent — it is not a spoken word but a blood-pulse, felt in the chest more than heard. Lore-Keepers who specialize in Healing Roar train their voices for decades, learning to shape the sound to prioritize the most gravely wounded. In the chaos of battle, that roar has pulled more soldiers from death’s edge than any surgeon’s blade.', 'At 4th level or higher, the healing increases by 1d4 per spell level above 3rd.', ARRAY['bard', 'cleric', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'mass-healing-word']::text[], FALSE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Shroud', 3, 'Abjuration', '1 action', 'Touch', 'V, S, M (Intact Aether-Core — Shadow)', '8 hours', 'You press an Intact Shadow-Core to a creature’s chest and whisper the Old Tongue phrase veyr’shath mir sul (“eyes see none”). The core’s essence diffuses through the target’s bloodstream, masking their bloodline from all divination magic and scrying sensors. The target cannot be perceived through magical means, cannot be located by spells like Far-Sight or Blood-Seek, and any magical attempt to discern their location, thoughts, or purity simply fails. The shroud is invisible, but the target feels a constant, subtle chill — the shadow of their dragon ancestor wrapping around them like a cloak. Fugitive Archons call this their “second skin.”', 'At 4th level or higher, the duration increases to 24 hours at 5th level, 30 days at 8th level.', ARRAY['bard', 'ranger', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'nondetection']::text[], FALSE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Ghost-Steed', 3, 'Illusion', '1 minute', '30 feet', 'V, S, M (Intact Aether-Core — Shadow)', '1 hour', 'You toss an Intact Shadow-Core forward and whistle the Old Tongue steed-call: vayr’vrak sul’dan (“sky-runner, come”). The core unfolds into a quasi-real horse-like creature, dark as shadow with a mane of pale smoke and hooves that strike sparks from empty air. The Ghost-Steed has a speed of 100 feet (or 10 miles per hour at a fast pace), can run across water and quicksand as if solid, and leaves no tracks. It cannot fight and will not enter combat; if you dismount, it waits patiently. When the spell ends, the steed gradually fades over 1 minute, giving the rider time to dismount. Ghost-Steeds are favored by couriers, spies, and anyone who needs to cross the Sump canals without a boat.', 'At 4th level or higher, the steed’s speed increases by 20 feet per spell level above 3rd.', ARRAY['wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'phantom-steed']::text[], TRUE, FALSE, 25, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Verdant Surge', 3, 'Transmutation', '1 action', '150 feet', 'V, S, M (Intact Aether-Core — Nature)', 'Instantaneous', 'You bury an Intact Nature-Core in soil and sing the Old Tongue growing-song: vrak’nir gran’sul, sheth’kar vorn (“wild growth, become here”). The core dissolves into the earth, and all plants within a 100-foot radius surge into overgrowth. Grass becomes waist-high, shrubs become walls, and vines wrap every surface. The area becomes difficult terrain for creatures other than you (who can pass unhindered), and any creature that moves through it must spend 4 feet of movement per 1 foot traveled. The plants are mundane but aggressive; if left alone, they produce double yield for one year. This spell is the reason Wild-Blood farmsteads are self-sufficient within weeks. It can restore a blighted field or turn a battlefield into a deathtrap.', 'At 4th level or higher, the radius increases by 50 feet per spell level above 3rd.', ARRAY['bard', 'druid', 'ranger', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'plant-growth']::text[], FALSE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Element-Ward', 3, 'Abjuration', '1 action', 'Touch', 'V, S, M (Intact Aether-Core — Wild)', 'Concentration, up to 1 hour', 'You press an Intact Wild-Core against a creature and speak the Old Tongue phrase sheth’sul karôs (“element, be still”). The core shifts color to match the element you choose: red (fire), blue (lightning), white (cold), or green (acid). The target gains resistance to the chosen damage type for the duration. The protection manifests as a faint elemental shimmer — a heat haze around a fire-warded target, a cool mist around a cold-warded target. The magic works by commanding the target’s blood to recognize the element as kin; to a fire-blooded creature, a Cinder Burst is merely a warm breeze. This spell is standard issue for Citadel Purge Squads deploying against elemental-breathing rogue Archons.', 'At 4th level or higher, you can target one additional creature per spell level above 3rd.', ARRAY['artificer', 'cleric', 'druid', 'ranger', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'protection-from-energy']::text[], FALSE, TRUE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Break the Malediction', 3, 'Abjuration', '1 action', 'Touch', 'V, S, M (Intact Aether-Core — Law)', 'Instantaneous', 'You press an Intact Law-Core to the cursed creature and intone the Old Tongue severance: vel’shath sheth’kar, vorn’sul mir’shek (“come undone, cursed thing”). The core flares white-hot as it forces the target’s bloodline to reject the foreign magic embedded within. This ends all curses affecting the target — whether from a Wyrm’s Malediction, a cursed item, or another source. The severance is violent; the target takes 1d4 psychic damage as the curse is ripped from their blood, and a visible black mist exudes from their skin before dissipating. The core shatters. Attunement to a cursed item is not broken, but the curse itself is purged. Inquisitors demand that all confiscated cursed items be processed by an Ordained using this spell before storage.', NULL, ARRAY['cleric', 'paladin', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'remove-curse']::text[], FALSE, FALSE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Death-Defy', 3, 'Necromancy', '1 action', 'Touch', 'V, S, M (Intact Aether-Core — Light)', 'Instantaneous', 'You press an Intact Light-Core to the chest of a creature that has died within the last minute and speak the Old Tongue command that no mortal was meant to utter: vrak’sul vorthûn, sheth’kar mir vel’shath! (“flesh unbroken, defy the void!”). The core’s light pours into the corpse, igniting the embers of their bloodline. The creature returns to life with 1 hit point, though they bear a scar where the core touched them — a permanent mark resembling a draconic scale. This spell cannot restore missing body parts or lost purity, nor can it revive someone who died of old age. The Light-Core is consumed in the process. The Inquisition classifies Death-Defy as a restricted miracle — only Ordained of the highest rank may perform it, and every casting must be justified in writing to the Citadel.', NULL, ARRAY['artificer', 'cleric', 'druid', 'paladin', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'revivify']::text[], FALSE, FALSE, 25, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Far-Speech', 3, 'Evocation', '1 action', 'Unlimited (same plane)', 'V, S, M (Intact Aether-Core — Mind)', '1 round', 'You hold an Intact Mind-Core to your lips and whisper a message of up to 25 words, followed by the recipient’s full name and bloodline sigil — if you know it. Speak the Old Tongue phrase mir’shek vayr’sul (“words, fly”). The core vibrates, and your words travel along the aetheric current that connects all dragon-blooded creatures, arriving instantly in the recipient’s mind. They hear the message in your voice and can respond immediately with up to 25 words. The connection is one-way per message; hold a conversation by repeated castings. The Mind-Core is not consumed. Messages sent across planar boundaries require an Intact Wild-Core and have a 5% chance of failure per planar boundary crossed.', 'At 4th level or higher, the message length doubles per spell level above 3rd.', ARRAY['bard', 'cleric', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'sending']::text[], FALSE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Freezing Gale', 3, 'Conjuration', '1 action', '150 feet', 'V, S, M (Intact Aether-Core — Frost)', 'Concentration, up to 1 minute', 'You fling an Intact Frost-Core skyward and shriek the Old Tongue words sul’vayr mir’sul (“freeze the still air”). The core detonates into a 40-foot-radius, 20-foot-high cylinder of driving sleet and razor-sharp ice shards. The area is heavily obscured, and the ground becomes slick (difficult terrain, and any creature that starts its turn there or enters must make a Dexterity save or fall prone). At the start of each of your turns, the storm intensifies, dealing 2d6 cold damage to all creatures within. The flames of any fire in the area are extinguished. Frost-blooded Dragon-Heirs can stand in the heart of their own Freezing Gale and feel only a pleasant chill.', 'At 4th level or higher, the cold damage increases by 1d6 per spell level above 3rd.', ARRAY['druid', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'sleet-storm']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sluggish Blood', 3, 'Transmutation', '1 action', '120 feet', 'V, S, M (Intact Aether-Core — Frost)', 'Concentration, up to 1 minute', 'You point an Intact Frost-Core at up to six creatures in a 40-foot cube and utter the Old Tongue word sul’dan (“slow”). Their blood thickens, their muscles rebel, their draconic spark dims. Each target must make a Wisdom saving throw. On failure, their speed is halved, they take -2 AC and Dexterity saving throws, and they cannot take reactions. On their turn, they can use either an action or a bonus action — not both — and can make only one attack regardless of Extra Attack. They also have a 25% chance (1 on a d4) to have their spellcasting delayed until their next turn, the aether moving sluggishly through their veins. The target can repeat the save at the end of each turn.', 'At 4th level or higher, the number of targets increases by two per spell level above 3rd.', ARRAY['sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'slow']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Corpse-Tongue', 3, 'Necromancy', '1 action', '10 feet', 'V, S, M (Intact Aether-Core — Death)', '10 minutes', 'You press an Intact Death-Core between the jaws of a corpse and speak the Old Tongue question-rite: veyr’shath mir’shek, vrak’sul sul’dan (“dead mouth, speak of what was”). The core turns black and crumbles, and the corpse animates just enough to answer up to five questions — jaw creaking, tongue moving though the lungs are still. The corpse knows only what it knew in life and is not compelled to be truthful (though most are, seeing no reason to lie). Corpses cannot speculate, only recount. Each question you ask burns away more of the remaining spirit-residue; after five, the corpse slumps, unable to speak again even with a new casting. The Inquisition requires a writ from a magistrate to question the dead, though in the Sump, a few silver scales buy the same service.', NULL, ARRAY['bard', 'cleric', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'speak-with-dead']::text[], FALSE, FALSE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Root-Whisper', 3, 'Transmutation', '1 action', 'Self (30-foot radius)', 'V, S, M (Intact Aether-Core — Nature)', '10 minutes', 'You kneel and touch an Intact Nature-Core to the ground, humming the Old Tongue greeting that the first dragons used to speak with the forests they claimed as territory: vrak’nir sul’dan, mir’shek vorn (“green things, speak to me here”). For the duration, you can communicate with plants within 30 feet as if they were creatures that understood Old Tongue. You can question them about recent events — a tree remembers who passed beneath it yesterday, a vine recalls what it entangled last night. Plants are not intelligent but are perceptive in their way; they speak of light, water, weight, and movement. The experience is dreamlike. A rose bush cannot describe a face, but it can tell you that something warm and iron-scented passed by at moonrise.', NULL, ARRAY['bard', 'druid', 'ranger', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'speak-with-plants']::text[], FALSE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Sentinels', 3, 'Conjuration', '1 action', 'Self (15-foot radius)', 'V, S, M (Intact Aether-Core — Law)', 'Concentration, up to 10 minutes', 'You hurl an Intact Law-Core into the air above you and speak the Old Tongue guardian-invocation: keth’nar vorn’sul, sheth’kar mir (“guardians of old, attend this place”). The core splits into drifting motes of light that orbit you in a 15-foot-radius, coalescing momentarily into spectral shapes — dragon-wing silhouettes, scaled fists, roaring maws. When you cast the spell and as a bonus action on subsequent turns, you designate creatures in the area: they must make a Wisdom saving throw or take 3d8 radiant damage (half on success). Their speed is halved in the area. The Sentinels are an echo of the Dragon-Lords’ personal guard, spectral remnants that never truly died. Creatures you designate as allies are unaffected.', 'At 4th level or higher, the damage increases by 1d8 per spell level above 3rd.', ARRAY['cleric', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'spirit-guardians']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Rot-Breath', 3, 'Conjuration', '1 action', '90 feet', 'V, S, M (Intact Aether-Core — Death)', 'Concentration, up to 1 minute', 'You crush an Intact Death-Core and exhale the contents into a 20-foot-radius sphere at a point within range, speaking the Old Tongue phrase vrak’sul vel’shath (“flesh-rot, come forth”). The sphere fills with thick, yellow-green fumes that reek of carrion and old dragon’s breath. The area is heavily obscured. Any creature that starts its turn within the cloud must make a Constitution saving throw or spend its action retching and reeling. Creatures that do not need to breathe or are immune to poison automatically succeed. The fumes linger even after the spell ends, the smell clinging to clothing for days. In the Sump, Rot-Breath is called “the dragon’s morning-after” and is used to clear out rival gang strongholds.', 'At 4th level or higher, the radius increases by 5 feet per spell level above 3rd.', ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'stinking-cloud']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('All-Tongue', 3, 'Divination', '1 action', 'Touch', 'V, S, M (Intact Aether-Core — Mind)', '1 hour', 'You press an Intact Mind-Core to a creature’s throat and speak the Old Tongue phrase mir’shek gran, sheth’kar vorn (“great words, become here”). The core dissolves into the target’s larynx, and for the duration, any creature that knows at least one language can understand everything the target says, regardless of language. The target also understands any spoken language they hear. This is not translation — it is draconic authority imposing comprehension. The words are still spoken in their native tongue, but the meaning is delivered directly to the listener’s mind, accompanied by a faint taste of the target’s bloodline. This spell is essential for diplomatic summits between Houses and the Citadel.', NULL, ARRAY['bard', 'cleric', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'tongues']::text[], FALSE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sanguine Grasp', 3, 'Necromancy', '1 action', 'Self', 'V, S, M (Intact Aether-Core — Blood)', 'Concentration, up to 1 minute', 'You wrap an Intact Blood-Core in your fingers and whisper the Old Tongue thirst-curse: vrak’sul vorn’sul, sul’mir sheth’kar (“your flesh become mine, your life become here”). Your hand becomes wreathed in crimson-black shadow that hungers. Make a melee spell attack against a creature; on a hit, the target takes 3d6 necrotic damage, and you regain hit points equal to half the damage dealt. On each subsequent turn, you can use your action to make the attack again. The shadow-hand does not require contact with bare skin — it phases through armor and clothing to leech directly from the blood beneath. This is the most forbidden spell in Solis-Grave; casting it is an automatic death sentence in every jurisdiction. Even Penitents speak of Sanguine Grasp only in whispers.', 'At 4th level or higher, the damage increases by 1d6 per spell level above 3rd.', ARRAY['warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'vampiric-touch']::text[], FALSE, TRUE, 25, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Gill-Gift', 3, 'Transmutation', '1 action', '30 feet', 'V, S, M (Intact Aether-Core — Water)', '24 hours', 'You crack an Intact Water-Core and anoint up to ten creatures with its cool, briny essence while speaking the Old Tongue phrase vayr’mir sul’dan (“breathe water, still”). Each target’s neck develops faint scale-like ridges — temporary gills that allow them to breathe underwater for the duration. The gills vanish when the spell ends, leaving no trace. The magic was a gift from the Sea-Dragons to their land-bound allies during the ancient wars, allowing armies to march along seafloors and surprise coastal fortresses. Modern smugglers favor Gill-Gift for moving contraband through flooded Sump tunnels where Inquisitor patrol boats cannot follow.', NULL, ARRAY['artificer', 'druid', 'ranger', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'water-breathing']::text[], TRUE, FALSE, 25, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Surface-Tread', 3, 'Transmutation', '1 action', '30 feet', 'V, S, M (Intact Aether-Core — Water)', '1 hour', 'You toss an Intact Water-Core from creature to creature (up to ten) and speak the Old Tongue command vayr’sul sul’dan (“walk still upon the water”). Each target’s feet shimmer with a faint, fluid light. For the duration, they can move across any liquid surface — water, acid, mud, snow, quicksand, lava — as if it were solid ground. Creatures crossing molten lava still take fire damage from the heat. Targets cannot willingly submerge; the surface refuses them. The magic was originally developed by Dragon-Lords who grew tired of fording rivers on campaign. Strider rangers use Surface-Tread to lead pursuit across lakes and bogs, watching their enemies founder helplessly behind them.', 'At 4th level or higher, you can target ten additional creatures per spell level above 3rd.', ARRAY['artificer', 'cleric', 'druid', 'ranger', 'sorcerer', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'water-walk']::text[], TRUE, FALSE, 25, 'None', 0, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Gale-Barrier', 3, 'Evocation', '1 action', '120 feet', 'V, S, M (Intact Aether-Core — Storm)', 'Concentration, up to 1 minute', 'You hurl an Intact Storm-Core and split it mid-flight with the Old Tongue words vayr’shul gran (“great wind-wall”). A wall of roaring wind 50 feet long, 15 feet high, and 1 foot thick springs into existence. The wall deflects arrows, bolts, and thrown weapons — they automatically miss anything behind the wall. Gaseous creatures and swarms cannot pass through. Creatures must make a Strength saving throw to move through the wall; on failure, they are pushed back. The wall howls like a dragon in gale-force fury, imposing disadvantage on Perception checks relying on hearing within 30 feet. The wind smells faintly of the caster’s bloodline — an olfactory signature that can identify the caster to those who know the scent.', 'At 4th level or higher, the wall’s length increases by 25 feet per spell level above 3rd.', ARRAY['druid', 'ranger', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'wind-wall']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Boiling Blood', 3, 'Necromancy', '1 action', '60 feet', 'V, S, M (Intact Aether-Core — Blood)', 'Concentration, up to 1 minute', 'You hold an Intact Blood-Core before you and whisper your own name in Old Tongue, then the target’s, binding your bloodlines in painful sympathy: vrak’sul ignar’sul, sheth’vorn vel’shath (“blood boil, I burn so you burn”). Choose a creature you can see; its blood begins to seethe within its veins. The target must make a Constitution saving throw. On failure, it takes 3d8 fire damage and is wracked with agony — it has disadvantage on attack rolls and ability checks until the end of its next turn. On subsequent turns, you can use your action to deal 3d8 fire damage automatically. However, each time you do so, you take 1d8 necrotic damage as the hemocraft backlash scorches your own blood. Crimson Oaths consider Boiling Blood their signature curse — a weapon of mutual destruction.', 'At 4th level or higher, the initial and ongoing damage increases by 1d8 per spell level above 3rd.', ARRAY['blood_hunter', 'warlock']::text[], ARRAY['solis-grave', 'homebrew', 'blood-hunter-curse']::text[], FALSE, TRUE, 25, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Clockwork Ward', 3, 'Abjuration', '1 action', 'Self (10-foot radius)', 'V, S, M (Intact Aether-Core — Law)', 'Concentration, up to 10 minutes', 'You slot an Intact Law-Core into a palm-sized brass disc inscribed with your maker’s mark and speak the Old Tongue activation phrase keth’nar vorthûn (“guardians, unbroken”). The disc splits into six floating gear-plates that orbit you in a 10-foot radius, continuously rotating. Any hostile creature that enters the radius for the first time on a turn or starts its turn there must make a Dexterity saving throw or take 3d8 slashing damage as the spinning gears tear at them. Allies within the radius are unharmed — the gears recognize your bloodline and your designation of friend from foe. When the spell ends, the gears retract into the disc with a satisfying click. Aether-Smiths refine their Clockwork Wards obsessively, each generation quieter, faster, and more discerning than the last.', 'At 4th level or higher, the damage increases by 1d8 per spell level above 3rd.', ARRAY['artificer']::text[], ARRAY['solis-grave', 'homebrew', 'artificer-gadget']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Bloodline Recall', 3, 'Divination', '1 bonus action', 'Self', 'V, S, M (Intact Aether-Core — Mind)', 'Instantaneous', 'You press an Intact Mind-Core to your temple and roar your own bloodline name in Old Tongue — your full ancestral title, tracing back to the Named Dragon you descend from. The core flashes, and you recover one expended spell slot of 2nd level or lower. This is not simple replenishment; you are reaching back through your bloodline to a moment when that spell was cast by an ancestor, and you are borrowing the unused portion of their power. The experience is disorienting — you briefly relive a fragment of their memory, smell what they smelled, feel what they felt. Bloodline Recall can only be used once per long rest, regardless of how many times it is cast. Dragon-Heirs whisper that overuse risks attracting the attention of ancestors who may not wish to be disturbed.', 'At 4th level or higher, the recovered spell slot level cap increases by one per spell level above 3rd.', ARRAY['sovereign']::text[], ARRAY['solis-grave', 'homebrew', 'sovereign-bloodline']::text[], FALSE, FALSE, 25, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Consecrated Ground', 3, 'Abjuration', '1 minute', 'Touch (30-foot-radius circle)', 'V, S, M (Intact Aether-Core — Law)', '1 hour', 'You kneel and inscribe a 30-foot-radius circle around yourself with an Intact Law-Core, reciting every line of your sworn oath in Old Tongue as you trace. When completed, the circle’s boundary ignites with silver flame, and the ground within becomes consecrated. Allies within the circle gain +2 to AC and saving throws. Any creature that dies within the circle cannot be raised as undead. Any spell of the Necromancy school cast within the circle by a creature other than you requires the caster to succeed on a Spellcasting check against your spell save DC or fail. The consecration is absolute — the flame does not burn, but it rejects the unholy. This is the Oath-Sworn’s ultimate declaration: “This ground is mine. This ground is clean. Nothing profane passes.”', 'At 4th level or higher, the radius increases by 10 feet per spell level above 3rd.', ARRAY['paladin', 'cleric']::text[], ARRAY['solis-grave', 'homebrew', 'paladin-oath']::text[], FALSE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Trail of the Hunt', 3, 'Divination', '1 action', 'Self (1 mile)', 'V, S, M (Intact Aether-Core — Flesh)', 'Concentration, up to 1 hour', 'You crush an Intact Flesh-Core against your chest and inhale deeply, speaking the Old Tongue hunter’s prayer: veyr’shath gran’sul, vrak’sul vorn’nir (“great eyes, show me the blood”). For the duration, you can sense the approximate location, direction, and distance of any creature within 1 mile whose blood you have tasted, whose bloodline sigil you know, or who is currently bleeding. The sense is not visual — it is a pull in your chest, a warmth that grows stronger as you approach, a taste that intensifies on your tongue. You know if the quarry is stationary or moving, and whether their blood-scent is fresh or growing cold. Striders consider Trail of the Hunt sacred; it is taught only to those who have proven they will not abuse the blood-bond between hunter and prey.', 'At 4th level or higher, the range increases by 1 mile per spell level above 3rd.', ARRAY['ranger', 'blood_hunter']::text[], ARRAY['solis-grave', 'homebrew', 'ranger-tracking']::text[], TRUE, TRUE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Watcher', 4, 'Divination', '1 action', '30 feet', 'V, S, M (Intact Aether-Core — Wild)', '1 hour', 'You breathe an ancient syllable of the Old Tongue and trace your bloodline sigil upon the air, tearing free a translucent Aether-Watcher — a floating spectral eye that is the crystallized echo of a dragon''s gaze. The eye has darkvision 30 feet and can see through solid barriers up to 1 foot thick. As a bonus action, you may shift your perception into the eye, seeing through it until you choose to return to your own senses. The eye hovers and moves at your silent mental command (30 feet per round). The eye radiates faint draconic resonance; creatures with 25%+ purity can sense its presence within 10 feet with a successful DC 15 Wisdom (Insight) check.', 'When cast at 5th level or higher, the watcher''s darkvision extends to 60 feet and you may command it to pass through barriers up to 3 feet thick.', ARRAY['wizard', 'sorcerer', 'warlock', 'bard', 'sovereign', 'artificer']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sovereign Vitality', 4, 'Abjuration', '1 action', 'Self (30-foot radius)', 'V, S, M (Intact Aether-Core — Flesh)', '10 minutes', 'You press your palm to your chest and invoke the vital essence of the Primal Dragons, releasing a shimmering pulse of amber-gold light from your bloodline sigil. For the duration, a 30-foot-radius aura radiates from you. All non-hostile creatures within the aura gain resistance to necrotic damage and cannot have their maximum hit points reduced. Any creature that starts its turn within the aura with 0 hit points makes a death saving throw with advantage. The aura manifests as warm, pulsing veins of light crisscrossing the ground like exposed ley-lines.', 'When cast at 6th level or higher, the aura radius increases to 60 feet.', ARRAY['cleric', 'paladin', 'druid', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 30, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Pure Aegis', 4, 'Abjuration', '1 action', 'Self (30-foot radius)', 'V, S, M (Intact Aether-Core — Law)', '10 minutes', 'You carve your bloodline sigil into the air with rigid strokes, calling upon the Law Dragons who first bound chaos into order. A 30-foot aura of silver-tinged light erupts from you. Non-hostile creatures within cannot be diseased, poisoned, blinded, deafened, paralyzed, or charmed — existing conditions are suppressed while the creature remains in the aura. The aura manifests as interlocking geometric bands of light — the principle of draconic order made visible.', 'When cast at 6th level or higher, the aura radius increases to 60 feet.', ARRAY['cleric', 'paladin', 'sovereign', 'druid']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 30, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Severance Decree', 4, 'Abjuration', '1 action', '60 feet', 'V, S, M (Intact Aether-Core — Void)', '1 minute', 'You speak a severance-syllable in the Old Tongue — a word so ancient it predates the division of the planes — and thrust your sigil toward a creature. The target must succeed on a Charisma saving throw or be forcibly ejected from the current plane. If native to a different plane, it returns home. If native to the current plane, it is shunted into the Void Between — a lightless demiplane where it is incapacitated. At each turn''s end, the target repeats the save, returning on success. Creatures with higher blood purity than the caster gain advantage. Those with 90%+ purity are immune.', 'When cast at 5th level or higher, you may target one additional creature for each slot level above 4th.', ARRAY['cleric', 'paladin', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 30, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Withering Blood', 4, 'Necromancy', '1 action', '30 feet', 'V, S, M (Intact Aether-Core — Flesh)', 'Instantaneous', 'You curl your fingers into a claw and hiss a curse-phrase in the Old Tongue, draining life-force from a creature''s bloodline. The target makes a Constitution saving throw, taking 8d8 necrotic damage on a failure or half on a success. Plant creatures and those with the Drained bloodline condition save with disadvantage and take maximum damage. A creature killed by this collapses as a desiccated husk — its Aether-Core instantly fractures into a harvestable Fractured Core. The Inquisition classifies this as bloodline corruption.', 'When cast at 5th level or higher, the damage increases by 1d8 for each slot level above 4th.', ARRAY['druid', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 25, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon''s Command', 4, 'Enchantment', '1 action', '30 feet', 'V, S, M (Intact Aether-Core — Law)', '1 minute', 'You utter a resonant command in the Old Tongue, your voice layered with the harmonic overtones of dragon-speech. Up to three creatures you can see must make a Wisdom saving throw. On a failure, you choose a command word — Approach, Drop, Flee, Halt, Kneel, or Submit — which the target obeys on its next turn. The compulsion is exerted through their blood: they feel an overwhelming ancestral urge to obey a greater dragon-blood. Creatures with higher purity than the caster have advantage; 75%+ are immune except to Submit.', 'When cast at 5th level or higher, target one additional creature for each slot level above 4th.', ARRAY['bard', 'wizard', 'sovereign', 'cleric']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 30, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Mind-Scatter', 4, 'Enchantment', '1 action', '90 feet', 'V, S, M (Intact Aether-Core — Void)', '1 minute', 'You trace a fractured version of your bloodline sigil and release a discordant shriek — the cry of a Void-Dragon''s shattered mind. Creatures in a 10-foot-radius sphere must succeed on a Wisdom save or be unable to take reactions and must roll a d10 at the start of each turn: 1 moves randomly, 2-6 takes no action, 7-8 attacks a random creature in reach, 9-10 acts normally. Affected creatures repeat the save at each turn''s end. Void-blooded creatures have advantage. This spell is deeply illegal — even the Citadel does not authorize it outside containment scenarios.', 'When cast at 5th level or higher, the radius increases by 5 feet per slot level above 4th.', ARRAY['bard', 'druid', 'sorcerer', 'wizard', 'warlock', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Call Aether-Kin', 4, 'Conjuration', '1 minute', '90 feet', 'V, S, M (Intact Aether-Core — matching element)', '1 hour', 'You chant the Naming-Rite of the Old Tongue, calling lesser elemental spirits forged from the blood of dead dragons whose essence seeped into the elements millennia ago. Summon Aether-Kin — elemental creatures with faint draconic features (scaled hide, slit pupils, vestigial wing-frills): one CR 2 or lower, two CR 1 or lower, four CR 1/2 or lower, or eight CR 1/4 or lower. They obey verbal commands in the Old Tongue. When slain, they dissolve into inert elemental residue with no harvestable Core.', 'When cast at 6th level or higher, the CR limit increases: 5th-CR 3, 6th-CR 4, etc.', ARRAY['druid', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Summon Wild-Blood', 4, 'Conjuration', '1 action', '60 feet', 'V, S, M (Intact Aether-Core — Flesh)', '1 hour', 'You trace the Primal Sigil — the oldest bloodline crest — and call forth fey spirits embodying the untamed dragon-blood of the deep wilds. Summon fey in beast form with draconic features (wolves with scale-crests, stags with forked tongues, serpents with wing-flaps): one CR 2 or lower, two CR 1 or lower, four CR 1/2 or lower, or eight CR 1/4 or lower. They are fey, not beasts, and understand the Old Tongue. Slain Wild-Bloods evaporate into mist laced with ozone and old blood.', 'When cast at 6th level or higher, the CR limit increases: 5th-CR 3, 6th-CR 4, etc.', ARRAY['druid', 'ranger', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Tide Command', 4, 'Transmutation', '1 action', '300 feet', 'V, S, M (Intact Aether-Core — Frost or Storm)', '10 minutes', 'You intone a fluid phrase in the Old Tongue — the speech of the Sea-Dragons sleeping beneath Abyssal trenches. Seize control of a 100-foot cube of water. Choose one: Flood (raise water level by 20 feet, Strength save or be carried), Part Water (100-ft-long, 20-ft-wide trench), Redirect Flow (reverse or divert at up to 30 ft/round), or Whirlpool (50-ft-cube vortex, Strength save or 2d8 bludgeoning and pulled to center). The water''s surface roils with faint spectral draconic scales. Licensed for shipping guilds with maritime permit.', 'When cast at 5th level or higher, the cube increases by 50 feet per side for each slot level above 4th.', ARRAY['cleric', 'druid', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Last Breath Binding', 4, 'Abjuration', '1 action', 'Touch', 'V, S, M (Intact Aether-Core — Flesh)', '8 hours', 'You press your sigil-hand to a willing creature and whisper the Binding-Vow of the First Dragons. The first time the target would drop to 0 hit points, they instead drop to 1 and the spell ends. If subjected to an instant-death effect, that effect is negated and the spell ends. The ward manifests as faint, near-invisible draconic scales flickering silver when triggered. Oath-Sworn paladins consider this a sacred duty. The Inquisition barely tolerates it — it defers death, does not raise the dead.', NULL, ARRAY['cleric', 'paladin', 'sovereign', 'druid']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sigil-Step', 4, 'Conjuration', '1 action', '500 feet', 'V, S, M (Intact Aether-Core — Void)', 'Instantaneous', 'You trace your bloodline sigil before you and plunge your hand through its center. The air tears with a sound like ripping silk. You teleport yourself and one willing creature of your size or smaller to any unoccupied space you can see or visualize. You arrive wreathed in dissipating aether-smoke. The Void Between journey takes an instant but feels like falling through darkness while distant draconic whispers echo. Attempting to teleport into an occupied space shunts you to the nearest unoccupied space dealing 4d6 force damage. Inquisitorial wards in cities block Sigil-Step — casting within Citadel zones triggers alarms.', 'When cast at 5th level or higher, bring one additional willing creature per slot level above 4th.', ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Read the Bloodlines', 4, 'Divination', '1 action', '?', 'V, S, M (Intact Aether-Core — Law or Wild)', 'Instantaneous', 'You prick your finger on your Aether-Core and let blood fall upon your sigil. The drop spreads into patterns. Ask a question about a goal, event, or activity within 7 days. The Blood-Gods respond through an omen, an Old Tongue fragment, a sensory vision, or a symbolic blood-image. Answers are truthful but often cryptic — the Dragon-Gods speak in riddles. Recalling the same topic yields the same answer. The reading leaves a blood-sigil on the ground for 1 hour, readable by anyone 25%+ purity (DC 15 Arcana). Unlicensed casting is sedition — punishable by branding.', NULL, ARRAY['cleric', 'druid', 'warlock', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], TRUE, FALSE, 30, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Bend the Wild Blood', 4, 'Enchantment', '1 action', '60 feet', 'V, S, M (Intact Aether-Core — Flesh)', '1 minute', 'You fix a beast with your draconic stare, invoking the Primal Dominance — the ancient covenant that all lesser creatures descend from the First Dragons. The target must succeed on a Wisdom save or be charmed. You share a telepathic link same-plane and may issue mental commands. You may use your action to assume total control, perceiving through its senses. The beast''s eyes take on a golden, slit-pupiled gleam. Beasts with draconic ancestry save with disadvantage. Beasts with 10%+ purity repeat the save at each turn''s end.', 'At 5th: 10 min. At 6th: 1 hour. At 7th+: 8 hours.', ARRAY['druid', 'ranger', 'sorcerer', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Forging', 4, 'Transmutation', '10 minutes', '120 feet', 'V, S, M (Intact Aether-Core — Fire or Storm)', 'Instantaneous', 'You sketch the Forge-Sigil and channel raw draconic creation energy into raw materials, converting them into a finished product of the same material. Forge a bridge from lumber, reshape ore into a blade, weave hemp into rope and sails. Quality matches raw materials. Cannot create magical items or creatures. Objects are permanent. Creatures in the area when matter reshapes make a Dexterity save or take 4d10 force damage. Materials glow white-hot, flow like liquid, and solidify in seconds. Licensed to guild-certified Aether-Smiths only.', 'At 5th+, affect material one size category larger per slot level above 4th.', ARRAY['wizard', 'artificer', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Cinder Mantle', 4, 'Evocation', '1 action', 'Self', 'V, S, M (Intact Aether-Core — Fire or Frost)', '10 minutes', 'You exhale a wreath of elemental draconic energy that wraps around your body like a second skin. Thin spectral scales shimmer across your form — wreathed in whirling flames (warm) or sheening frost (cold). Gain resistance to fire (warm) or cold (cold). Any creature within 5 feet that hits you with a melee attack takes 2d8 damage of the chosen type. Sheds bright light 10 ft. and dim 10 ft. (warm) or dim 10 ft. only (cold). Switch modes as a bonus action by whispering the opposing element''s name. Fire-blooded Archons may cast without verbal components.', 'At 5th+, retaliation damage increases by 1d8 per slot level above 4th.', ARRAY['wizard', 'sorcerer', 'sovereign', 'warlock']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Unchained Blood', 4, 'Abjuration', '1 action', 'Touch', 'V, S, M (Intact Aether-Core — Storm)', '1 hour', 'You smear a drop of your blood across a willing creature''s forehead and intone the Liberation Verse of the Storm-Dragons. For the duration, the target''s movement is unaffected by difficult terrain, and magic cannot reduce its speed or paralyze, restrain, or grapple it. The target may spend 5 feet of movement to auto-escape non-magical restraints. The body subtly flickers like heat haze — the Storm-Dragon''s blessing of unchained motion. Swimming speed is full speed without penalty. Strider rangers favor this for hostile wilderness navigation.', 'At 5th+, target one additional creature per slot level above 4th.', ARRAY['bard', 'cleric', 'druid', 'ranger', 'sovereign', 'artificer']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Swarm Awakening', 4, 'Transmutation', '1 action', '30 feet', 'V, S, M (Intact Aether-Core — Flesh)', '10 minutes', 'You snatch a handful of insects and breathe aether-laced air over them. They swell grotesquely, veins pulsing with temporary draconic ichor, growing to giant size. Transform: ten centipedes into giant centipedes, three spiders into giant spiders, five wasps into giant wasps, or one scorpion into a giant scorpion. They obey your Old Tongue commands on their own initiative. When the spell ends or they drop to 0 hit points, they shrink back to normal size, dead or exhausted. Corpses yield trace aether-residue worth 5 GC to alchemists.', 'At 5th+, double the number of insects transformed per slot level above 4th.', ARRAY['druid', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Drake-Tendril Grasp', 4, 'Conjuration', '1 bonus action', '30 feet', 'V, S, M (Intact Aether-Core — Flesh or Wild)', '1 minute', 'You thrust your hand toward the ground and a thick, thorned vine erupts — each barb a tiny keratinous scale, the vine pulsing with a reptilian heartbeat. The vine occupies a 5-foot square on the ground. As a bonus action, you command it to lash a creature within 30 feet: Dexterity save or pulled 20 feet toward the vine and restrained until your next turn. AC 15, 30 HP, resistance to non-magical piercing/bludgeoning, immunity to poison and psychic. Bleeds thin amber ichor when damaged. Wild-Blood druids grow these from drake-graves.', 'At 5th+, summon one additional vine per slot level above 4th.', ARRAY['druid', 'ranger', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Void-Shroud', 4, 'Illusion', '1 action', 'Touch', 'V, S, M (Intact Aether-Core — Void)', '1 minute', 'You press your Aether-Core to a willing creature and whisper the Void-Dragon''s Name-of-Nothing. The target becomes invisible — nothing breaks it: attacking, casting, or shouting all remain covered. The target appears as a faint heat-shimmer, requiring DC 20 Perception to spot. Blindsight, truesight, and 75%+ purity (DC 18 Wisdom save) still perceive normally. This is borrowed nothingness — an echo of the space between planes. Shadow-Blood rogues and Penitents seek this obsessively. Void-Core possession plus knowledge of this spell is prima facie conspiracy evidence.', 'At 5th+, target one additional creature per slot level above 4th.', ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 30, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Oath-Warden', 4, 'Conjuration', '1 action', '30 feet', 'V, S, M (Intact Aether-Core — Law)', '8 hours', 'You slash your sigil onto the ground and a spectral guardian rises — a faceless armored figure wreathed in silver light, clutching a greatsword of pure radiance. The guardian occupies a 10-foot cube, immune to all damage. Any hostile creature entering the area for the first time on a turn or ending its turn there makes a Dexterity save: 20 radiant damage on failure, half on success. Vanishes after dealing 60 total damage. Immobile and silent. An echo of an ancient Oath-Sworn who died keeping a promise. On desecrated ground, may manifest as shadow-veiled, dealing necrotic damage.', 'At 5th: 80 threshold; 6th: 100; 7th: 120; 8th+: 140.', ARRAY['cleric', 'paladin', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 30, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dream-Scaped Ground', 4, 'Illusion', '10 minutes', '300 feet', 'V, S, M (Intact Aether-Core — Wild or Void)', '24 hours', 'You walk the perimeter, brushing the ground and whispering a Dream-Weaving draconic lullaby. Terrain within a 150-foot cube is cloaked in illusion: natural terrain looks, sounds, and smells like other natural terrain. Swamp becomes meadow, cliff becomes slope, forest clearing becomes bog. Structures, equipment, and creatures are not disguised. The illusion includes tactile elements but no physical change. Physical interaction reveals the illusion. Woven from the dreams of the World-Dragons who shaped the continents. Lore-Keepers protect hidden bloodline shrines with it.', 'At 5th+, cube dimensions increase by 50 feet per slot level above 4th.', ARRAY['bard', 'druid', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Rime Cascade', 4, 'Evocation', '1 action', '300 feet', 'V, S, M (Intact Aether-Core — Frost)', 'Instantaneous', 'You roar a Frost-Dragon''s battle-cry and a cylinder of howling sleet and jagged hail plummets onto a point. Creatures in a 20-foot-radius, 40-foot-high cylinder make a Dexterity save: 2d8 bludgeoning + 4d6 cold on failure, half on success. The area becomes difficult terrain until the end of your next turn, and the ground freezes — any creature starting its turn there or entering makes a DC 10 Dexterity save or falls prone. Hailstones shimmer with faint draconic blue luminescence. Inspired by Rime-Dragons, the smallest and most vicious Frost lineage.', 'At 5th+, bludgeoning damage increases by 1d8 per slot level above 4th.', ARRAY['druid', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sigil-Vault', 4, 'Conjuration', '1 action', 'Touch', 'V, S, M (Intact Aether-Core — Void, and a chest of drake-bone or dragon-scale worth 500 GC)', 'Instantaneous', 'You touch a chest and trace your sigil across its lid. It vanishes with a soft sucking sound — pulled into a stable Void Between pocket keyed to your bloodline. The chest must be crafted from draconic-resonant materials. As an action, summon it back to within 5 feet by tracing your sigil in reverse. A Tiny replica (non-magical, 5 GC) remains; crushing it destroys the chest and scatters contents irretrievably across the Void. Persists indefinitely until retrieved or replica destroyed. Inquisition detection wards sense active Sigil-Vaults within 100 feet.', 'At 6th: Huge chest. At 8th+: Gargantuan chest.', ARRAY['wizard', 'warlock', 'artificer', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Trail Hunt', 4, 'Divination', '1 action', 'Self', 'V, S, M (Intact Aether-Core — Flesh or Wild)', '1 hour', 'You prick your finger and let blood fall upon your tongue, tasting the resonance of a creature''s bloodline signature. Name or describe a creature familiar to you. For the duration, sense its direction and distance within 1,000 feet on the same plane. If moving, you know direction of movement. Can locate a specific creature or the nearest of a kind you''ve seen within 30 feet at least once. Running water, thick lead, or consecrated Citadel ground blocks the sense. Strider rangers learn this for bounty-hunting. Cannot locate 90%+ purity creatures actively suppressing their signature.', 'At 5th: 5,000 ft; 6th: 1 mile; 7th: 10 miles; 8th+: unlimited same-plane.', ARRAY['bard', 'cleric', 'druid', 'paladin', 'ranger', 'wizard', 'sovereign', 'blood_hunter']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Watch Hound', 4, 'Conjuration', '1 action', '30 feet', 'V, S, M (Intact Aether-Core — Law)', '8 hours', 'You sketch a hound-shape with your sigil and a phantom watchdog materializes — a spectral mastiff woven from pure aether and draconic vigilance. Invisible except to you, it cannot be harmed. Occupies a 5-foot cube. When a Small or larger creature comes within 30 feet without speaking the password, the hound barks loudly — audible to 300 feet with a draconic harmonic undertone. It sees invisible and ethereal creatures, ignoring illusions. On barking, it bites one intruder within 5 feet (your spell attack, 4d8 piercing). Archon Casters developed this from studying watch-drakes bred by ancient bloodlines.', 'At 5th+, bite damage increases by 1d8 per slot level above 4th.', ARRAY['wizard', 'sovereign', 'artificer']::text[], ARRAY['solis-grave', 'srd']::text[], TRUE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sealed Blood-Sanctum', 4, 'Abjuration', '10 minutes', '120 feet', 'V, S, M (Intact Aether-Core — Law or Void)', '24 hours', 'You trace your sigil at four cardinal points and bleed a drop at each corner. A cube up to 100 feet per side becomes warded. Sound cannot pass through; creatures outside cannot see in — the barrier appears as opaque shimmering silver-gray. Scrying sensors cannot enter; creatures inside cannot be targeted by divination. Teleportation into or out is blocked. Keyed to your bloodline signature; same-element creatures pass freely. Casting daily for one year makes it permanent. Sovereigns use this to shield heirs from Inquisitorial scrying. Discovery of a permanent sanctum is grounds for immediate Inquisitor raid.', 'At 5th+, cube dimensions increase by 50 feet per slot level above 4th.', ARRAY['wizard', 'sovereign', 'cleric', 'warlock']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 30, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Shell', 4, 'Evocation', '1 action', '30 feet', 'V, S, M (Intact Aether-Core — Law or Wild)', '1 minute', 'You cup your hands and exhale a shimmering sphere of force — a translucent, iridescent dome humming with contained aetheric pressure. A Large or smaller creature within range must make a Dexterity save or be enclosed. The sphere is immobile and impenetrable — nothing passes inward or outward. The creature breathes normally but leaves only via teleportation (Charisma check vs. your spell DC). Can be rolled at half speed. AC 10, damage threshold 15; shatters if it takes more than 15 damage from a single attack.', 'At 5th+, enclose one size larger per slot level above 4th.', ARRAY['wizard', 'sovereign', 'artificer']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dread-Vision', 4, 'Illusion', '1 action', '120 feet', 'V, S, M (Intact Aether-Core — Void)', '1 minute', 'You lock eyes with a creature and draw forth their deepest fear — a primal terror embedded in bloodline memory from when dragons hunted humanoids. Target must make a Wisdom save. On failure, frightened for the duration. At each turn''s end, it makes another Wisdom save: 4d10 psychic damage on failure, spell ends on success. The target perceives its worst fear as a physical manifestation stalking it. 50%+ purity has advantage on the initial save. Void-touched creatures are immune. Penitents of the Void believe this culls the weak-blooded. The Inquisition has executed casters for using this as torture.', 'At 5th+, psychic damage increases by 1d10 per slot level above 4th.', ARRAY['wizard', 'warlock', 'sorcerer', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Shape the Blood', 4, 'Transmutation', '1 action', '60 feet', 'V, S, M (Intact Aether-Core — Flesh)', '1 hour', 'You invoke the Primal Dragon''s gift of infinite forms — the power that let the first dragons walk as humanoids among mortals. Transform a creature into a new form. Unwilling targets make a Wisdom save. New form: any beast of CR ≤ target''s level/CR (max CR 8). Statistics replaced, but alignment, personality, and language understanding remain. Creatures with 25%+ purity retain Int/Wis/Cha scores. Gains temp HP equal to beast''s HP; reverts when depleted or spell ends. Skin stretches and draconic scales flicker during transformation. Wild-Blood druids consider this their highest art.', 'At 5th+, CR maximum increases by 2 per slot level above 4th.', ARRAY['bard', 'druid', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 30, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Earth-Blood Sculpt', 4, 'Transmutation', '1 action', 'Touch', 'V, S, M (Intact Aether-Core — Flesh or Wild)', 'Instantaneous', 'You place both hands upon stone and murmur the Earth-Dragon''s Shaping-Hymn — a grinding chant vibrating through your bones. Reshape a 5-foot-cube section of stone into any form: a door, window, statue, non-magical weapon, manacles, or a passage. Finely crafted stonework grants +5 to the shaping DC. No intricate moving parts, but simple hinges work. Stone warms under your hands, flows like thick mud, and solidifies permanently. If used to seal a creature in stone, they may attempt DC 20 Strength to break free (AC 17). Aether-Smiths use this to craft invention chassis; Ordained repair damaged shrines with it.', NULL, ARRAY['cleric', 'druid', 'wizard', 'sovereign', 'artificer']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Scale-Hide', 4, 'Abjuration', '1 action', 'Touch', 'V, S, M (Intact Aether-Core — Flesh or Fire)', '1 hour', 'You clasp a willing creature''s arm and exhale gritty, mineral-laden breath over their skin. Semi-translucent draconic scales ripple across the flesh, hardening instantly. The target gains resistance to non-magical bludgeoning, piercing, and slashing damage. Scales are visible — a faint opalescent shimmer shifting colors with movement (DC 15 Perception to notice). The target''s voice drops half an octave as their throat thickens with protective cartilage. Developed from studying Adamant-Dragons whose scales no mortal weapon could pierce. Oath-Sworn cast this on squires before first battle; Striders use it expecting ambushes.', 'At 5th+, target one additional creature per slot level above 4th.', ARRAY['druid', 'ranger', 'sorcerer', 'wizard', 'sovereign', 'artificer', 'paladin']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Cinder Wall', 4, 'Evocation', '1 action', '120 feet', 'V, S, M (Intact Aether-Core — Fire)', '1 minute', 'You slash your hand through the air and a wall of roaring draconic flame erupts — 60 feet long, 20 feet high, 1 foot thick, burning orange-gold with writhing draconic silhouettes within. One side blasts searing heat: creatures within 10 feet of that side when appearing or ending turns there take 5d8 fire damage (Dex save). The opposite side emits only warmth. Entering or ending in the wall deals 5d8 fire damage. Opaque, blocks line of sight. Ignites flammable objects within 10 feet of the hot side. Flames roar like distant dragon-cries. Fire-blooded Archons add Charisma modifier to damage.', 'At 5th+, damage increases by 1d8 per slot level above 4th.', ARRAY['druid', 'sorcerer', 'wizard', 'sovereign', 'warlock']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Crimson Brand', 4, 'Necromancy', '1 bonus action', 'Self', 'V, S, M (Intact Aether-Core — Flesh, and the caster takes 4d6 necrotic self-damage)', '1 minute', 'The apex Blood Curse of the Crimson Oath — earned through the Hemocraft Trials. You drag your blade across your palm; spilling blood ignites into burning crimson sigils. For the duration, your weapon attacks deal +2d6 necrotic, and each hit forces a Constitution save: on failure, the target is branded — it cannot regain hit points until your next turn and the next attack against it has advantage. As a bonus action, you may amplify: target one branded creature within 60 feet, dealing 3d6 necrotic automatically (no save, bypasses resistance/immunity), ending the brand. Self-damage cannot be reduced. Your blood makes the ground within 10 feet difficult terrain for all but you. Overuse risks permanent bloodline scarring visible to Inquisitors as glowing red vein-patterns.', 'At 5th level: self-damage 5d6, weapon bonus 3d6, amplify 4d6.', ARRAY['blood_hunter']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, TRUE, 30, 'Severe', 3, 'Crimson Oath') ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Bound Mechanism', 4, 'Transmutation', '1 minute', 'Touch', 'V, S, M (Intact Aether-Core — Storm or Fire, plus a mundane mechanical device worth at least 100 GC)', '8 hours', 'The signature masterwork of the Aether-Smith. You embed your Aether-Core into a mundane device''s heart. It bonds, animating with aetheric energy and gaining temporary magical properties. Choose one infusion: Auto-Loading (device operates on its own once per round — crossbow reloads, lantern re-ignites), Overcharge (output doubles — weapon deals +1d10 lightning on next attack, lantern double radius, shield +3 AC for one round), or Sentinel Mode (device hovers independently within 5 feet and acts on your bonus action — crossbow fires using your spell attack). Glows with blue-white aether-light; draconic script scrawls across its surface. At spell''s end or when reduced to 0 HP, returns to mundane state and the Core is burned out (harvestable as Fractured Core).', 'At 5th level: duration 24 hours, may apply two infusions simultaneously.', ARRAY['artificer']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, FALSE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Oath of the Sovereign''s Shield', 4, 'Abjuration', '1 action', '30 feet', 'V, S, M (Intact Aether-Core — Law)', '1 minute', 'The high oath of the Shield-Order Paladins — those who pledge their bloodline to protect a single charge unto death. You kneel, press your palm to your heart, and speak the Binding Vow in the Old Tongue. Choose a willing creature — your Charge. When your Charge takes damage, as a reaction you may teleport to an unoccupied space within 5 feet of them and the damage transfers to you (bypassing your resistances/immunities). You and your Charge gain +2 AC and saving throws while within 30 feet. The bond manifests as a shimmering golden chain linking your sigil to your Charge''s chest. Moving more than 120 feet apart ends the spell. If you drop to 0 HP intercepting damage, it also ends. Requires completion of the Trial of the Shield — a grueling ritual leaving permanent scars. Casting it selfishly (self-only, no intent to protect) causes 6d6 psychic backlash.', 'At 5th: designate up to two Charges, teleport-interception costs no reaction (once per round).', ARRAY['paladin']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, TRUE, 35, 'Severe', 3, 'Shield-Order') ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Strider''s Apex Trail', 4, 'Divination', '1 action', 'Self (1-mile radius)', 'V, S, M (Intact Aether-Core — Flesh or Wild)', '1 hour', 'The apex tracking technique of Strider conclave masters. You close your eyes and taste the air, your sigil glowing faintly on your tongue. For the duration, you perceive blood-trails of all creatures that passed within 1 mile in the last 24 hours as translucent colored ribbons visible only to you: red (warm-blooded), blue (cold-blooded), black (undead), iridescent silver (extraplanar). Fresher = brighter. As a bonus action, focus on one trail to learn the creature''s type, emotional state at passage (frightened, aggressive, calm, injured), and direction of travel. Ribbons hover at waist height. Consecrated Citadel ground or active Sealed Blood-Sanctums disrupt trails within 100 feet. This is a closely guarded Strider secret; teaching outsiders is punishable by exile.', 'At 5th level: 5-mile radius, perceive trails up to 7 days old.', ARRAY['ranger']::text[], ARRAY['solis-grave', 'homebrew']::text[], TRUE, TRUE, 25, 'Low', 1, 'Strider Conclave') ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Awaken the Vessels', 5, 'Transmutation', '1 action', '120 feet', 'V, S, M (Intact Aether-Core — Storm or Flesh)', '1 minute', 'You spread your arms and intone the Animating Verse — a rolling, percussive Old Tongue chant the World-Dragons used to give motion to the first mountains. Up to ten non-magical objects animate as constructs with AC 18, HP by size (Tiny: 20, Small: 25, Medium: 40, Large: 50), blindsight 30 feet, flying 30 (leaving faint aether-trails). As a bonus action, mentally command any within 500 feet to move and attack. Damage by size: Tiny 1d4+4, Small 1d8+2, Medium 2d6+1, Large 2d10+2 (bludgeoning). Surfaces ripple with spectral scales — a cup sprouts draconic wings, a table grows a serpentine flame-tongue. Aether-Smithers field-test prototype swarms; the Inquisition clears rubble without touching corrupted artifacts.', 'At 6th+, animate two additional objects per slot level above 5th.', ARRAY['bard', 'sorcerer', 'wizard', 'sovereign', 'artificer']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Repel the Living', 5, 'Abjuration', '1 action', 'Self (10-foot radius)', 'V, S, M (Intact Aether-Core — Void or Law)', '1 hour', 'You trace a circle with your sigil-hand and a shimmering pale-silver hemisphere barrier springs up, humming with repulsive aetheric pressure. Extends 10 feet from you, moving with you. Living creatures (not undead or constructs) cannot enter; any inside when cast are pushed out. Attacks, spells, and effects crossing the barrier are blocked — though you may cast on yourself freely. Parts around terrain. The barrier thrums with a low, draconic subsonic growl. Void-touched Penitents use this to create negotiation zones with hostile creatures. Teleportation in is possible but the living creature is immediately shunted out unharmed.', 'At 6th+, radius increases by 5 feet per slot level above 5th.', ARRAY['druid', 'cleric', 'sovereign', 'warlock']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 30, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Grant Blood-Sentience', 5, 'Transmutation', '8 hours', 'Touch', 'V, S, M (Intact Aether-Core — Flesh, plus a drop of the caster''s own blood)', 'Instantaneous', 'You sit before a beast or plant for eight hours, weaving the Long Narrative — the story of how the Primal Dragons granted speech and thought to the first mortals. At the ritual''s end, press blood to the target''s forehead and speak its new name in the Old Tongue. The target gains Intelligence 10, speaks one language you know (plus Old Tongue if you know it), and develops a personality shaped by experience and your guidance. Plants gain mobility of limbs and human-like senses. Charmed by you for 30 days or until you or companions harm it; afterward decides independently. The highest sacrament of Wild-Blood druids. The Inquisition forbids it — awakened creatures are potential vectors for unsanctioned bloodline spread. A ranger''s awakened wolf has been execution grounds in Citadel territories.', NULL, ARRAY['druid', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 35, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon-Claw Grasp', 5, 'Evocation', '1 action', '120 feet', 'V, S, M (Intact Aether-Core — Storm or Fire)', '1 minute', 'You thrust your arm forward and your sigil flares — a massive spectral draconic claw materializes. Large, translucent, colored by your bloodline. As a bonus action, command: Clenched Fist (melee spell attack, 4d8 force), Grasping Hand (grapple Huge or smaller, using your spellcasting modifier + proficiency), Interposing Hand (interpose between you and a chosen creature — that creature has disadvantage against anyone but the hand, and you gain half cover), or Forceful Hand (push a creature within 5 feet up to 30 feet, Strength save negates). AC 20, HP equal to your maximum. Drops to 0 ends the spell. Leaves faint evaporating aether-prints on everything touched. Storm-blooded Archons add Charisma to damage.', 'At 6th+, damage increases by 2d8 per slot level above 5th.', ARRAY['sorcerer', 'wizard', 'sovereign', 'warlock']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 30, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blight-Vapor', 5, 'Conjuration', '1 action', '120 feet', 'V, S, M (Intact Aether-Core — Void or Flesh)', '10 minutes', 'You spit a black, viscous Old Tongue syllable onto the ground. A roiling 20-foot-radius sphere of green-yellow vapor erupts — the dying breath of a plague-dragon. Heavily obscured. When it appears, creatures inside make a Constitution save: 5d8 poison on failure, half on success. Creatures ending turns inside repeat the save. As a bonus action, you may move the cloud up to 10 feet away from you (it flows along the ground at 3-foot height, sinking into pits and basements). Strong wind disperses in 1 round. Vapor tastes of copper and decay; survivors report nightmares of a rotting dragon''s corpse for weeks. The Inquisition''s Cleanse division specializes in dissipating Blight-Vapor.', 'At 6th+, damage increases by 1d8 per slot level above 5th.', ARRAY['sorcerer', 'wizard', 'warlock', 'sovereign', 'druid']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Consult the Dragon-Gods', 5, 'Divination', '1 minute', '?', 'V, S, M (Intact Aether-Core — Law)', '1 minute', 'You kneel within a consecrated circle (ash or salt), prick your finger, and let three blood drops fall onto your sigil. Your blood steams into smoke that coalesces into the face of a Dragon-God — an ascended ancestor. Ask up to three yes/no questions. The god answers truthfully from its own knowledge: everything witnessed near bloodline shrines, all Old Tongue spoken in the last century, locations of 50%+ purity creatures same-plane. The face is specific — Vaskar the Cinder-Lord, Selendra the Frost-Weaver, Tharaxis the Law-Binder, etc. Voice like grinding stone and crackling flame. Only Ordained are licensed. Afterward, caster''s blood-drops remain as permanent coin-sized sigils visible to anyone 10%+ purity.', NULL, ARRAY['cleric', 'paladin', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], TRUE, FALSE, 35, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Hear the Wild Blood', 5, 'Divination', '1 minute', '?', 'V, S, M (Intact Aether-Core — Flesh or Wild)', 'Instantaneous', 'You sit cross-legged upon the earth, press both palms flat, and enter the Trance of Roots — a meditative state of the oldest Wild-Blood hermits. Your awareness extends into land, plants, and animals within 3 miles. Instantly learn up to three facts: location/strength of natural hazards, presence/number of humanoid settlements, presence of powerful celestial/fiendish/fey/elemental/undead creatures, location of water bodies or mineral deposits, or general ecosystem health. The land speaks in sensory fragments — smoke scent from a distant campfire, heavy footfall vibrations through roots, tainted water taste. Works only outdoors in natural settings. In urban areas, civilization''s weight drowns the voice (spell fails, slot wasted). Rangers and druids who rely on it are flagged as ''potential reclusives'' in Inquisitorial records.', NULL, ARRAY['druid', 'ranger', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], TRUE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Frost Breath', 5, 'Evocation', '1 action', 'Self (60-foot cone)', 'V, S, M (Intact Aether-Core — Frost)', 'Instantaneous', 'You inhale until your lungs burn, then exhale a 60-foot cone of howling crystalline frost — the breath weapon of the Frost-Dragons. Creatures in the cone make a Constitution save: 8d8 cold on failure, half on success. A creature killed freezes solid; its corpse shatters into worthless fragments if struck. Water freezes instantly — puddles become ice slicks (difficult terrain), small ponds freeze over, submerged creatures are restrained in ice (DC 15 Strength to break free). The cone emanates as visible blue-white energy laced with draconic sigils that hang for one round. Frost-blooded Archons may exclude creatures equal to their Charisma modifier. Citadel permits Frost Breath for sanctioned naval engagements only.', 'At 6th+, damage increases by 1d8 per slot level above 5th.', ARRAY['sorcerer', 'wizard', 'druid', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 25, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Call Aether-Lord', 5, 'Conjuration', '1 minute', '90 feet', 'V, S, M (Intact Aether-Core — matching element)', '1 hour', 'You trace the Greater Naming-Rite — a complex interlocking sigil encompassing your bloodline crest and an elemental rune. An Aether-Lord answers: a CR 5 elemental forged from the crystallized blood of a dead Ancient Dragon. Humanoid-draconic form: fire elemental with flame wings, water as a coiling sea-serpent, earth with a sleeping dragon''s mountainous posture, air trailing wispy wing-edges. Friendly to you and companions, acts on its own initiative. Verbally command as a bonus action. If you lose concentration, the Aether-Lord becomes hostile to all (prioritizing you). Dismiss as bonus action. When slain, collapses into elemental particles and leaves a harvestable Pristine Aether-Core (matching element) — the only reliable method to create Pristine Cores.', 'At 6th+, CR increases by 1 per slot level above 5th.', ARRAY['druid', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 30, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Reach Beyond the Veil', 5, 'Divination', '1 minute', '?', 'V, S, M (Intact Aether-Core — Void)', '1 minute', 'You enter a trance and cast your consciousness into the Void Between — the interstitial space where whispers of dead dragons and unborn realities commingle. Mentally contact a demigod, a dragon-sage spirit, or an alien intelligence from beyond. Ask up to five questions; the entity answers with one word (yes, no, maybe, never, irrelevant, unclear). Answers are truthful as far as the entity knows, but the entity may be deceptive, cryptic, or malevolent. On a failed Intelligence save (entity''s save vs. your spell DC), you are overwhelmed: 6d6 psychic damage and stunned for 1d4 rounds as alien draconic consciousness floods your mind. Classified as ''Void Communion'' — a capital offense. Penitents seek it despite the risks.', NULL, ARRAY['warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], TRUE, FALSE, 25, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Curse', 5, 'Necromancy', '1 action', 'Touch', 'V, S, M (Intact Aether-Core — Flesh or Void)', '7 days', 'You touch a creature and seed its bloodstream with a virulent draconic blood-curse. Target makes a Constitution save. On failure, afflicted with a disease of your choice: Blinding Sickness (disadvantage on Wisdom checks/saves, attack rolls), Filth Fever (disadvantage on Strength checks/saves/attacks), Flesh Rot (disadvantage on Charisma checks, vulnerability to all damage), Mindfire (disadvantage on Intelligence checks/saves, behaves as Confused), Seizure (disadvantage on Dexterity checks/saves/attacks, no reactions), or Slimy Doom (bleeds from eyes/mouth — each turn''s end, Constitution save or 3d6 necrotic and one exhaustion level). Manifests in 1d4 hours. Magical healing cannot cure; only Purify the Blood (Greater Restoration) or comparable 5th+ cleansing works. Veins blacken and writhe; blood smells of sulfur and rot. Inquisitors classify this as bloodline terrorism.', 'At 6th+, the disease cannot be cured by any means for the first 24 hours.', ARRAY['druid', 'warlock', 'sovereign', 'cleric']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 30, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether-Weaving', 5, 'Illusion', '1 minute', '30 feet', 'V, S, M (Intact Aether-Core — Wild, plus a fragment of matter from a similar object)', 'Special', 'You pull raw potentiality from the Void Between and weave it into temporary physical form — the Creation-Rite of the first World-Dragons. Create a non-magical object of a seen material: vegetable matter for 24 hours, stone/crystal for 12 hours, precious metals for 1 hour, gems for 10 minutes, or adamantine/mithral for 1 minute. Must fit in a 5-foot cube, single discrete item. When duration expires, the object dissolves into glowing mist. You may make it permanent by consuming a second Aether-Core, but the object becomes a lure — anyone 25%+ purity touching it knows it was Created and can track the caster by residual bloodline resonance for 1 week. The Citadel tightly controls the economy; Aether-Weaving counterfeits are a serious crime.', 'At 6th: 10-ft cube; 7th: 15-ft; 8th: 20-ft; 9th: 25-ft.', ARRAY['wizard', 'sorcerer', 'sovereign', 'artificer', 'warlock']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 30, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Banish the Unclean', 5, 'Abjuration', '1 action', 'Self', 'V, S, M (Intact Aether-Core — Law)', '1 minute', 'You pound your fist twice against your chest — over heart, then sigil-hand — releasing a shockwave of Law-Dragon radiance. Each celestial, elemental, fey, fiend, or undead within 30 feet must make a Charisma save. On failure: Dismissal (sent to home plane for the duration, incapacitated, returns when spell ends) or Binding (disadvantage on attacks, all attacks against it have advantage). 75%+ purity has save advantage; 100% pure are immune. The radiance manifests as blinding silver-white light — witnesses report a massive dragon silhouette superimposed over the caster. Ordained and Oath-Sworn use this to cleanse corrupted shrines. Authorized for active-duty Inquisitors only.', 'At 6th+, radius increases by 10 feet per slot level above 5th.', ARRAY['cleric', 'paladin', 'sovereign', 'warlock']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 35, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Subjugate the Blood', 5, 'Enchantment', '1 action', '60 feet', 'V, S, M (Intact Aether-Core — Law or Flesh)', '1 minute', 'You lock eyes with a humanoid and invoke the Dominance Clause of the Old Blood Compact — the ancient contract binding lesser bloodlines to obey greater ones. Target makes a Wisdom save or be charmed. While charmed, you share a telepathic link (same plane). Use your action to take total control: decide its actions, movement, and features. The target won''t follow obviously suicidal commands. Each time it takes damage, it makes a new Wisdom save. Commands to harm loved ones, betray oaths, or reveal bloodline secrets grant advantage. Target''s eyes glow with your bloodline color. The Inquisition uses this for ''enhanced interrogation.'' Sovereigns use it for the same purpose, less euphemistically.', 'At 6th: 10 min; 7th: 1 hour; 8th: 8 hours (no concentration, damage no longer triggers saves).', ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'sovereign', 'cleric']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 35, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Walk the Blood-Dream', 5, 'Illusion', '1 minute', 'Special', 'V, S, M (Intact Aether-Core — Void, plus a drop of the caster''s blood)', '8 hours', 'You lie down and bleed a drop onto your forehead. Your body enters a deathlike sleep as your consciousness enters the Blood-Dream — the shared dreamscape of the sleeping Dragon-Gods. Shape the dream of a creature you know by name, delivered when they next sleep. Design a message of any length in any form (conversation, landscape, memory, nightmare, prophecy). Vivid and unforgettable. If the target is awake when delivered, you appear as a spectral translucent form (visible only to them), speak up to ten words, and vanish. You may instead send a nightmare: the dream is terrifying, the target gains no benefit from that long rest, and takes 3d6 psychic upon waking. Sending a nightmare leaves a bloodline trace — any 50%+ purity caster examining the target within 24 hours identifies you. Penitents and Sovereigns exploit the Blood-Dream for espionage.', 'At 6th+, target one additional creature per slot level above 5th.', ARRAY['bard', 'warlock', 'wizard', 'sovereign', 'druid']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragonfire Pillar', 5, 'Evocation', '1 action', '60 feet', 'V, S, M (Intact Aether-Core — Fire)', 'Instantaneous', 'You thrust your sigil-hand toward the sky and roar the Fire-Dragon''s name for ''wrath.'' A vertical column of divine draconic flame roars down from the heavens — a 10-foot-radius, 40-foot-high cylinder. Creatures in the area make a Dexterity save: 4d6 fire + 4d6 radiant on failure, half on success. Radiant damage (the Dragon-God''s judgment) ignores fire resistance. Void-blooded and undead take an additional 2d6 radiant. Ground is seared black and radiates warmth for 1 hour; plants die instantly. The pillar is visible for miles as blazing gold-white light with a thunderous sky-echo. Ordained call this ''the Finger of the Gods.'' The Inquisition uses it for public execution of captured Sovereigns — the spectacle sends a message.', 'At 6th+, fire or radiant damage (caster''s choice) increases by 1d6 per slot level above 5th.', ARRAY['cleric', 'paladin', 'sovereign', 'warlock']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 30, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Oath Binding', 5, 'Enchantment', '1 minute', '60 feet', 'V, S, M (Intact Aether-Core — Law, plus a written oath signed in the target''s blood)', '30 days', 'You present a written command — a geas — to a creature within range. The target must hear, understand, and be able to perform it. Target makes a Wisdom save. On failure, magically compelled to follow the command to the best of its ability. If the target willingly disobeys, it takes 5d10 psychic damage once per day as its own bloodline rebels (blood literally burns). Cannot kill but can reduce to 1 HP. Commands may span the full duration (guard this vault, never speak of what you saw). The target''s bloodline sigil manifests visibly on their dominant hand for the duration — a glowing Old Tongue brand reading the geas. Removing requires Purify the Blood (Greater Restoration) or Wish-level effect. The Inquisition uses this to enforce parole for captured casters. Prisoners call it slavery.', 'At 7th: 1 year. At 9th: permanent until dispelled by 9th-level effect.', ARRAY['bard', 'cleric', 'druid', 'wizard', 'sovereign', 'paladin']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 35, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Purify the Blood', 5, 'Abjuration', '1 action', 'Touch', 'V, S, M (Intact Aether-Core — Law or Flesh, plus diamond dust worth 100 GC which the spell consumes)', 'Instantaneous', 'You lay both hands upon a creature and trace the Purification Sigil — the spiral crest said to be the original bloodline pattern before the Dragon-Gods diverged. You flood the target''s bloodstream with pure unfiltered aether, expelling magical impurities. End one of: blinded, charmed, deafened, frightened, paralyzed, petrified, poisoned, or stunned. Reduce exhaustion by one level. End any effect reducing hit point maximum. End one disease or curse (including Blood-Curse and cursed item attunement). The target''s blood visibly clears — blackened veins redden, sluggish blood quickens. Veins glow warm gold for one minute; Inquisitors within 100 feet can detect the residual purification aura. Diamond dust represents the Law-Dragon''s ''perfect crystalline blood.'' Unlicensed healing is a regulatory violation; healing fugitive heretics makes the healer an accessory.', NULL, ARRAY['bard', 'cleric', 'druid', 'paladin', 'ranger', 'sovereign', 'artificer', 'warlock']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 30, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Consecrate Blood-Ground', 5, 'Evocation', '24 hours', 'Touch', 'V, S, M (Intact Aether-Core — Law, plus herbs, oils, and incense worth 1,000 GC — consumed)', 'Until dispelled', 'You walk a consecration zone''s perimeter for 24 hours — up to 60-foot radius — tracing your sigil, burning incense, and chanting the Hallowing Rite of the Law-Dragons. The area becomes sanctified ground. Choose one extra effect: Courage (no frightened), Darkness (dim light, no darkvision through), Daylight (bright light, no magical darkness), Energy Protection (resist one of acid/cold/fire/lightning/thunder), Energy Vulnerability (designate creatures gain vulnerability to one), Everlasting Rest (bodies cannot become undead), Extradimensional Interference (no planar travel in/out), Fear (designated creatures frightened), Silence (no sound created or through barrier), Tongues (all understand/speak one language), or Creature Exclusion (celestials/elementals/fey/fiends cannot enter, disadvantage on attacks against those within). The boundary glows with faint draconic runes. Mandated on all Citadel buildings. Unauthorized consecration = territorial claim — rebellion.', NULL, ARRAY['cleric', 'paladin', 'sovereign', 'warlock']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 35, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Paralyze Aberrant Blood', 5, 'Enchantment', '1 action', '90 feet', 'V, S, M (Intact Aether-Core — Law)', '1 minute', 'You intone the Stillness Decree — a commanding phrase invoking the Law-Dragon''s authority over all flesh, blood, and motion. Target one creature you can see; it must succeed on a Wisdom save or be paralyzed. The paralysis is not muscular but a bloodline command: the target''s own draconic essence is ordered to halt. At each turn''s end, the target may repeat the save. Its eyes remain mobile; it is fully conscious, trapped in an unresponsive body. 75%+ purity has advantage on the initial save; 90%+ immune. If the target has Unchained Blood (Freedom of Movement) active, that spell is suppressed for one round rather than automatically ending the paralysis. The Inquisition trains ''Binder'' squads to coordinate this against high-value Sovereign targets.', 'At 6th+, target one additional creature per slot level above 5th.', ARRAY['bard', 'cleric', 'sorcerer', 'warlock', 'wizard', 'sovereign', 'druid']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 30, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Scarab-Swarm', 5, 'Conjuration', '1 action', '300 feet', 'V, S, M (Intact Aether-Core — Flesh)', '10 minutes', 'You scatter dried insect husks and whisper the Swarming Verse — calling the blood-drinking scarabs of the desert dragon-graves. A 20-foot-radius sphere of biting, stinging locusts erupts at a chosen point — lightly obscured, difficult terrain. When appearing and at the start of each of your turns, creatures inside make a Constitution save: 4d10 piercing on failure, half on success. As a bonus action, move the sphere up to 30 feet. The scarabs are iridescent black-gold, their carapaces etched with microscopic draconic sigils. They consume flesh, ignore bone. Creatures reduced to 0 HP are skeletonized in 1d4 rounds. A physical manifestation of the Hunger of the Buried — an ancient curse on the grave of the last Flesh-Dragon. Wild-Blood druids may redirect the swarm to avoid certain creatures (DC 18 Wisdom check as action).', 'At 6th+, damage increases by 1d10 per slot level above 5th.', ARRAY['druid', 'sovereign', 'warlock']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Read the Blood-Annals', 5, 'Divination', '10 minutes', 'Self', 'V, S, M (Intact Aether-Core — Law, plus incense worth 250 GC — consumed)', 'Instantaneous', 'You burn consecrated incense in a brass brazier and inhale the smoke. Your eyes roll back white as your consciousness taps into the Blood-Annals — the collective memory of all dragon-blooded beings, stored in the aether itself. Name a person, place, or object of legendary importance. The Annals return a summary of significant lore: tales, songs, histories, and known secrets. Information is always accurate but limited to what has been witnessed or preserved by the collective blood-memory. For example: a lost Sovereign blade''s forging (vision-snippet), its last wielder, and the dying witness''s final memory of its location — but not what happened after all witnesses died. Caster is dazed for 1d4 minutes afterward, with faint golden Old Tongue glyphs slowly fading from their skin. Ordained archivists are licensed. Extracted knowledge is Citadel property — sharing without authorization is espionage.', NULL, ARRAY['bard', 'cleric', 'wizard', 'sovereign', 'warlock']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 30, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sovereign Mending', 5, 'Evocation', '1 action', '60 feet', 'V, S, M (Intact Aether-Core — Flesh)', 'Instantaneous', 'You raise your sigil-hand, palm out, and release a wave of liquid amber light — the Vital Surge, a draconic healing technique flooding the bloodstream with regenerative aether. Up to six creatures you can see within range each regain hit points equal to 3d8 + your spellcasting ability modifier. No effect on undead or constructs. Healing manifests as a warm golden pulse from the chest outward — flesh knits, bleeding stops, small wounds seal. Healed creatures'' blood glows faintly for one round; Inquisitor forensic teams can detect this up to 1 hour later. Street-level healers using this without a license are fined; repeat offenders branded. Cannot heal a creature that has taken Aether Burn damage in the last round — residual aetheric interference blocks the Vital Surge.', 'At 6th+, healing increases by 1d8 per slot level above 5th.', ARRAY['bard', 'cleric', 'druid', 'sovereign', 'paladin']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Double', 5, 'Illusion', '1 action', 'Self', 'V, S, M (Intact Aether-Core — Void)', '1 hour', 'You bleed a single drop onto your sigil and become invisible while an illusory double appears in your space, behaving as you direct. It looks, sounds, and smells exactly like you, mimicking movements and speech perfectly. As a bonus action, mentally move the double up to twice your speed and command it to gesture, speak, or act. You may also move yourself separately. Perceive through the double''s senses as a bonus action. Creatures seeing through the illusion perceive it as a translucent phantom overlaying your invisible form. The double has your AC but no HP — taking damage flickers it, revealing the illusion. Spell ends if you attack or cast a spell affecting an enemy. A favored spell of Shadow-Blood rogues and Penitents. High-security Citadel facilities employ ''Blood-Sniffers'' — trained drakes that track by scent, which the double doesn''t perfectly replicate (DC 18 Perception to notice lack of body odor).', 'At 6th: 8 hours; 7th+: 24 hours.', ARRAY['bard', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Reshape the Blood-Mind', 5, 'Enchantment', '1 action', '30 feet', 'V, S, M (Intact Aether-Core — Void or Law)', '1 minute', 'You fix a creature with an unblinking stare and recite a new memory — a draconic weaving technique that rewrites the blood-record within a creature''s mind. The target must see and hear you, and make a Wisdom save. On failure, reshape its memory of an event within the last 24 hours lasting up to 10 minutes. You may: erase the memory, alter perceived details, or implant a fabricated memory. The new memory must be logically consistent. If it contradicts deeply held beliefs (e.g., a loyal paladin remembering betrayal), the target has advantage. Can be ended early by Purify the Blood (Greater Restoration) or Remove Curse. After casting, the caster''s own eyes flicker with the memory briefly — DC 20 Insight to spot. The Inquisition uses this for ''witness correction.'' Penitents and Sovereigns use it against the Inquisition.', 'At 6th: event up to 7 days ago; 7th: 30 days; 8th: 1 year; 9th: any time.', ARRAY['bard', 'wizard', 'sovereign', 'warlock', 'cleric']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 30, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Part the Stone', 5, 'Transmutation', '1 action', '30 feet', 'V, S, M (Intact Aether-Core — Flesh or Wild)', '1 hour', 'You press your sigil-hand against a stone surface and exhale a grinding syllable — the Earth-Dragon''s command to ''yield.'' A passage up to 5 feet wide, 8 feet tall, and 20 feet deep opens through the stone, smooth-walled and slightly warm as if melted and re-solidified. May be straight or angled. The opening closes at the spell''s end; any creature or object still inside is shunted to the nearest unoccupied space and takes 6d6 force damage. Multiple castings extend the passage. Stone edges glow faint amber. Used extensively in Aether-Core mining — licensed Aether-Smiths may cast for excavation. Unauthorized use to breach secure facilities carries a mandatory death sentence. Inquisition prison walls are reinforced with aether-dampening alloy specifically to block this.', 'At 6th+, depth increases by 20 feet per slot level above 5th.', ARRAY['druid', 'wizard', 'sovereign', 'artificer']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Bind the Outsider', 5, 'Abjuration', '1 hour', '60 feet', 'V, S, M (Intact Aether-Core — Law, plus a binding circle of powdered dragon-bone worth 1,000 GC)', '24 hours', 'You draw a binding circle using powdered dragon-bone and your own blood, then intone the sixteen-stanza Binding Verses of the Law-Dragon''s Compact governing extraplanar relations. Target one celestial, elemental, fey, or fiend within range. Charisma save or bound to serve for the duration. The creature must follow your verbal commands: guard a location, accompany you, fight alongside, or perform a specific task. If hostile, it has advantage. If you or your companions harm the creature, binding breaks. Suicidal commands also break it, though the creature may obey out of fear. The bound creature bears your bloodline sigil on its forehead. When the spell ends, the creature knows your identity, purity level, and the binding location — it may seek revenge. The Citadel strictly licenses planar binding. Unsanctioned celestial binding is the only capital crime against the gods themselves.', 'At 6th: 10 days; 7th: 30 days; 8th: 180 days; 9th: 1 year and 1 day.', ARRAY['cleric', 'druid', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 35, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Recall the Blood', 5, 'Necromancy', '1 hour', 'Touch', 'V, S, M (Intact Aether-Core — Flesh, plus a diamond worth 500 GC — consumed)', 'Instantaneous', 'You kneel beside a dead humanoid who has been dead no more than 10 days, place both hands upon the corpse, and recite the Recall Verse — a necromantic passage in the Old Tongue that calls a departed bloodline back to its vessel. The soul must be free and willing. The creature returns to life with 1 hit point and is stable. This spell closes mortal wounds but does not restore missing body parts. The revived creature suffers a -4 penalty to all attack rolls, saves, and ability checks, reduced by 1 after each long rest. The creature''s bloodline sigil appears faintly glowing on their chest for 24 hours; anyone 25%+ purity can see it. The Inquisition requires a death certificate and Citadel license for this spell. Unauthorized resurrection is ''bloodline reanimation'' — a capital crime. The diamond represents crystallized life-force and is consumed. The caster permanently loses 5% purity for 1 week — the Dragon-Gods exact a toll for returning what was taken.', NULL, ARRAY['cleric', 'sovereign', 'druid']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 40, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Rebirth', 5, 'Transmutation', '1 hour', 'Touch', 'V, S, M (Intact Aether-Core — Flesh, plus rare oils and unguents worth 1,000 GC — consumed)', 'Instantaneous', 'You anoint a dead humanoid''s body or a fragment thereof with rare oils and intone the Rebirth Hymn — an ancient song of the Primal Dragons who first shaped mortal forms from clay and blood. The soul must be free and willing. A new adult body is formed for the soul from the blood-essence within the oils; the creature is reincarnated into a random humanoid form (DM rolls on a table or chooses). The new body retains the original''s memories, personality, and class levels, but racial traits change to match the new form. The creature loses all old racial traits and gains new ones. The transformation is spectacular: the oils ignite and blaze with rainbow draconic light, a cocoon of scales envelops the body-fragment, and the reborn creature tears free gasping. The reborn creature has disadvantage on all rolls for 1 day as their blood and new form reconcile. Wild-Blood druids perform this as a sacrament of nature''s cycle. The Inquisition considers it ''unsanctioned bloodline mutation'' and prosecutes aggressively — the new body may alter the creature''s purity threshold.', NULL, ARRAY['druid', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 35, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Eye of the Dragon', 5, 'Divination', '10 minutes', 'Self', 'V, S, M (Intact Aether-Core — Wild or Void, plus a focus worth 1,000 GC — bloodline mirror, crystal orb, or silver pool)', '10 minutes', 'You gaze into a reflective surface — a bloodline mirror, crystal orb, or silvered pool — and unfocus your eyes, letting your draconic sight extend across space. You can see and hear a particular creature you choose that is on the same plane of existence. The target must make a Wisdom save (unaware of the scrying unless it succeeds, in which case it senses a draconic presence watching). The save is modified by your knowledge of and connection to the target: +5 if you have never met them, +0 if familiar, -5 if you possess a body part, lock of hair, blood sample, or personal possession. The dragon''s eye manifests as a faintly glowing overlay on the reflective surface; anyone looking into the surface sees a slit-pupiled draconic eye staring back. The Inquisition operates a ''Scrying Bureau'' that monitors all known reflective pools in Citadel territory. Sovereigns counter-scry using Sealed Blood-Sanctums.', 'At 6th+: duration 1 hour; 7th+: sensor moves with the target.', ARRAY['bard', 'cleric', 'druid', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 30, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Mask the Blood', 5, 'Illusion', '1 action', '30 feet', 'V, S, M (Intact Aether-Core — Void or Law)', '8 hours', 'You trace a layered web of illusion over up to ten creatures you can see, overwriting their appearances with draconic glamour. Each target''s appearance — including clothing, armor, weapons, and equipment — can be altered as you choose to look like any humanoid of the same basic arrangement of limbs. The illusion includes tactile feedback (a disguised guard uniform feels like rough wool), but physical properties don''t change (a staff disguised as a sword still hits like a staff). A creature physically inspecting an illusion discovers it (Investigation check vs. your spell DC). The illusion masks bloodline signature readings at ranges beyond touch; an Inquisitor checking purity must physically touch the target to get an accurate reading. Sovereigns and Penitents use this to move through Citadel cities undetected. The Inquisition counters with ''Aether-Hounds'' — drakes trained to identify people by the unique resonance of their footsteps.', 'At 6th+, duration 24 hours; target one additional creature per slot level above 5th.', ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Will Over Flesh', 5, 'Transmutation', '1 action', '60 feet', 'V, S, M (Intact Aether-Core — Storm or Law)', '10 minutes', 'You fix a creature or object with an unwavering stare, and your bloodline sigil projects from your eyes onto the target — a visible beam of draconic will. You gain the ability to move or manipulate the target with your mind. As an action, you may: Move (shift a Huge or smaller creature or object up to 30 feet in any direction, including vertically), Manipulate (exert fine control — open a door, pour a vial, turn a key, pull a lever — as if using an invisible hand), or Hurl (violently throw a held creature or object up to 90 feet, dealing 1d6 bludgeoning per 10 feet traveled to anything it strikes). You may also contest a creature''s physical action (Strength check vs. your spellcasting ability). The target visibly strains against invisible draconic force; creatures with 50%+ purity feel the ''taste'' of the caster''s bloodline — they may make a DC 20 Intelligence check to identify you later.', 'At 6th+, you may target one additional creature or object per slot level above 5th, commanding them simultaneously.', ARRAY['sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 30, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Kin Communion', 5, 'Divination', '1 action', '30 feet', 'V, S, M (Intact Aether-Core — Flesh or Law)', '1 hour', 'You prick your own finger and the fingers of up to eight willing creatures, mingling a drop of blood from each on your sigil. A telepathic bond forms between all participants. Creatures linked in this way can communicate telepathically with one another across any distance on the same plane. The bond bypasses language — thoughts, images, and emotions translate instinctively through the shared blood-drop resonance. The bond does not grant access to deeper memories or secrets unless the creature intentionally shares them. Each participant has a faint awareness of the others'' emotional states and whether they are in danger. A creature linked this way whose bloodline differs from yours by more than one element bracket has disadvantage on Charisma checks made through the bond. The Inquisition monitors for large-scale Blood-Kin networks; they consider it conspiracy infrastructure.', 'At 6th+, the bond works across planes if both creatures are not on consecrated ground.', ARRAY['bard', 'wizard', 'sovereign', 'cleric', 'druid']::text[], ARRAY['solis-grave', 'srd']::text[], TRUE, FALSE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sigil-Gate', 5, 'Conjuration', '1 minute', '10 feet', 'V, S, M (Intact Aether-Core — Void, plus rare chalks and inks infused with dragon-scale dust worth 50 GC — consumed)', '1 round', 'You draw a 10-foot-diameter circle on the ground using dragon-scale chalk, tracing your bloodline sigil at the cardinal points. The circle ignites with pale aether-light, and you designate a permanent Sigil-Gate (another teleportation circle whose sigil sequence you have studied). The portal opens as a shimmering oval of translucent energy showing the destination on the other side. Any creature that enters the circle is instantly transported to the destination. The portal remains open until the end of your next turn. You may step through yourself before it closes. The destination circle must be on the same plane. Major Citadel cities have public Sigil-Gate circles (with usage fees and identity logging). Sovereign resistance networks maintain hidden circles in Sealed Blood-Sanctums. The Inquisition has a ''Gate-Cracking'' division that traces portal usage signatures to locate illegal circles.', 'At 6th+, the portal remains open for 1 minute instead of 1 round.', ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'sovereign', 'cleric']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, FALSE, 30, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Root-Walk', 5, 'Conjuration', '1 action', 'Self', 'V, S, M (Intact Aether-Core — Flesh or Wild)', '1 minute', 'You step into a tree — and through it. Your body merges with the trunk, dissolving into a swirl of amber light and the scent of sap and old bark. You may instantly emerge from a second tree of the same type within 500 feet, stepping out of the trunk as if walking through a door. Once in a tree, you may re-enter the same tree or any other of the same type within 500 feet as a bonus action on subsequent turns. You must exit before the spell ends or you are shunted to the nearest unoccupied space and take 6d6 force damage. While in a tree, you perceive the world dimly through the tree''s bark — you can hear muffled sounds and feel vibrations (tremorsense 30 feet). The trees used glow faint amber for 1 minute afterward, and anyone 25%+ purity touching one experiences a brief vision of the caster''s silhouette passing through. A favored escape spell of Strider rangers and Wild-Blood druids. The Inquisition has been known to burn entire groves to flush out Root-Walkers.', 'At 6th+, range between trees increases to 1,000 feet; at 7th+: 1 mile.', ARRAY['druid', 'ranger', 'sovereign']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aegis Barrier', 5, 'Evocation', '1 action', '120 feet', 'V, S, M (Intact Aether-Core — Law)', '10 minutes', 'You thrust both palms forward and an invisible wall of pure draconic force springs into existence at a point you choose. The wall can be a flat plane up to ten 10-foot-by-10-foot panels (arranged contiguously in any shape) or a hemispherical dome or sphere of 10-foot radius. It is invisible, immobile, and indestructible — nothing can physically pass through. A creature fully enclosed by the wall must make a Charisma save or be trapped. The wall extends into the Ethereal Plane, blocking ethereal travel. Disintegrate destroys one 10-foot panel instantly. The wall hums faintly; creatures touching it feel a smooth, warm, glass-like surface that tingles with contained draconic authority. Archon Casters consider Aegis Barrier the pinnacle of defensive evocation. The Inquisition uses dome-configuration barriers to contain captured Sovereigns during transport.', 'At 6th+, you may create ten additional panels per slot level above 5th.', ARRAY['wizard', 'sovereign', 'sorcerer', 'artificer']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 30, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Stone-Rampart', 5, 'Evocation', '1 action', '120 feet', 'V, S, M (Intact Aether-Core — Flesh or Wild)', '10 minutes', 'You slam your sigil-hand against the ground and a wall of fused, non-magical stone erupts at a point you choose. The wall is 6 inches thick and composed of ten 10-by-10-foot panels contiguously arranged. Each panel has AC 15 and 30 HP; reducing a panel to 0 HP destroys it and the wall collapses in that section. If the wall cuts through a creature''s space when it appears, the creature is pushed to one side (your choice) and must make a Dexterity save or take 5d8 bludgeoning. The stone is permanent if concentrated on for the full duration; otherwise it crumbles when the spell ends. The wall''s surface is rough-hewn and warm to the touch, bearing faint impressions of draconic scales. Aether-Smiths use this spell to create instant fortifications. The Inquisition uses it for crowd control during heretic uprisings.', 'At 6th+, create two additional panels per slot level above 5th.', ARRAY['druid', 'sorcerer', 'wizard', 'sovereign', 'artificer']::text[], ARRAY['solis-grave', 'srd']::text[], FALSE, TRUE, 25, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Hemoplague Curse', 5, 'Necromancy', '1 action', '60 feet', 'V, S, M (Intact Aether-Core — Flesh, and the caster takes 5d8 necrotic self-damage)', '1 minute', 'The ultimate Blood Curse of the Crimson Oath, taught only to those who have survived the Hemocraft Trials and faced a dragon alone. You slash deeply into your own arm and fling a spray of blood into the air — it ignites into a crimson mist that seeks a target within range. The target must make a Constitution saving throw. On failure, the target''s own blood turns against them: at the start of each of their turns, they take 4d6 necrotic damage (bypassing resistance and immunity — this is soul-attacking blood magic). Additionally, whenever the target takes damage from any source, the damage is increased by 2d6 necrotic as their wounds weep and refuse to clot. The curse manifests as weeping crimson rivulets running from the target''s eyes, mouth, and any open wounds. A creature reduced to 0 HP by Hemoplague Curse does not make death saves — they are dead, their blood having boiled away from within. The caster''s self-damage cannot be reduced. Casting this curse is visible for 300 feet as a pillar of crimson light. It is the signature of a Crimson Oath on the warpath — the Inquisition prioritizes Hemoplague casters above all other threats.', NULL, ARRAY['blood_hunter']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, TRUE, 35, 'Severe', 3, 'Crimson Oath') ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Masterwork Awakening', 5, 'Transmutation', '10 minutes', 'Touch', 'V, S, M (Intact Aether-Core — Storm, plus a non-magical weapon or armor worth at least 500 GC, plus aether-resonant oils worth 300 GC — consumed)', 'Until dispelled or destroyed', 'The pinnacle of Aether-Smith artifice — the Masterwork ritual. You spend 10 minutes inscribing draconic runes and embedding aether-resonant oils into a non-magical weapon or suit of armor. The item awakens as a permanent +1 magical item. The weapon gains a faint, visible aether-glow when wielded, and its strikes leave thin contrails of blue-white light. You may choose one additional property: Adaptive (as a bonus action, the weapon changes damage type between slashing, piercing, or bludgeoning), Resonant (the weapon stores one spell of 1st level or lower cast into it; the wielder may release it as a bonus action on a hit), or Sentinel (the armor grants +5 to initiative and the wearer cannot be surprised). The item''s draconic runes glow faintly when its properties activate. An Aether-Smith may maintain only one Masterwork at a time; casting this spell again severs the bond with the previous Masterwork (reverting it to mundane). The item is recognizable as Aether-Smith work by its distinctive blue-white glow; the Inquisition requires all Masterwork items to be registered and taxed.', 'When cast at 7th level, the item becomes +2; at 9th level, +3. Slot must still be 5th — the higher slot is used for the casting.', ARRAY['artificer']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, FALSE, 35, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sovereign''s Decree', 5, 'Enchantment', '1 action', '60 feet', 'V, S, M (Intact Aether-Core — Law)', '1 minute', 'The signature spell of the Dragon-Heir — a Sovereign''s ultimate assertion of bloodline dominance. You raise your sigil-hand and speak a Decree in the Old Tongue, your voice layered with the full harmonic resonance of your draconic ancestry. All creatures of your choice within range that can hear you must make a Charisma saving throw. On failure, they are compelled by the Decree. You may issue one of the following Decrees: Kneel (targets fall prone and cannot stand or take reactions for the duration — a new save at the end of each turn), Flee (targets must use their action to Dash away from you by the safest route each turn), Silence (targets cannot speak, cast spells with verbal components, or use breath weapons), Yield (targets drop everything held and cannot pick up items or make attacks), or Serve (targets obey a single command of up to five words, which they carry out to the best of their ability on their next turn). Creatures with higher purity than the caster have advantage. Creatures with 75%+ purity are immune to all Decrees except Silence. At the end of each of their turns, affected creatures may repeat the save. The Decree manifests as visible ripples of golden light emanating from the caster in expanding rings, accompanied by a subsonic rumble that shakes loose objects. This spell is the mark of a true Sovereign — the Inquisition places a 50,000 GC bounty on anyone merely suspected of knowing it.', 'When cast at 7th level or higher, 75%+ purity creatures lose immunity and save normally.', ARRAY['sovereign', 'paladin']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, TRUE, 50, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Oath of Burning Judgment', 5, 'Evocation', '1 action', 'Self (30-foot radius)', 'V, S, M (Intact Aether-Core — Fire or Law)', '1 minute', 'The ultimate oath-spell of the Flame-Order Paladins — those who channel the wrath of the Cinder-Dragons into holy fire. You kneel, plant your weapon point-down into the ground, and speak the Judgment Vow. Your body erupts in golden draconic flame that does not harm you or your allies. For the duration, you gain the following: your melee attacks deal an additional 2d8 fire damage and 1d8 radiant damage; any creature that hits you with a melee attack takes 2d8 fire damage; you shed bright light 60 feet and dim light 60 feet; and as a bonus action, you may designate one creature you can see as Marked for Judgment — the first time you hit that creature each turn, it must make a Wisdom save or be frightened until the end of your next turn. Your weapon leaves contrails of golden flame. The ground within 30 feet of you is bathed in warm, flickering light that resembles dragonfire. This spell is the visible symbol of a Flame-Order Paladin on crusade — friend and foe alike know what it means. Maintaining the Oath for more than 5 minutes begins to visibly scar the caster with golden vein-patterns (a mark of honor among Flame-Order faithful and a dead giveaway to Inquisitors).', 'When cast at 7th level, the aura radius increases to 60 feet and frightened creatures must also make a Strength save or be pushed 10 feet away from you.', ARRAY['paladin']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, TRUE, 40, 'Severe', 3, 'Flame-Order') ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Cinder-Scale Barrier', 6, 'Evocation', '1 action', '90 feet', 'V, S, M (Pristine Aether-Core — fire element)', 'Concentration, up to 10 minutes', 'You sweep your bloodline sigil through the air, and a curtain of spinning draconic scales forged from molten cinder erupts into existence. The wall appears in a straight line up to 100 feet long, 20 feet high, and 5 feet thick, or a ringed wall up to 60 feet in diameter. When a creature enters or starts its turn in the wall''s space, it must make a Dexterity saving throw. On a failed save, it takes 6d10 fire damage as the superheated scales tear through flesh; on a successful save, it takes half damage. If the wall appears in a creature''s space, that creature makes the save immediately. The wall provides three-quarters cover. Flammable objects within 5 feet of the wall''s path catch fire instantly — the scales shed embers that hunger for kindling. The barrier''s heat is visible as a shimmering orange haze, and the grinding of the scales produces a sound like a thousand swords being sharpened at once.', 'When you cast this spell using a spell slot of 7th level or higher, the damage increases by 1d10 for each slot level above 6th.', ARRAY['cleric']::text[], ARRAY['solis-grave', 'srd-ref', 'Blade Barrier']::text[], FALSE, TRUE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Storm-Blood Cascade', 6, 'Evocation', '1 action', '150 feet', 'V, S, M (Pristine Aether-Core — storm element)', 'Instantaneous', 'Your bloodline pulses with the fury of a storm dragon, and a bolt of blue-white lightning erupts from your outstretched hand toward a creature you can see. The target must make a Dexterity saving throw. On a failure, it takes 10d8 lightning damage as the draconic current sears through its veins, leaving branching scars like lightning-struck glass. On a success, it takes half. The lightning then arcs to up to three additional creatures of your choice within 30 feet of the first, each of which must also make the save, suffering the same fate. The cascade bears the unmistakable crack of the Old Tongue — any creature familiar with draconic lore recognizes the syllables of the Storm-Wyrm bloodline embedded in the thunder.', 'When you cast this spell using a spell slot of 7th level or higher, one additional bolt leaps from each target to a new creature for each slot level above 6th.', ARRAY['sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Chain Lightning']::text[], FALSE, FALSE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Void-Blood Siphon', 6, 'Necromancy', '1 action', '150 feet', 'V, S, M (Pristine Aether-Core — void element)', 'Instantaneous', 'You utter syllables of the Void-Wyrm bloodline, and a sphere of absolute darkness blossoms from a point you choose within range before collapsing inward with a soundless shriek. Each creature in a 60-foot-radius sphere must make a Constitution saving throw. A creature takes 8d6 necrotic damage on a failed save as the void hungrily drinks its life force, the warmth draining from its body as frost forms on its eyelids; on a successful save, it takes half. A creature killed by this spell leaves no mark on its flesh — it simply stops. The soul is not consumed, but witnesses swear the body looks... emptied. Plants in the area wither and blacken. The spell leaves a lingering chill in the air for 1 minute, during which time any healing received in the area is halved.', 'When you cast this spell using a spell slot of 7th level or higher, the damage increases by 2d6 for each slot level above 6th.', ARRAY['sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Circle of Death']::text[], FALSE, FALSE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Forethought Ward', 6, 'Evocation', '10 minutes', 'Self', 'V, S, M (Pristine Aether-Core — any element, and an item of personal significance to the caster)', '10 days', 'You inscribe a contingency sigil upon your own bloodline, tying a protective or reactive spell to a trigger condition you specify. Choose a spell of 5th level or lower that you can cast, that has a casting time of 1 action, and that can target you. Describe a circumstance — "when I fall below half health," "when I am struck by silver," "if an Inquisitor enters my presence" — and the ward will cast that spell on you instantly when the condition is met. The ward glows faintly beneath your skin, visible only to those who can perceive aether. You may have only one Forethought Ward active at a time. The spell woven into the ward is cast at its base level and consumes its own Aether-Core stored during the ritual. The ancients called this the Dragon''s Foresight — a sliver of the predictive instinct possessed by the Great Wyrms.', NULL, ARRAY['wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Contingency']::text[], FALSE, FALSE, 50, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Rise Dredged', 6, 'Necromancy', '1 minute', '10 feet', 'V, S, M (Pristine Aether-Core — void or flesh element, and three intact corpses)', 'Instantaneous', 'You speak the forbidden words of the Flesh-Wyrm bloodline over three corpses, channeling your aether into the dead flesh until it twitches, then rises. Up to three Medium or Small humanoid corpses within range animate as dread dredged — the Solis-Grave equivalent of ghouls, their flesh pale and slick as if pulled from the Sump canals. They obey your verbal commands for 24 hours, after which their false life expires and the corpses collapse into black sludge. The dredged retain a fragment of the caster''s bloodline sigil burned into their foreheads — a mark that an Inquisitor would recognize instantly. Maintaining control requires a bonus action each round to issue a command; without one, they defend themselves against the nearest threat. You may assert or reassert control over up to three dredged created by this casting; existing dredged beyond this limit are released. This spell is punishable by Pyre execution in all six Sovereign Houses.', 'When you cast this spell using a spell slot of 7th level, you create four dread dredged. At 8th: five. At 9th: six.', ARRAY['cleric', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Create Undead']::text[], FALSE, FALSE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wyrm''s Unmaking', 6, 'Transmutation', '1 action', '60 feet', 'V, S, M (Pristine Aether-Core — void element)', 'Instantaneous', 'You trace the Unmaking Sigil — the only bloodline crest shared by every dragon bloodline, said to be the mark the First Wyrm used to erase its mistakes from creation — and a thin beam of pale green light springs from your finger to a target you can see. The target must make a Dexterity saving throw. On a failed save, it takes 10d6 + 40 force damage as the Old Tongue commands its form to forget itself. If this damage reduces the target to 0 hit points, it is entirely unmade: its body, its possessions, and any nonmagical objects it carries are reduced to fine gray ash. Nothing remains but a faint scorch mark and the smell of ozone. A creature unmade by this spell can only be restored to life by a Rebirth of the Bloodline spell or an equivalent 7th-level or greater restoration. This spell disintegrates nonmagical matter instantly and can destroy a 10-foot cube of any nonmagical object. Magical objects are unaffected. The beam is silent — witnesses describe a moment of absolute stillness before the target simply ceases to be.', 'When you cast this spell using a spell slot of 7th level or higher, the damage increases by 3d6 for each slot level above 6th.', ARRAY['sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Disintegrate']::text[], FALSE, FALSE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Gaze of the Dragon-Lord', 6, 'Necromancy', '1 action', 'Self', 'V, S, M (Pristine Aether-Core — any element matching your bloodline)', 'Concentration, up to 1 minute', 'Your eyes ignite with the terrible authority of a sovereign wyrm, glowing with your bloodline''s elemental hue. For the duration, your gaze becomes a weapon. As an action on each of your turns, you can fix your stare upon a creature within 60 feet and invoke one of three aspects: the Sleepless Terror (target must succeed on a Wisdom save or be frightened of you until the spell ends), the Sickness Unto Death (target must succeed on a Constitution save or be poisoned and take 4d8 psychic damage at the start of each of its turns until it saves), or the Wyrm''s Slumber (target must succeed on a Wisdom save or fall unconscious until damaged, the spell ends, or an action is used to shake it awake). A creature that successfully saves against your gaze is immune to that aspect for 24 hours. The gaze costs no action to maintain — your eyes simply burn until the spell ends. Those who meet your stare swear they see the outline of wings behind you.', NULL, ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Eyebite']::text[], FALSE, TRUE, 50, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Call the Wild-Blood', 6, 'Conjuration', '1 minute', '90 feet', 'V, S, M (Pristine Aether-Core — flesh element)', 'Concentration, up to 1 hour', 'You speak the Old Tongue into the earth and call a Wild-Blood spirit from the spaces between — a primal draconic entity born of the dragons who became forests, rivers, and mountains. A fey-like creature of challenge rating 6 or lower manifests in an unoccupied space you can see. The spirit is friendly to you and your companions for the duration, acting on its own turn. It obeys verbal commands (no action required), but if you give none, it defends itself. The spirit disappears when it drops to 0 hit points or the spell ends. The entity appears as a creature woven from elemental dragon essence — a stag with scales of bark, a serpent of living water, a wolf whose fur is autumn leaves — and it speaks Old Tongue. The Inquisition considers this spell a form of consorting with unsanctioned powers; if witnessed, the caster is branded a heretic.', 'When you cast this spell using a spell slot of 7th level or higher, the challenge rating increases by 1 for each slot level above 6th.', ARRAY['druid', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Conjure Fey']::text[], FALSE, TRUE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Basilisk''s Gaze', 6, 'Transmutation', '1 action', '60 feet', 'V, S, M (Pristine Aether-Core — flesh element)', 'Concentration, up to 1 minute', 'Your bloodline sigil twists into the pattern of the Stone-Wyrm — a creature so ancient its very gaze calcifies the living. A creature you can see within range must make a Constitution saving throw, its limbs stiffening as gray scales of stone creep across its skin. On a failure, it is restrained as its flesh petrifies. It must repeat the save at the end of each of its turns. If it fails three times (not necessarily consecutive), it is permanently turned to stone and subjected to the petrified condition. If it succeeds three times, the spell ends. Successes and failures need not be consecutive; track both until the target collects three of a kind. A creature turned to stone by this spell is not dead — it exists in a state of suspended animation, its soul trapped within the stone. A Greater Restoration, Scale-Mend, or similar 6th-level or greater restorative magic can reverse the effect. The stone bears swirling patterns matching the caster''s bloodline sigil. Statues left by this spell are known in the Citadel as Basilisk-Gifts and are considered sacred — they cannot be destroyed without a Sovereign''s pardon.', NULL, ARRAY['warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Flesh to Stone']::text[], FALSE, TRUE, 50, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sanctum of the Bloodline', 6, 'Abjuration', '10 minutes', 'Touch', 'V, S, M (Pristine Aether-Core — matching your bloodline element, plus Aether-Cores worth at least 1,000 GC total which are consumed by the ritual)', '24 hours', 'You consecrate a 40,000-square-foot area (up to 200 feet on a side) by walking its perimeter and marking the boundary with your bloodline sigil. The sanctum wards against specific creature types you designate — celestials, elementals, fey, fiends, or any creature with a bloodline purity of 50% or higher. Chosen creatures cannot enter the area willingly, cannot teleport into it, and take 5d10 radiant damage if they attempt to breach the ward. Additionally, you may key the sanctum to a password spoken in the Old Tongue, and you may declare a type of damage (chosen from acid, cold, fire, lightning, necrotic, or poison) to which all creatures within the sanctum gain resistance. The ward is visible as a shimmering draconic script that hovers at the boundary — readable by any who know the Old Tongue. This spell is used by noble Houses to protect their estates and by Ordained to shield cathedrals. The Inquisition uses Forbiddance to seal buildings suspected of harboring unsanctioned bloodlines.', 'When you cast this spell using a spell slot of 7th level or higher, the damage increases by 1d10 and the duration increases to 10 days (7th), 30 days (8th), or until dispelled (9th).', ARRAY['cleric']::text[], ARRAY['solis-grave', 'srd-ref', 'Forbiddance']::text[], TRUE, FALSE, 50, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aegis of the Sovereign', 6, 'Abjuration', '1 action', 'Self (10-foot radius)', 'V, S, M (Pristine Aether-Core — any element)', 'Concentration, up to 1 minute', 'You raise your bloodline sigil as a shimmering barrier extends from you in a 10-foot-radius sphere. For the duration, the sphere moves with you and remains centered on you. Any spell of 5th level or lower cast from outside the sphere cannot affect creatures or objects within it — the magic hits the barrier and unravels, its draconic syllables silenced. Even spells cast using higher-level slots are blocked if the base spell level is 5th or lower. The barrier itself is a translucent sheath in the color of your bloodline''s element, rippling like heat haze. Spells of 6th level or higher penetrate the barrier normally. You and your allies may leave and re-enter freely. The Aegis does not block spells cast from within the sphere targeting creatures outside, nor does it block breath weapons, aether-fueled devices, or spell-like abilities that do not use a spell slot. This is the most coveted defensive spell among nobles who fear assassination by rival bloodlines.', 'When you cast this spell using a spell slot of 7th level or higher, the barrier blocks spells of one level higher for each slot level above 6th.', ARRAY['sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Globe of Invulnerability']::text[], FALSE, TRUE, 50, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon''s Rebuke', 6, 'Necromancy', '1 action', '60 feet', 'V, S, M (Pristine Aether-Core — void or fire element)', 'Instantaneous', 'You speak a single syllable of the Old Tongue — the word the First Wyrm used to punish its disobedient children — and a wave of withering, dragon-borne illness crashes into a creature you can see. The target must make a Constitution saving throw. On a failure, it takes 14d6 necrotic damage as its blood runs black and its veins glow with sickly aetheric light. On a success, it takes half. The spell cannot reduce the target''s hit points below 1. The target''s flesh blisters with scale-shaped welts that persist for 1d4 days and mark the victim as having been touched by sovereign wrath. This spell is favored by Ordained as a tool of chastisement — it wounds without killing, leaving the victim alive to contemplate their transgression. Among the Houses, casting Dragon''s Rebuke on a member of a rival bloodline is considered a formal declaration of enmity.', 'When you cast this spell using a spell slot of 7th level or higher, the damage increases by 2d6 for each slot level above 6th.', ARRAY['cleric']::text[], ARRAY['solis-grave', 'srd-ref', 'Harm']::text[], FALSE, FALSE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Vitalis Surge', 6, 'Evocation', '1 action', '60 feet', 'V, S, M (Pristine Aether-Core — flesh or fire element)', 'Instantaneous', 'You call upon the Life-Wyrm — the primordial dragon whose blood became the first heartbeat. A wave of golden draconic light washes over a creature you can see, mending flesh and purging affliction. The target regains 70 hit points and is cured of blindness, deafness, and any diseases. This spell has no effect on constructs or undead. The healing manifests as a brief vision: the recipient sees the silhouette of a golden dragon unfurling its wings behind their own shadow. Survivors of near-fatal wounds describe the sensation as "waking from a fever into a dragon''s embrace." In Solis-Grave, this spell is the highest form of battlefield medicine — those who can cast it are valued above gold in any mercenary company or noble household.', 'When you cast this spell using a spell slot of 7th level or higher, the healing increases by 10 for each slot level above 6th.', ARRAY['cleric', 'druid', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Heal']::text[], FALSE, FALSE, 50, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Bloodline Communion', 6, 'Conjuration', '10 minutes', '30 feet', 'V, S, M (Pristine Aether-Core — fire element, and a feast worth at least 500 GC which is consumed)', 'Instantaneous', 'You prepare a ritual feast infused with aether drawn from a Pristine Aether-Core, and up to twelve creatures partake. The food appears as if from nowhere, arriving on golden platters wreathed in the faint glow of dragon-fire. Those who consume the feast gain 2d10 temporary hit points, become immune to poison and the frightened condition, and gain advantage on Wisdom saving throws for 24 hours. Their maximum hit points also increase by 2d10 for the same duration. The feast evokes a shared vision among the diners: they briefly see the great conclave of the First Wyrms, gathered in a hall of obsidian and starlight, and feel the warmth of belonging to a bloodline older than the world. This is the traditional spell cast before a Sovereign-led military campaign or a noble wedding. The Inquisition tolerates the practice — barely — because several bloodline saints were canonized during Bloodline Communions.', NULL, ARRAY['cleric', 'druid', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Heroes'' Feast']::text[], FALSE, FALSE, 50, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wyrm''s Beguiling Rite', 6, 'Enchantment', '1 action', '30 feet', 'V, S, M (Pristine Aether-Core — any element)', 'Concentration, up to 1 minute', 'You begin the Beguiling Rite — an ancient draconic courting dance that no mortal mind can witness without succumbing. A creature you can see within range must make a Wisdom saving throw. On a failure, it begins a comic, involuntary dance: shuffling, capering, spinning in place for the duration. Its movement speed is halved, it has disadvantage on Dexterity saving throws and attack rolls, and other creatures have advantage on attack rolls against it. As an action, the dancer can attempt a Wisdom saving throw to end the effect early. There is no sound to the rite — the target dances in silence, compelled by the geometry of your sigil alone. Bystanders report feeling an urge to tap their feet. The spell was first developed by a Lore-Keeper who witnessed the mating display of a silver dragon and spent a decade translating it into a spell. It has since become a signature of Solis-Grave bards, used as often in courtly intrigue as in battle.', NULL, ARRAY['bard', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Irresistible Dance']::text[], FALSE, TRUE, 50, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Vessel of the Usurper', 6, 'Necromancy', '1 action', 'Self', 'V, S, M (Pristine Aether-Core — void element, and a gemstone or reliquary worth at least 500 GC)', 'Until dispelled', 'You enact the Usurpation Rite — the spell that created the first God-Shroud and the sin for which the dragon Ouroborath was exiled from the First Conclave. Your soul leaves your body and enters the material component, which becomes a soul-vessel. From the vessel, you may attempt to possess a humanoid creature within 100 feet (Wisdom save negates). On a failure, your soul enters the host and the host''s soul is trapped in the vessel. You control the host body, using its physical statistics but your own mental stats, class features, and spellcasting. You cannot use the host''s class features or spellcasting. If the host body dies, your soul returns to the vessel if it is within 100 feet; otherwise, you die. If the vessel is destroyed while your soul is inside it, you die instantly with no chance of resurrection short of a Rebirth of the Bloodline. The Inquisition considers this the most heretical spell in existence — possession of another body without consent of the Dragon-Gods is an unforgivable crime. The Usurpation Rite is suppressed knowledge; grimoires containing it are burned on sight.', NULL, ARRAY['wizard', 'warlock', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Magic Jar']::text[], FALSE, FALSE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sovereign''s Decree', 6, 'Enchantment', '1 action', '60 feet', 'V, M (Pristine Aether-Core — fire element)', '24 hours', 'You speak words in the Old Tongue that resonate with the authority of a ruling wyrm, and up to twelve creatures of your choice within range must make a Wisdom saving throw. On a failure, a creature is charmed by you and follows a course of action you describe in one or two sentences —"defend this gate until relieved," "surrender your weapons and kneel," "the man in blue is an enemy — seize him" — for the duration, provided the suggestion is not obviously self-destructive. The decree must sound reasonable; asking a creature to stab itself, immolate, or betray a sworn blood-oath will automatically end the spell for that creature. A creature that saves is unaware you attempted to influence it. The words carry a physical weight — listeners feel pressure on their chest, as if a dragon''s claw rests there. This is the spell of rulers, not warriors. It has ended more blood feuds than any blade.', 'When you cast this spell using a spell slot of 7th level or higher, the duration increases to 10 days (7th), 30 days (8th), or 1 year and 1 day (9th).', ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Mass Suggestion']::text[], FALSE, FALSE, 50, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Solar Wyrm''s Radiance', 6, 'Evocation', '1 action', 'Self (60-foot line)', 'V, S, M (Pristine Aether-Core — fire element)', 'Concentration, up to 1 minute', 'You hold your bloodline sigil before you like a lens, and a blazing beam of golden-white dragon-light — the radiance of the Solar Wyrm, the dragon who ate a star — shines forth in a line 5 feet wide and 60 feet long. Each creature in the line must make a Constitution saving throw, taking 6d8 radiant damage on a failure or half on a success. A creature that fails is also blinded until the end of your next turn. On each of your subsequent turns, you can use your action to sweep the beam in a new direction. Undead and creatures of the Void take double damage from this spell and have disadvantage on the saving throw. The light is considered true sunlight; creatures with sunlight sensitivity react accordingly. The beam burns with the color of your bloodline — golden for fire, silver-white for storm, pale blue for frost — but always carries the unmistakable quality of dragon-light. Lore-Keepers sing that the Solar Wyrm''s Radiance was the first spell ever cast: the moment the First Wyrm used its own light to create the sun.', NULL, ARRAY['druid', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Sunbeam']::text[], FALSE, TRUE, 50, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon''s Third Eye', 6, 'Divination', '1 action', 'Touch', 'V, S, M (Pristine Aether-Core — any element, and ointment made from dragon-scale powder)', '1 hour', 'You anoint a willing creature''s brow with dragon-scale ointment, tracing the sigil of the All-Seeing Wyrm — a dragon so ancient it grew a third eye to watch over its entire bloodline simultaneously. For the duration, the creature has truesight out to 120 feet, noticing secret doors hidden by magic, seeing into the Ethereal Plane, and perceiving the true form of shapechangers and creatures under illusion. The creature can also see the aetheric glow around magical objects and effects, and can perceive the bloodline sigil that hovers faintly above any creature with purity 10% or higher. The recipient''s eyes split vertically during the spell''s duration — a second pupil forms, golden and slit-pupiled. This is painless but deeply unsettling to observers. The effect cannot be hidden without magical disguise. Ordained use this spell to verify bloodline claims during Citadel ceremonies. The Inquisition''s most feared agents — the Scale-Eyes — all bear a permanent version of this spell burned into their sight.', NULL, ARRAY['bard', 'cleric', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'True Seeing']::text[], FALSE, FALSE, 50, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Rime-Scale Wall', 6, 'Evocation', '1 action', '120 feet', 'V, S, M (Pristine Aether-Core — frost element)', 'Concentration, up to 10 minutes', 'You exhale a long breath that freezes into a wall of interlocking draconic scales made of solid ice. The wall appears on a solid surface in a line up to 60 feet long, 20 feet high, and 1 foot thick, or a hemispherical dome up to 30 feet in diameter. When the wall appears, each creature within its area must make a Dexterity saving throw, taking 10d6 cold damage on a failure or half on a success. The wall is opaque, providing total cover, with AC 12 and 30 hit points per 10-foot section. A destroyed section leaves a curtain of frigid mist that deals 2d6 cold damage to any creature passing through it for the remaining duration. If a creature is touching the wall when it takes fire damage, the wall absorbs some of the heat — the creature takes an additional 5d6 cold damage as the rime-scales flash-melt and refreeze around its flesh. The wall''s surface is etched with the caster''s bloodline sigil in frost patterns that reform if scraped away.', 'When you cast this spell using a spell slot of 7th level or higher, the damage increases by 2d6 for each slot level above 6th.', ARRAY['wizard', 'druid', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Wall of Ice']::text[], FALSE, TRUE, 50, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Call of the Dragon Court', 6, 'Conjuration', '1 minute', '60 feet', 'V, S, M (Pristine Aether-Core — fire element, and an offering appropriate to the entity called, worth 500-5,000 GC)', 'Instantaneous', 'You perform the Summoning Rite and beseech the Dragon Court — the celestial parliament of the Dragon-Gods — for aid. An emissary from the Court arrives: a draconic celestial spirit in a form appropriate to the request. You may ask the emissary to perform one task: deliver a message anywhere in the planes, guide you and up to eight companions through a dangerous region for 8 hours, provide knowledge about a specific bloodline or draconic artifact, or fight alongside you in a single battle (treat as a celestial of CR 5 or lower). The emissary''s form reflects the nature of the request — a small golden dragon for messages, a hound of silver fire for guidance, a luminous serpent for knowledge, a winged warrior of bronze for battle. The entity is not compelled; if the task is dishonorable or counter to the Dragon-Gods'' interests, it may refuse or demand a greater offering. The spell''s cost in GC represents the offering; a miserly gift may be rejected outright, while a generous one may earn the emissary''s favor and a potential ongoing relationship. Ordained who cast this regularly are considered to have a "seat at the Court" — a mark of the highest clerical prestige.', NULL, ARRAY['cleric', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Planar Ally']::text[], FALSE, FALSE, 50, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Hearth-Sigil', 6, 'Conjuration', '1 action', '5 feet', 'V, M (Pristine Aether-Core — fire element, and a sanctuary prepared with your bloodline sigil)', 'Instantaneous', 'You trace the Hearth-Sigil — the first sigil every bloodline child learns, the mark of home — and you and up to five willing creatures within 5 feet are instantly transported to a sanctuary you have previously consecrated. The sanctuary must be a place strongly linked to your bloodline: your ancestral home, a temple dedicated to your family''s dragon patron, or a location where you have spent at least 24 hours performing a binding ritual. The destination must be on the same plane of existence. If no sanctuary exists, the spell fails and the slot is wasted. Teleportation is silent and instantaneous; one moment you are there, the next you smell the incense of your safehold. Each bloodline''s Hearth-Sigil is unique and cannot be replicated — it is as personal as a signature. This is the spell every noble parent teaches their children first. In a world of Inquisitors and blood feuds, the ability to go home is worth more than any weapon.', NULL, ARRAY['cleric', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Word of Recall']::text[], FALSE, FALSE, 50, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sovereign''s Mandate', 6, 'Enchantment', '1 action', '30 feet', 'V, S, M (Pristine Aether-Core — fire element)', 'Concentration, up to 1 minute', 'Your bloodline authority manifests as an overwhelming draconic presence, and you issue a single-word command in the Old Tongue to up to six creatures of your choice within range. Each target must make a Wisdom saving throw. On a failure, a creature is compelled to follow the command on its next turn. The command must be a single word — Kneel, Flee, Halt, Drop, Grovel, Approach — and a creature that cannot hear you or does not share a language with you has advantage on the save. The command is not telepathic; the creatures hear the word spoken in the Old Tongue, and its meaning is felt viscerally regardless of language. A creature ordered to take directly harmful action (such as "Jump" off a cliff) is unaffected, but indirect danger ("Flee" through a trap-filled hall) is permitted. The Sovereign''s Mandate is not a request — it is an assertion of blood-right. Creatures with 50% or higher purity have advantage on the save, as their own bloodlines resist subjugation. This spell is a core component of the Rite of Ascension, used to establish a new Sovereign''s authority before the assembled Houses.', 'When you cast this spell using a spell slot of 7th level or higher, you can affect two additional creatures for each slot level above 6th.', ARRAY['sovereign', 'bard', 'cleric']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, TRUE, 50, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Debt of Crimson', 6, 'Necromancy', '1 action', '60 feet', 'V, S, M (Pristine Aether-Core — void or flesh element, and a drop of the target''s blood or a personal possession)', 'Concentration, up to 1 minute', 'You invoke the Blood Debt — an ancient pact-law that binds Penitents to their patrons — and turn it upon a creature. One creature you can see must make a Charisma saving throw. On a failure, crimson sigils of debt burn into its forearms, and at the start of each of its turns for the duration, it takes 4d6 psychic damage as its own bloodline rebels against it, the unpaid debt gnawing at its soul. The creature can repeat the save at the end of each of its turns, ending the effect on a success. On a successful initial save, the target takes half the initial damage and suffers no ongoing effect. A creature killed by this spell leaves a corpse with its bloodline sigil inverted — a mark of a broken pact that any Penitent or Inquisitor can identify. The Debt of Crimson bypasses resistance to psychic damage because it targets the bloodline rather than the mind. This spell is the signature of Penitents who serve the Void-Wyrm, but it has been adopted by other warlocks whose patrons demand payment.', 'When you cast this spell using a spell slot of 7th level or higher, the ongoing damage increases by 1d6 for each slot level above 6th.', ARRAY['warlock', 'sovereign']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, TRUE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Leyline Communion', 6, 'Divination', '1 action', 'Self', 'V, S, M (Pristine Aether-Core — any element)', 'Instantaneous', 'You open your bloodline to the draconic ley lines that crisscross the world — the invisible veins of aether left by the First Wyrms as they shaped creation. For the next hour, your purity is treated as 10% higher for the purposes of Spell Safety DC calculations only, and you gain the ability to sense the direction and distance of the nearest Dragon-Touched Location within 1 mile. Additionally, you may ask the ley lines one question about the history of the area you stand in — the resonance of draconic magic that has been cast here, the bloodlines that have passed through, or the presence of any slain dragons whose bones still pulse beneath the earth. The answer arrives as a vision: a flash of images and Old Tongue syllables lasting no more than 6 seconds. The ley lines do not know the future and cannot reveal information deliberately hidden by a creature of greater purity than your own. Druids and Wild-Bloods favor this spell for locating ancient dragon graves and avoiding areas tainted by Inquisitor wards.', 'When you cast this spell using a spell slot of 7th level or higher, the purity bonus increases to +15% (7th) or +20% (8th+), and you may ask one additional question per slot level above 6th.', ARRAY['druid', 'cleric', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'homebrew']::text[], TRUE, FALSE, 50, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sigil of Concealment', 6, 'Abjuration', '1 action', 'Self', 'V, S, M (Pristine Aether-Core — any element)', '8 hours', 'You draw your bloodline sigil inward — a painful act of magical suppression — wrapping your draconic heritage in a sheath of null-aether. For the duration, your bloodline is undetectable to Inquisitor wards, Scale-Eye agents, Dragon''s Third Eye, and any spell or effect that detects or reveals bloodline purity. Your purity is treated as 0% for the purposes of any detection effect (but NOT for spellcasting — you cast using your actual purity). Additionally, you ignore the -10% purity penalty for Inquisitor proximity while this spell is active. The concealment is not perfect: if you cast a spell of 4th level or higher, the Sigil flickers for 1 round, during which detection is possible. Casting a spell of 6th level or higher immediately ends the concealment. The suppression is uncomfortable — many casters describe it as "holding your breath for hours" — and you have disadvantage on Constitution saving throws to maintain concentration on other spells. This spell is essential for any unsanctioned caster operating within a Citadel-patrolled city.', NULL, ARRAY['sorcerer', 'warlock', 'wizard', 'sovereign', 'bard', 'druid']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, FALSE, 50, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blade of the Wyrm-King', 7, 'Evocation', '1 action', '60 feet', 'V, S, M (Pristine Aether-Core — fire or storm element)', 'Concentration, up to 1 minute', 'You conjure a blade-shaped rift of pure draconic aether — the sword-form of Ourobathrax the Wyrm-King, first sovereign of dragonkind — that hovers in an unoccupied space within range. The blade is a shimmering plane of force roughly the size and shape of a greatsword, glowing with the color of your bloodline. When it appears, you may make a melee spell attack against a creature within 5 feet of the blade, dealing 4d12 force damage on a hit. As a bonus action on each of your subsequent turns, you can move the blade up to 20 feet and repeat the attack against a creature within 5 feet of its new position. The blade can also be mentally commanded to attack a creature within range as your action. The sword is semi-sentient and will hum the Old Tongue word for "mercy" when near a creature with lower purity than the caster — a detail that unnerves even experienced casters. The blade passes through nonmagical barriers but cannot harm ethereal creatures.', 'When you cast this spell using a spell slot of 8th level or higher, the damage increases by 1d12 for each slot level above 7th.', ARRAY['bard', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Mordenkainen''s Sword']::text[], FALSE, TRUE, 50, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Delayed Cinder Burst', 7, 'Evocation', '1 action', '150 feet', 'V, S, M (Pristine Aether-Core — fire element)', 'Concentration, up to 1 minute', 'You conjure a bead of compressed draconic fire — a miniature star no larger than a pearl — and place it at a point within range, where it hovers, pulsing with building pressure. The bead glows faintly in colors that shift through your bloodline''s spectrum and hums at a frequency just below hearing. At the end of your turn, if the bead has not yet detonated, its damage increases by 1d6. You may use a bonus action on a subsequent turn to detonate it early, or it detonates when the spell ends. When it explodes, each creature in a 20-foot-radius sphere must make a Dexterity saving throw. On a failure, a creature takes fire damage equal to the accumulated total (base 12d6, plus 1d6 per round delayed, maximum 22d6 after 10 rounds). On a success, it takes half. The explosion leaves no smoke — only a brief, blinding flash and a circle of blackened ground. Anything flammable not worn or carried ignites. The bead can be moved up to 30 feet as a bonus action, and it detonates early if touched by a creature. The Delayed Cinder Burst was invented by an Archon Caster who wanted to give enemies time to reconsider their choices.', 'When you cast this spell using a spell slot of 8th level or higher, the base damage increases by 1d6 for each slot level above 7th.', ARRAY['sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Delayed Blast Fireball']::text[], FALSE, TRUE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon-God''s Edict', 7, 'Evocation', '1 bonus action', 'Self (30-foot radius)', 'V', 'Instantaneous', 'You speak a single utterance of the Old Tongue — a word so potent that lesser dragons go their entire lives without earning the right to hear it. The word erupts from you in a 30-foot-radius pulse of divine draconic authority. Each creature of your choice within range must make a Charisma saving throw. The edict''s effect depends on the target''s current hit points and its purity relative to your own. Creatures with 20 hit points or fewer are instantly deafened and rendered unconscious for 1 hour (until damaged or shaken awake). Creatures with 30 hit points or fewer that fail are blinded, deafened, and stunned for 1 minute. Creatures with 40 hit points or fewer that fail are deafened and blinded for 1 minute. All other creatures that fail are deafened for 1 minute. Creatures with purity equal to or greater than your own have advantage on the save, and creatures with a purity of 75% or higher are immune to all effects except deafness. The word also instantly kills all nonmagical plants within range and banishes any celestial, elemental, fey, or fiend with fewer than 15 hit points to its home plane. The Inquisition has approved exactly three recorded uses of this spell in Citadel history; each was followed by a century of theological debate.', NULL, ARRAY['cleric', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Divine Word']::text[], FALSE, FALSE, 50, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Step Between Scales', 7, 'Transmutation', '1 action', 'Self', 'V, S, M (Pristine Aether-Core — void or storm element)', 'Up to 8 hours', 'You perform the Scale-Parting Rite and step sideways through the boundary of the material world into the Ethereal Plane — the space between the scales of the Great Wyrm whose body is the universe. You and up to three willing creatures within 10 feet enter the Border Ethereal, a gray mist-world where solid objects appear as ghostly outlines. In the Border Ethereal, you can move in any direction (including up and down) at half speed, pass through solid objects, and perceive the Material Plane out to 60 feet. Creatures and objects on the Material Plane cannot perceive or interact with you. You cannot affect or be affected by anything on the Material Plane except force damage, abjuration effects, and creatures that also exist on the Ethereal Plane. When the spell ends, you and your companions return to the Material Plane at your current positions, which may be inside solid objects — resulting in 1d10 force damage and shunting to the nearest unoccupied space. The Ethereal Plane in Solis-Grave is known as the Space Between Scales, and it is said that if you travel far enough, you can see the outline of the World-Wyrm''s eye watching you.', NULL, ARRAY['cleric', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Etherealness']::text[], FALSE, FALSE, 50, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon''s Death Mark', 7, 'Necromancy', '1 action', '60 feet', 'V, S, M (Pristine Aether-Core — void element)', 'Instantaneous', 'You point at a creature, and your bloodline sigil appears on its chest as a black brand, burning through armor and flesh alike. The target must make a Constitution saving throw. On a failure, it takes 7d8 + 30 necrotic damage as the Death Mark consumes its life force. On a success, it takes half. A humanoid killed by this spell rises at the start of your next turn as a dread dredged permanently under your control (no action required to command, but you may only control one such dredged at a time). The risen creature retains the black brand on its chest — a permanent mark visible to any who know draconic lore, identifying it as having been slain by a caster of the Death Mark. The brand cannot be removed by any means short of a Rebirth of the Bloodline or Wish. This spell is forbidden by every Sovereign House and the Citadel alike — it is considered a direct violation of the Compact of the Wyrm-Council, which prohibits the enslavement of souls through draconic magic. Casting it is punishable by immediate Pyre execution, no trial permitted.', 'When you cast this spell using a spell slot of 8th level or higher, the damage increases by 1d8 + 5 for each slot level above 7th.', ARRAY['sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Finger of Death']::text[], FALSE, FALSE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Cinder-Tide', 7, 'Evocation', '1 action', '150 feet', 'V, S, M (Pristine Aether-Core — fire element)', 'Instantaneous', 'You sweep your arms wide, and a tide of roaring dragon-fire crashes across the battlefield, shaping itself around allies with draconic precision. Choose a point within range, then designate up to ten 10-foot cubes within 150 feet of that point — each cube must be adjacent to at least one other cube, forming a contiguous inferno. Each creature in the area must make a Dexterity saving throw, taking 7d10 fire damage on a failure or half on a success. The fire consumes plants in the area automatically, but you may choose for the flames to spare plant life by selectively cooling the edges of your cubes. The Cinder-Tide is the signature battlefield spell of House Pyre; their Archons can be identified by the precise geometric burn patterns they leave on warfields. Unlike a normal fireball, the Cinder-Tide carries the intelligence of the draconic bloodline that fuels it — it will not burn the caster''s bloodline allies unless the caster wills it (though allies of different blood are not protected). The spell leaves the ground hot for 1 minute, dealing 2d4 fire damage to any creature that ends its turn prone on the affected area.', 'When you cast this spell using a spell slot of 8th level or higher, the damage increases by 1d10 for each slot level above 7th.', ARRAY['cleric', 'druid', 'sorcerer', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Fire Storm']::text[], FALSE, FALSE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wyrm''s Grip', 7, 'Evocation', '1 action', '100 feet', 'V, S, M (Pristine Aether-Core — any element, plus powdered scale worth 1,500 GC)', '1 hour', 'You clench your fist and speak the binding-word of the First Wyrm, creating an immobile, invisible prison of force shaped from the concept of a dragon''s closed claw. Choose a 20-foot cube or a 10-foot radius cage within range. For the duration, nothing — not physical matter, not magic, not even aetheric projection — can enter or exit the zone without your permission. Creatures inside cannot leave by nonmagical means. Creatures may attempt a Charisma saving throw to escape via teleportation or planar travel. The prison is immune to all damage and cannot be dispelled by Dispel Magic or similar effects of 6th level or lower. A Disintegrate spell destroys the prison instantly, as does the touch of a God-Shroud Armor. The Wyrm''s Grip is visible only as a faint shimmer at the boundaries when viewed through a Dragon''s Third Eye or similar truesight. The Inquisition uses this spell to hold high-value prisoners awaiting trial; its use against noble bloodlines without Citadel authorization constitutes an act of war between Houses.', NULL, ARRAY['bard', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Forcecage']::text[], FALSE, FALSE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Shroud Mirage', 7, 'Illusion', '10 minutes', 'Sight', 'V, S, M (Pristine Aether-Core — storm or void element)', '10 days', 'You weave an illusion so vast and so profound that it bends the perception of an entire landscape into the shape of your will. Choose a square area up to 1 mile on each side within range. For the duration, you reshape the terrain''s appearance, sound, smell, and even tactile sensation. A ruin can become a glittering citadel, a desert can bloom as a lush forest, a battlefield can become a tranquil lake — and the illusion is tangible enough that creatures can interact with its false structures, walk on illusory bridges, and feel the warmth of phantom fire. Structures created by the mirage can provide cover but cannot actually harm creatures (an illusory cliff cannot cause falling damage — a creature that steps off "falls" through the illusion and reappears prone on the real ground beneath). Creatures that physically interact with an illusory feature may make an Intelligence (Investigation) check against your spell save DC to disbelieve that specific feature; once disbelieved, the illusion becomes faint and translucent to that creature. The mirage does not mask creatures within the area and does not change the terrain''s actual geography. This spell is used by nobles to hide their estates, by generals to deceive enemy armies, and by Penitents to conceal the entrances to patron sanctums.', NULL, ARRAY['bard', 'druid', 'wizard', 'sovereign', 'warlock']::text[], ARRAY['solis-grave', 'srd-ref', 'Mirage Arcane']::text[], FALSE, FALSE, 50, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Void-Walk', 7, 'Conjuration', '1 action', 'Touch', 'V, S, M (Pristine Aether-Core — void element, and a forked metal rod attuned to the destination plane)', 'Instantaneous', 'You trace the Crossing-Sigil — the pattern that marks the boundary where the World-Wyrm''s body ends and the Void begins — and tear open a momentary rift. You and up to eight willing creatures who link hands in a circle are transported to another plane of existence. You may specify a target destination in general terms ("the Obsidian Court of the Void-Wyrm," "the highest peak of the Cinder-Sovereign''s domain," "a location within 5 miles of the Infernal Duke''s throne") and the spell places you in the nearest corresponding location. To reach a specific location, you need an object attuned to that plane — a scale from a dragon native to it, soil from its ground, water from its seas. The transition is violent: the aetheric pressure of void-walking causes all travelers to take 2d10 force damage (no save) unless they possess a purity of 50% or higher, in which case their bloodline insulates them. The rift closes behind you with a sound like a thunderclap. If cast on a creature unwilling to travel, it must make a Charisma saving throw; on a success, only that creature is left behind. This spell is the only means of reaching the Dragon Court''s celestial halls without dying first. Lore-Keepers warn that void-walking too often stretches the soul thin — casters who have used this spell more than a dozen times report hearing whispers from the Void even when alone.', NULL, ARRAY['cleric', 'druid', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Plane Shift']::text[], FALSE, FALSE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Chromatic Wrath', 7, 'Evocation', '1 action', 'Self (60-foot cone)', 'V, S, M (Pristine Aether-Core — fire or void element)', 'Instantaneous', 'You release a cone of raw chromatic dragonfire — the undiluted blood-fury of all five elemental wyrm-lines compressed into a single breath. Each creature in a 60-foot cone must make a Dexterity saving throw. For each target, roll a d8 to determine which draconic element strikes them: 1 = Fire (10d6 fire damage and ignites), 2 = Frost (10d6 cold damage and speed halved for 1 round), 3 = Storm (10d6 lightning damage and cannot take reactions for 1 round), 4 = Caustic (10d6 acid damage and AC reduced by 2 for 1 round), 5 = Venom (10d6 poison damage and poisoned for 1 minute), 6 = Radiant (10d6 radiant damage and blinded for 1 round), 7 = Void (10d6 necrotic damage and cannot regain hit points for 1 round), 8 = Roll twice, target struck by both (apply both damage types and effects). On a successful save, damage is halved and no secondary effects apply. The cone explodes in a kaleidoscopic blast — witnesses describe it as the most beautiful and terrifying thing they have ever seen, a rainbow made of pain. The Chromatic Wrath is the ultimate expression of draconic versatility, favored by Archons who refuse to limit themselves to a single bloodline element.', 'When you cast this spell using a spell slot of 8th level or higher, the damage for each element increases by 1d6 for each slot level above 7th.', ARRAY['sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Prismatic Spray']::text[], FALSE, FALSE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Scale-Mend', 7, 'Transmutation', '1 minute', 'Touch', 'V, S, M (Pristine Aether-Core — flesh element)', '1 hour', 'You lay your hands upon a creature and speak the name of the Flesh-Wyrm, the dragon who shaped mortal bodies from river clay and taught wounds how to close. The target regains 4d8 + 15 hit points at the start of each of its turns for the first minute of the spell''s duration (10 hit points per round at a minimum). For the remaining duration, the target regains 1 hit point at the start of each of its turns (up to 60 minutes total). Severed body members (fingers, hands, arms, legs, tail) are restored after 2 minutes of regeneration. If you have the severed part and hold it to the stump, the spell reattaches it instantly. The regeneration manifests as draconic scales forming over wounds, then flaking away to reveal healed flesh beneath. The process is warm and faintly luminous, leaving no scars except a pattern of fine scale-lines that fade over 1d4 weeks. Creatures observing the regeneration hear a distant, rhythmic thrumming — the heartbeat of the Flesh-Wyrm, still beating somewhere deep in the earth.', NULL, ARRAY['bard', 'cleric', 'druid', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Regenerate']::text[], FALSE, FALSE, 50, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Rebirth of the Bloodline', 7, 'Necromancy', '1 hour', 'Touch', 'V, S, M (Pristine Aether-Core — flesh element, and a pristine dragon scale of the same bloodline as the target, consumed by the spell)', 'Instantaneous', 'You perform the Rite of the Second Breath — the most sacred and most feared ritual in all of Solis-Grave. You touch a creature that has died within the last century (provided its soul is free and willing to return) and call it back to life. The target returns with all its hit points, its body restored to its prime condition, and any missing parts regenerated. The target''s bloodline purity resets to its maximum (as if never diminished) and all diseases, poisons, curses, and nonmagical afflictions are purged. The ritual requires a dragon scale from a creature of the target''s bloodline — without it, the soul cannot find its way back through the Sea of Aether. The ritual is physically agonizing for the caster, who takes 4d8 psychic damage that cannot be reduced (this is not Aether Burn — it is the cost of pulling a soul through the Veil). After the ritual, the caster suffers one level of exhaustion and their bloodline purity is temporarily halved for 24 hours as their body recovers from channeling the Flesh-Wyrm''s essence directly. The Inquisition permits this spell only when authorized by a full Citadel council; unsanctioned resurrection is punishable by the caster''s own execution. The Rite of the Second Breath cannot return a creature whose soul has been consumed by a God-Shroud, nor a creature that died of old age by natural causes.', NULL, ARRAY['cleric', 'bard', 'druid', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Resurrection']::text[], FALSE, FALSE, 50, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Inexorable Rise', 7, 'Transmutation', '1 action', '100 feet', 'V, S, M (Pristine Aether-Core — storm or void element)', 'Concentration, up to 1 minute', 'You invert the binding-law that the World-Wyrm used to pin the earth to its place, and gravity within a 50-foot-radius, 100-foot-high cylinder centered on a point within range reverses direction. Each creature and unattached object in the cylinder falls upward, reaching the top of the area in a single round. Upon reaching the top, creatures and objects hang there, bobbing gently, until the spell ends. When the spell ends, everything falls back to the ground, taking normal falling damage. A creature may make a Dexterity saving throw when the spell is cast, catching onto a fixed object to avoid the fall. Creatures with a fly speed may attempt to arrest their ascent with a successful Strength (Athletics) check. The experience is disorienting but not inherently nauseating — most victims describe it as "the world deciding it was finished with you." This spell is the signature of the Storm-Wyrm bloodline''s Archons, who use it to clear battlefields and to make dramatic entrances. The Inquisition has officially classified Inexorable Rise as a "weapon of aesthetic terror" after an incident in which a noble ball was disrupted by the entire dance floor ascending mid-waltz.', NULL, ARRAY['druid', 'sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Reverse Gravity']::text[], FALSE, TRUE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Echo', 7, 'Illusion', '12 hours', 'Touch', 'V, S, M (Pristine Aether-Core — flesh or void element, and a sample of the target''s blood or tissue, consumed by the spell)', 'Until dispelled', 'You perform the Echoing Rite over a sample of a creature''s blood, growing a duplicate of that creature from a vat of aether-infused clay and the blood of your own veins. The blood-echo is an illusory construct given quasi-physical form — it appears identical to the original, has the same statistics (except half the original''s maximum hit points), and possesses all the original''s memories, personality, and mannerisms up to the moment the blood sample was taken. The echo is friendly to you and obeys your spoken commands. It cannot gain levels, learn spells, or increase its purity; it is fixed at the state of the original at the time of creation. The echo knows it is a copy and behaves accordingly — most are either melancholic or aggressively devoted to proving their worth. If the echo drops to 0 hit points, it dissolves into a pool of colorless aether with a sound like a sigh. You may only maintain one blood-echo at a time; creating a second instantly destroys the first. The original creature retains no connection to the echo and cannot sense its existence. The Inquisition considers this spell an abomination — creating a conscious being solely to serve is, in their doctrine, a usurpation of the Dragon-Gods'' creative authority. Possession of a blood-echo spell scroll carries a mandatory sentence of Pyre purification.', NULL, ARRAY['wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Simulacrum']::text[], FALSE, FALSE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Threshold Step', 7, 'Conjuration', '1 action', '10 feet', 'V, M (Pristine Aether-Core — storm or void element)', 'Instantaneous', 'You speak the Traveling-Word — the Old Tongue syllable that dragons use to fold distance — and you and up to eight willing creatures within range are instantly transported to a destination you are familiar with on the same plane. Your familiarity with the destination determines the spell''s reliability. A place you have visited often ("very familiar") carries no risk of mishap. A place you have seen casually or studied on a map ("seen casually") has a 25% chance of off-target arrival (d% to determine distance and direction). A place you have only heard described ("viewed once" or "description") has a 50-75% chance of off-target arrival or complete failure. A false destination — a place that doesn''t exist — results in the caster taking 8d10 force damage as the aether rejects the impossible coordinate. The journey is instantaneous and silent; travelers experience a moment of total sensory deprivation — no sight, sound, or sensation — that lasts subjectively far longer than the objective instant. Threshold Steps are the preferred escape mechanism for noble families under siege, and the Citadel maintains a dedicated team of Ordained whose sole duty is to trace and counter hostile Threshold Steps targeting Cathedral City.', NULL, ARRAY['bard', 'sorcerer', 'warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-ref', 'Teleport']::text[], FALSE, FALSE, 50, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Draconic Ascension', 7, 'Transmutation', '1 action', 'Self', 'V, S, M (Pristine Aether-Core — fire, storm, frost, void, or flesh element, matching your bloodline)', 'Concentration, up to 1 minute', 'You surrender to your bloodline completely. Your body transforms into a half-dragon hybrid form: draconic wings erupt from your shoulder blades, scales spread across your flesh like living armor, and your eyes become vertical slits burning with elemental light. For the duration, you gain a fly speed of 60 feet, your Armor Class increases by +2 as scales harden over your vital areas, and you gain immunity to the damage type matching your bloodline element (fire for cinder, lightning for storm, cold for frost, necrotic for void, acid for flesh). Your unarmed strikes deal 2d6 slashing damage as your hands become claws. Additionally, as an action, you can unleash a breath weapon in a 30-foot cone: each creature in the area must make a Dexterity saving throw, taking 8d8 damage of your bloodline''s element on a failure or half on a success. You may use this breath weapon once when you transform and once again as an action on a subsequent turn. When the spell ends, the transformation recedes — wings fold back into your spine, scales sink beneath your skin — and you gain one level of exhaustion as your body reels from the strain of partial apotheosis. Draconic Ascension is the signature spell of the Sovereign class; it is the moment a Dragon-Heir proves their blood-right to all who witness. The Inquisition has no legal jurisdiction to interrupt a Draconic Ascension in progress — the act of transformation is, by Citadel law, a sacred event.', 'When you cast this spell using a spell slot of 8th level or higher, the breath weapon damage increases by 1d8 for each slot level above 7th, and at 9th level you may use the breath weapon three times instead of twice.', ARRAY['sovereign', 'sorcerer']::text[], ARRAY['solis-grave', 'homebrew', 'Sovereign signature']::text[], FALSE, TRUE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Pact of the Sundered Scale', 7, 'Conjuration', '1 action', 'Self (60-foot radius)', 'V, S, M (Pristine Aether-Core — void or your patron''s matching element, and a token of your pact)', 'Instantaneous', 'You tear open the aether at the site of your pact-brand, and for one terrible moment, a fragment of your patron manifests in the world — a claw, an eye, a maw of impossible geometry. Each creature of your choice within 60 feet must make a Charisma saving throw. On a failure, a creature takes 10d8 damage (the type depends on your patron: fire for the Cinder-Wyrm, lightning for the Storm-Wyrm, cold for the Frost-Wyrm, necrotic for the Void-Wyrm, acid for the Flesh-Wyrm, or radiant for a Celestial patron) and is frightened of you for 1 minute. On a success, it takes half damage and is not frightened. A creature frightened by this spell may repeat the save at the end of each of its turns, ending the effect on a success. The manifestation lasts only seconds, but its aftermath lingers: the ground within the radius is scarred with a pattern of draconic runes spelling the terms of your pact in the Old Tongue, and the area becomes a temporary aetheric dead zone — no spell of 3rd level or lower can be cast within the radius for 1 minute. Casting this spell deepens your pact-debt; your patron will demand a task within 1 week, and failure to comply causes your Pact Magic slots to diminish by one level (7th becomes 6th, etc.) until the debt is satisfied. This is the ultimate expression of Penitent power — and the ultimate reminder that borrowed power must be repaid.', 'When you cast this spell using a spell slot of 8th level or higher, the damage increases by 1d8 for each slot level above 7th.', ARRAY['warlock']::text[], ARRAY['solis-grave', 'homebrew', 'Warlock pact spell']::text[], FALSE, FALSE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether Reversal', 7, 'Abjuration', '1 reaction, which you take when you suffer Aether Burn from a failed Spell Safety save', 'Self', 'S, M (Pristine Aether-Core — any element)', 'Instantaneous', 'In the moment of Aether Burn — when the searing psychic backlash surges through your veins and your skin begins to crack with luminous pain — you slam your bloodline sigil against the current and redirect it. Instead of taking the full Aether Burn damage, you take only half. The other half is channeled outward in a 30-foot cone of your choice; each creature in the cone must make a Dexterity saving throw, taking psychic damage equal to the redirected half on a failure or no damage on a success. The backlash you redirect is raw and unstable — it appears as a spray of multicolored light, fragments of your own erased spell, and the echoing syllables of the Old Tongue you failed to speak correctly. The redirected damage carries the same properties as Aether Burn: it cannot be reduced by psychic resistance and leaves temporary glowing vein-cracks on any creature it harms. This spell can only be cast as a reaction to your own failed Spell Safety save; you cannot use it to redirect burn suffered by allies or by environmental effects. Archons who master this spell become notoriously dangerous to fight, as every miscast becomes an opportunity to harm their enemies rather than only themselves.', NULL, ARRAY['sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, FALSE, 50, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Ancestral Retribution', 7, 'Evocation', '1 action', '120 feet', 'V, S, M (Pristine Aether-Core — fire or void element)', 'Instantaneous', 'You call upon the dragon-ancestors of your bloodline, naming them one by one in the Old Tongue, and a column of blazing ancestral fire descends upon a creature you can see. The target must make a Dexterity saving throw. On a failure, it takes 12d8 radiant damage plus an additional 2d8 damage for every 25% purity the target possesses (0% = +0, 25% = +2d8, 50% = +4d8, 75% = +6d8, 100% = +8d8), as the target''s own bloodline becomes fuel for the fire. On a success, the target takes half damage and the purity-based bonus is halved (rounded down). The column of flame is not fire — it is the condensed judgment of dragon ancestors, white-gold in color, and it carries the sound of roaring from a dozen draconic throats. Creatures with 0% purity (Blanks) take only the base 12d8 damage; the spell considers them beneath its full wrath. The ground where the column strikes is permanently scorched with the caster''s bloodline sigil, a mark that persists until magically erased. In noble blood feuds, casting Ancestral Retribution on a rival Sovereign is the ultimate declaration: I do not merely oppose you — I deny your bloodline''s right to exist.', 'When you cast this spell using a spell slot of 8th level or higher, the base damage increases by 1d8 for each slot level above 7th.', ARRAY['cleric', 'sovereign']::text[], ARRAY['solis-grave', 'homebrew']::text[], FALSE, FALSE, 50, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Warden of Beasts', 8, 'Transmutation', '1 action', '30 feet', 'V, S, M (Sovereign-Fragment Aether-Core — Flesh, worth 5,500 GC)', 'Concentration, up to 1 hour', 'You trace the sigil of the Primal Wyrm — eldest of the flesh-blooded dragons, whose shed scales became the first beasts — and roar a command in the Old Tongue. Up to 3 willing or subdued creatures you can see within range transform into beasts of your choosing (CR 4 or lower). The draconic essence in their blood awakens their feral ancestry, reshaping bone and sinew in a flash of amber light. Transformed creatures retain their alignment and personality, and their game statistics become those of the chosen beast — yet their eyes retain the slitted pupils of the dragon-blooded. An unwilling creature of 75%+ purity may make a Wisdom saving throw to resist. If any transformed creature drops to 0 hit points, it reverts with its original hit points less any excess damage, as the draconic thread severs.', 'When cast at 9th level, up to 5 creatures may be targeted and the CR limit increases to 5.', ARRAY['sorcerer', 'wizard', 'sovereign', 'cleric', 'warlock']::text[], ARRAY['solis-grave', 'srd-reflavor', 'animal-shapes']::text[], FALSE, TRUE, 75, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Null-Field', 8, 'Abjuration', '1 action', 'Self (10-foot-radius sphere)', 'V, S, M (Sovereign-Fragment Aether-Core — Void, worth 12,000 GC)', 'Concentration, up to 1 hour', 'You carve your bloodline sigil into the air with a blade of condensed void-essence, and the world''s magic gutters in a sphere around you. A shimmering 10-foot-radius sphere of aetheric dead-zone surrounds and moves with you, remaining centered on you for the duration. Within the sphere, spells cannot be cast, summoned creatures wink out of existence, and magic items function only as mundane objects. Aether-Cores within the zone pulse with a sickly gray light but produce no power. Creatures of 90%+ purity who enter the zone feel physically ill — their bloodline screams against the void. Spells and magical effects of 9th level or higher are unaffected by the null-field. If a creature''s summoned form or ongoing magical effect would be suppressed, it flickers back into existence the instant it leaves the sphere. Inquisitors carry portable null-field generators powered by chained Aether-Cores — this spell was reverse-engineered from their technology by a Sovereign who died the day after perfecting it.', NULL, ARRAY['sorcerer', 'wizard', 'sovereign', 'cleric']::text[], ARRAY['solis-grave', 'srd-reflavor', 'antimagic-field']::text[], FALSE, TRUE, 75, 'Severe', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Binding Aversion', 8, 'Enchantment', '1 hour', 'Touch', 'V, S, M (Sovereign-Fragment Aether-Core — Flesh, worth 7,000 GC, saturated with drops of the caster''s own blood)', '10 days', 'You press your bleeding palm against the target object or 200-foot-cube space and whisper the name of your progenitor dragon, binding its essence into the fabric of the place. Choose a creature type (or a specific bloodline sigil). Creatures of that type who enter the area must succeed on a Wisdom saving throw or be overcome with either irresistible attraction or profound repulsion (your choice at casting). Those attracted spend each turn moving closer, unable to willingly move away; those repulsed are frightened and use their movement to flee. A creature who succeeds on the save is immune to the effect for 24 hours, though they still feel the pull — a faint itch in their blood that will not fade. The effect permeates walls, floors, and doors. An Inquisitor who enters a space warded against their bloodline cannot hide their discomfort; their movements become stiff, their breathing audible. This spell was once used by a dying dragon to seal her lair for a century.', NULL, ARRAY['sorcerer', 'wizard', 'warlock', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'antipathy-sympathy']::text[], FALSE, FALSE, 75, 'Moderate', 2, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Blood-Forged Simulacrum', 8, 'Necromancy', '1 hour', 'Touch', 'V, S, M (Sovereign-Fragment Aether-Core — Flesh, worth 15,000 GC, and a vessel of blood drawn from the target — at least 1 pint per 10 hit points)', 'Instantaneous', 'You bleed the target — or yourself — and shape a vessel from crystallized blood, bone, and the raw aether of the Flesh-Father dragon lineage. Over the hour, this grotesque chrysalis hardens, cracks, and births a perfect duplicate: a living, breathing creature identical to the original in every respect save one — it is sterile, soulless, and knows it. The duplicate has the same statistics, memories, and personality as the original at the moment of blood-drawing, but cannot gain levels, increase purity, or learn new information. It is not a construct; it bleeds, dreams, and can even grow attached to companions. It obeys your verbal commands and acts on your initiative. If the original dies within 120 days of the casting, the duplicate crumbles to crimson ash within 1 hour. Only one duplicate of a given creature may exist at a time. Casting this spell upon a prisoner — to replace them with a compliant double — is one of the Citadel''s most severe crimes, punishable by Blood-Sundering.', NULL, ARRAY['wizard', 'sovereign', 'warlock']::text[], ARRAY['solis-grave', 'srd-reflavor', 'clone']::text[], FALSE, FALSE, 75, 'Catastrophic', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Storm-Lord''s Mandate', 8, 'Transmutation', '10 minutes', 'Self (5-mile radius)', 'V, S, M (Sovereign-Fragment Aether-Core — Storm, worth 8,000 GC)', 'Concentration, up to 8 hours', 'You stretch your arms to the sky and speak the names of the four Storm-Wyrms — Thunder, Gale, Deluge, and Frost — in rapid succession. The sky answers. You take control of the weather within a 5-mile radius. You may shift the weather through stages of precipitation, temperature, and wind as a bonus action on each of your turns. Summon a blizzard to bury an advancing Inquisitor battalion. Call a heat-wave to parch their water supplies. Stir a hurricane over a coastal fortress. Each shift takes 1d4 x 10 minutes to fully manifest; the weather does not change instantly but STIRS — clouds race, winds shift, and the air thickens with the charge of draconic command. The local climate remembers this violation for 1d4 days after the spell ends. Druids (Wild-Bloods) who witness this spell being cast instinctively know the caster''s direction and distance, and most regard it as sacrilege against the primordial dragons who became weather itself.', NULL, ARRAY['sorcerer', 'wizard', 'sovereign', 'cleric']::text[], ARRAY['solis-grave', 'srd-reflavor', 'control-weather']::text[], FALSE, TRUE, 75, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon''s Pocket Realm', 8, 'Conjuration', '1 action', '60 feet', 'V, S, M (Sovereign-Fragment Aether-Core — Void, worth 12,000 GC)', '1 hour', 'You draw a doorway in the air with your bloodline sigil, and the space within the frame peels open like a split cocoon to reveal a shadowed extradimensional chamber. The door leads to a demiplane: a room up to 30 feet in each dimension, stone-floored, wood-walled, and lit by a dim aetheric glow that casts no shadows. The air within is still and carries the faint scent of old dragon — metallic, ancient, and irrevocably OTHER. When the spell ends, the door vanishes, and any creatures or objects still inside remain trapped in the demiplane. Each time you cast this spell, you may create a new demiplane or reconnect to one you previously created by using the same Aether-Core. The demiplane persists indefinitely; it is not a pocket dimension you carry, but a fixed shard of reality carved from the Void Between Scales — the space dragons pass through when they teleport. Sovereigns use these as vaults for their hoards. Inquisitors would kill to learn this spell.', NULL, ARRAY['sorcerer', 'wizard', 'warlock', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'demiplane']::text[], FALSE, FALSE, 75, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sovereign''s Dominion', 8, 'Enchantment', '1 action', '60 feet', 'V, S, M (Sovereign-Fragment Aether-Core — Flesh, worth 9,000 GC)', 'Concentration, up to 1 hour', 'You meet the target''s eyes and your pupils dilate into vertical slits — the gaze of an apex predator older than kingdoms. The target must make a Wisdom saving throw. On a failure, they are charmed and you forge a telepathic link to them that functions across any distance on the same plane. You command their will as a dragon commands its thralls. You may issue precise or general commands, and they do their best to obey. They will not knowingly self-destruct, but they will fight allies, reveal secrets, and walk into danger at your order. Each time the target takes damage, they may repeat the saving throw. A creature with 90%+ purity has advantage on the save. If you command the target to betray their bloodline — to renounce their lineage, attack their progenitor, or aid the Inquisition against their kin — the spell immediately ends and the target is immune to your enchantments for one year. The target''s eyes retain a faint amber tint for 1d4 days after the spell ends; those who know what to look for will know they were dominated.', 'When cast at 9th level, the duration becomes 8 hours and the target must be reminded of your control only once per hour to maintain it.', ARRAY['sorcerer', 'warlock', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'dominate-monster']::text[], FALSE, TRUE, 75, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Shatter-Mind Hex', 8, 'Enchantment', '1 action', '150 feet', 'V, S, M (Sovereign-Fragment Aether-Core — Void, worth 7,500 GC)', 'Instantaneous', 'You speak a single word in the Old Tongue — the word that means ''forgetting,'' the word that erases itself from the listener''s memory AS it is heard. The target must succeed on an Intelligence saving throw. On a failure, the target''s Intelligence and Charisma scores become 1. They cannot cast spells, activate magic items, understand language, or communicate in any meaningful way. They can still recognize friends, follow them, and protect themselves. The effect lasts indefinitely — the mind does not heal from this wound naturally. Every 30 days, the target may attempt a new Intelligence saving throw to end the effect. The recovery is not gradual; one day they are an animal in a human shape, the next they surface gasping from a month-long nightmare with full recollection of everything they did. Creatures with 100% purity are immune. Casting this spell on a child is punished by execution without trial in every territory that claims to be civilized. Inquisitors use a weaker, ritualized version of this on captured spellcasters to make them ''safe'' for transport.', NULL, ARRAY['wizard', 'warlock', 'sovereign', 'cleric']::text[], ARRAY['solis-grave', 'srd-reflavor', 'feeblemind']::text[], FALSE, FALSE, 75, 'Catastrophic', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Serpent''s Tongue', 8, 'Transmutation', '1 action', 'Self', 'V, S, M (Sovereign-Fragment Aether-Core — Flesh, worth 6,000 GC)', '1 hour', 'You run your tongue along your teeth, and when next you speak, your voice carries the weight of the Dragon-Gods. For the duration, you cannot speak a deliberate falsehood without taking 4d6 psychic damage as your bloodline rebels against the lie. In exchange, your words wrap around the listener''s mind like a dragon coiling around a hoard — you have advantage on all Charisma checks to deceive, persuade, or intimidate, and any Wisdom (Insight) check to determine whether you are lying automatically fails unless the observer has 75%+ purity. Magic that would detect your lies reveals only truth. For the next hour, you are the most convincing creature alive. The spell''s name is a misdirection — a serpent''s tongue is forked, speaking two ways at once. A dragon''s tongue speaks ONLY truth, but has ten thousand ways to bend that truth into whatever shape serves best.', NULL, ARRAY['sorcerer', 'warlock', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'glibness']::text[], FALSE, FALSE, 75, 'Moderate', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Scales of the Progenitor', 8, 'Abjuration', '1 action', 'Self (30-foot radius)', 'V, S, M (Sovereign-Fragment Aether-Core — Celestial, worth 10,000 GC)', 'Concentration, up to 1 minute', 'You bellow the name of your progenitor dragon and spectral scales shimmer into existence across your skin and the skin of all chosen creatures within 30 feet. For the duration, affected creatures shed dim golden light in a 5-foot radius, gain advantage on all saving throws, and other creatures have disadvantage on attack rolls against them. Fiends, undead, and creatures with 0% purity that strike a warded creature take 2d6 radiant damage as the draconic essence sears their flesh. The light is not merely illumination — it is the visual echo of the First Dragon''s presence, and Inquisitors within 1 mile can sense it as a pressure behind their eyes. Creatures warded by this spell instinctively feel kinship with one another; they know, without being told, who else bears the scales. When a warded creature kills an enemy, a small golden scale flakes from their skin and drifts to the ground, solidifying into a tiny Aether-Core fragment worth 5 GC before crumbling an hour later.', NULL, ARRAY['cleric', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'holy-aura']::text[], FALSE, TRUE, 75, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Pyre of the First Wyrm', 8, 'Conjuration', '1 action', '150 feet', 'V, S, M (Sovereign-Fragment Aether-Core — Fire, worth 8,000 GC)', 'Concentration, up to 1 minute', 'You slam your palms together and from the friction between them births a spark that belongs to the fire-dragon that ignited the first star. A churning cloud of crimson-orange smoke, shot through with veins of white-hot fire, erupts in a 20-foot-radius sphere centered on a point within range. The cloud spreads around corners and is heavily obscured. When it appears, each creature inside it must make a Dexterity saving throw, taking 10d8 fire damage on a failure or half as much on a success. A creature must also make this save when it enters the spell''s area for the first time on a turn or ends its turn there. The fire within the cloud is alive — it seems to breathe, to pulse, to curl into shapes that almost resemble a dragon, then collapse. Water cannot douse this fire; it burns even submerged. A creature killed by this spell leaves a corpse that continues to burn for 1d4 hours, and the ash left behind is warm to the touch for a full year.', NULL, ARRAY['sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'incendiary-cloud']::text[], FALSE, TRUE, 75, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Labyrinth Between Scales', 8, 'Conjuration', '1 action', '60 feet', 'V, S, M (Sovereign-Fragment Aether-Core — Void, worth 8,500 GC)', 'Concentration, up to 10 minutes', 'You exhale a breath that folds the space around the target — not air, but void, the space between a dragon''s scales magnified to infinite proportions. The target must make an Intelligence saving throw. On a failure, they are banished into a labyrinth demiplane: an endless maze of obsidian corridors, lit by the faint bioluminescence of impossible fungi, where the walls are warm to the touch and seem to shift when not directly observed. The target remains there for the duration or until they escape. To escape, the target must use its action to make a DC 20 Intelligence check, navigating the labyrinth through pure logic — instinct and tracking are useless here. On a success, they find the exit and reappear in the space they left or the nearest unoccupied space. Minotaurs and creatures with an innate sense of direction do not have advantage on this check; the labyrinth is not a physical maze but a thought-construct. Creatures of 100% purity are unaffected. The caster has no control over the labyrinth and cannot observe the trapped creature — they have merely opened the door.', NULL, ARRAY['wizard', 'warlock', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'maze']::text[], FALSE, TRUE, 75, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aegis of the Self', 8, 'Abjuration', '1 action', 'Touch', 'V, S, M (Sovereign-Fragment Aether-Core — Void, worth 7,000 GC)', '24 hours', 'You draw a tight spiral over the target''s heart with your thumb — the sigil of the Self-Dragon, the conceptual dragon that represents the sanctity of identity. For the duration, the target is immune to psychic damage, immune to any effect that would sense its emotions or read its thoughts, and immune to divination spells and magical scrying. Additionally, the target has advantage on saving throws against being charmed. The mind is sealed — a fortress of bone and bloodline that no external force can breach. The target does not dream during this spell''s duration; the dream-space simply goes dark, calm, silent. The spell foils Inquisitor blood-detection, psionic interrogation, and scrying pools alike. Even Wish cannot pierce this barrier when cast by a creature of lower purity than the caster. The only cost: when the spell ends, all the dreams that were suppressed come at once, a 24-hour cascade compressed into the first sleep after the aegis falls — unsettling but harmless. Frequent users report that their dreams begin to contain dragons watching them, judging.', NULL, ARRAY['wizard', 'sovereign', 'cleric']::text[], ARRAY['solis-grave', 'srd-reflavor', 'mind-blank']::text[], FALSE, FALSE, 75, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragonlord''s Command', 8, 'Enchantment', '1 action', '60 feet', 'V (the words must be spoken at a volume that shakes glass)', 'Instantaneous', 'You speak a single word of absolute command in the Old Tongue — and the universe, for one heartbeat, believes you are a dragon. The target must make a Constitution saving throw. If it has 150 hit points or fewer, it is stunned until the end of your next turn. If it has 50 hit points or fewer, it drops to 0 hit points and begins making death saving throws. The word you speak is different for every bloodline — this spell cannot be taught, only inherited. A caster who does not know their own bloodline''s command word can attempt the casting, but the target has advantage on the save. Undead and creatures with 100% purity are immune. Creatures killed by this word do not appear injured; they simply collapse, their blood still warm, their hearts undamaged — as if the spark of life was commanded to leave and obeyed without question. An Aether-Core is not consumed in the casting because no core can contain this word; it must be spoken directly from the caster''s blood.', NULL, ARRAY['sorcerer', 'warlock', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'power-word-stun']::text[], FALSE, FALSE, 90, 'Catastrophic', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dawn-Fire Eruption', 8, 'Evocation', '1 action', '150 feet', 'V, S, M (Sovereign-Fragment Aether-Core — Celestial, worth 9,000 GC)', 'Instantaneous', 'You raise a fist to the sky, and for the span of a held breath, a second sun ignites above the battlefield — a sphere of brilliant, blinding, cleansing dragon-fire. The sphere erupts at a point you choose within range in a 60-foot-radius blast of radiant heat and light. Each creature in that area must make a Constitution saving throw, taking 12d6 radiant damage on a failure or half as much on a success. The light is not merely bright — it is the light of the Celestial Wyrm whose flame kindled the sun itself. Creatures that have 0% purity (Blanks) are blinded for 1 minute regardless of the save result. Creatures that have 50%+ purity feel the blast as warmth, not burning — it recognizes its own. Undead, oozes, and creatures of elemental darkness have disadvantage on the saving throw and take an additional 2d6 radiant damage. The area within the blast radius is sterilized of magical darkness for 24 hours. Flowers bloom in the blast zone the following dawn.', NULL, ARRAY['sorcerer', 'sovereign', 'cleric']::text[], ARRAY['solis-grave', 'srd-reflavor', 'sunburst']::text[], FALSE, FALSE, 75, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Whisper Across Blood', 8, 'Evocation', '1 action', 'Unlimited (same plane)', 'V, S, M (Sovereign-Fragment Aether-Core — Void, worth 5,000 GC)', '24 hours', 'You prick your finger on the Aether-Core and a single drop of blood falls into the Void within it, vanishing. Name or describe a creature familiar to you. A telepathic link is forged between you and the target, spanning any distance as long as you remain on the same plane of existence. You may send and receive thoughts, images, and emotions. The target knows it is being contacted — it feels the link settle into their mind like a second heartbeat, warm and intrusive. They may accept or refuse the link, but refusing requires a Wisdom saving throw; on success, they block the connection for 24 hours and you know they blocked it. On failure, the link establishes against their will. Creatures with 75%+ purity know the caster''s identity and general direction upon being contacted. If the target is asleep, they receive your communication as a shared dream — you may appear to them in any form you choose. Inquisitors have learned to detect the faint aetheric resonance of this spell within a 500-foot radius of either participant.', NULL, ARRAY['wizard', 'sorcerer', 'warlock', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'telepathy']::text[], FALSE, FALSE, 75, 'Low', 1, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wrath of the Deep Wyrm', 8, 'Conjuration', '1 minute', 'Sight', 'V, S, M (Sovereign-Fragment Aether-Core — Frost, worth 10,000 GC)', 'Concentration, up to 6 rounds', 'You walk to the edge of a body of water — sea, river, or lake — and kneel, pressing your forehead to the surface. You whisper the true name of the Deep Wyrm, the dragon who sleeps beneath the ocean floor and whose breathing is the tides. The water answers. A wall of water 300 feet wide, 50 feet thick, and up to 300 feet high rises from the surface and surges forward at your direction. Each creature in the wall''s path must make a Strength saving throw when the wall enters its space or when it ends its turn there. On a failure, a creature takes 6d10 bludgeoning damage and is swept along in the wave; on a success, it takes half damage and may swim to the nearest edge of the wall. Creatures swept along must hold their breath or begin drowning. Structures in the wave''s path take 50 bludgeoning damage per round of contact. The wave can be commanded to change direction as a bonus action but cannot reverse course. When the spell ends, the water crashes down as a final 30-foot wave in all directions, extinguishing all non-magical flames and leaving the landscape drowned. Coastal villages that survived this spell once renamed their town ''The Soaked Remembrance.''', NULL, ARRAY['sorcerer', 'sovereign', 'cleric']::text[], ARRAY['solis-grave', 'srd-reflavor', 'tsunami']::text[], FALSE, TRUE, 75, 'Catastrophic', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('God-Shroud', 8, 'Transmutation', '1 minute', 'Touch', 'V, S, M (Sovereign-Fragment Aether-Core — Celestial, worth 25,000 GC)', '1 hour', 'You lay the Aether-Core on the target''s chest, directly over the heart, and intone the secret names of all seven progenitor dragons in reverse order — unmaking their authority to grant yourself immunity from consequence. The Aether-Core liquefies into golden light and sinks into the target''s flesh. For the next hour, the target''s blood purity is treated as 90% for all purposes: spell casting, saving throws, purity gating, and bloodline abilities. Additionally, the target is immune to Aether Burn for the duration — their blood simply refuses to acknowledge the strain. Their eyes blaze with golden draconic light, their veins visibly pulse with power, and their shadow flickers between human and dragon form. When the spell ends, the target gains 1 level of exhaustion and their purity returns to its true value. This spell cannot be cast on a creature more than once per 7 days — the bloodline needs time to recover from the strain of borrowed divinity. The Inquisition considers possession of this spell a capital crime, as it ''simulates the state of the Unclean,'' meaning the Pure Dragons. Casting it within Citadel territory is an automatic death sentence.', NULL, ARRAY['sovereign', 'cleric', 'wizard']::text[], ARRAY['solis-grave', 'homebrew', 'legendary']::text[], FALSE, FALSE, 90, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon''s Gaze', 8, 'Divination', '10 minutes', 'Self (1-mile radius history)', 'V, S, M (Sovereign-Fragment Aether-Core — Void, worth 18,000 GC, and an object from the era you wish to view)', 'Concentration, up to 1 hour', 'You sit at the center of the location you wish to view, close your eyes, and let your bloodline memory unspool backward through time. Dragons do not experience time linearly — they perceive all moments they have witnessed as a single eternal present. This spell borrows that perception. You may witness any event that occurred within 1 mile of your current location at any point in the past 1,000 years. You do not travel physically; your consciousness becomes a silent, invisible, intangible observer. You see, hear, and smell the past as it truly was — not as legend recalls it. You may view the same event from multiple angles, move freely within the 1-mile radius, and fast-forward or rewind at will. You may witness the death of a dragon, the founding of a city, the secret conversation that started a war — but you cannot interact. You cannot be detected. The past does not know you are watching. If you attempt to view an event that involves a dragon with 95%+ purity, that dragon becomes aware of your observation and may choose to end the spell early by meeting your gaze. You return to the present with a nosebleed and the unsettling certainty that something ancient now knows your name.', 'When cast at 9th level, the history window extends to 10,000 years and the range expands to 10 miles.', ARRAY['sovereign']::text[], ARRAY['solis-grave', 'homebrew', 'legendary']::text[], FALSE, TRUE, 75, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Inquisitor''s Bane', 8, 'Abjuration', '1 action', 'Self (1-mile radius)', 'V, S, M (Sovereign-Fragment Aether-Core — Void, worth 15,000 GC, and a strand of hair from an Inquisitor)', '24 hours', 'You crush the Aether-Core against the strand of Inquisitor hair and it vaporizes into a fine gray mist that spreads outward at impossible speed, settling over a 1-mile radius like morning dew that isn''t there. For the next 24 hours, Inquisitors and their blood-hounds within the affected area cannot sense bloodlines, cannot detect magic, and their divination spells return false negatives or scrambled results. Their bloodline-detection talismans flicker with static. Their trained senses report only silence. To an Inquisitor inside the field, every creature reads as 0% purity — including themselves. They know something is wrong but cannot identify what. The field does not affect dragons, only Inquisitors and their specifically trained tools. Creatures with 50%+ purity inside the field instinctively know they are ''safe from hunters'' — a deep, primal relaxation that many have never experienced. The spell was created by a Sovereign who watched her children burned. She burned ten Inquisitor strongholds in return before they caught her. The last thing she wrote before her execution was the formula for this spell, smuggled out in the lining of a guard''s coat.', 'When cast at 9th level, the radius extends to 10 miles and the duration becomes 7 days.', ARRAY['sovereign', 'warlock']::text[], ARRAY['solis-grave', 'homebrew', 'legendary']::text[], FALSE, FALSE, 75, 'Severe', 3, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Void-Soul Projection', 9, 'Necromancy', '1 hour', 'Self', 'V, S, M (Sovereign-Fragment Aether-Core — Void, worth 20,000 GC, and a silver cord tied around the caster''s wrist — the cord must contain at least one thread from a dragon''s wing membrane)', 'Special (see description)', 'You lie down in a circle drawn from your own blood mixed with crushed Aether-Core dust and enter a death-trance. Your soul — a shimmering, draconic silhouette of silver light tethered to your body by the silver cord — separates and projects into the Astral Plane. In this form, you may travel the Astral Sea, visit other planes via color pools, observe the material plane as a ghost, and interact with astral entities. Your projected form uses your game statistics, cannot be harmed by non-magical attacks, and if reduced to 0 hit points you snap back to your body with 1 hit point. Your physical body remains in a catatonic state; if it is killed, you die. The silver cord is invisible to most creatures but vulnerable to astral predators — githyanki silver swords, astral dreadnoughts, and Void-dragons can sever it. If the cord is cut, your soul is cut loose: your body dies instantly in the material plane, and your soul becomes a permanent astral spirit — a ghost who remembers being alive. This is how the first Void-dragon was made: a Sovereign whose cord was severed, who refused to fade, and grew powerful enough to become something new.', NULL, ARRAY['wizard', 'warlock', 'sovereign', 'cleric']::text[], ARRAY['solis-grave', 'srd-reflavor', 'astral-projection']::text[], FALSE, FALSE, 75, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wyrm-Eye Premonition', 9, 'Divination', '1 minute', 'Touch', 'V, S, M (Sovereign-Fragment Aether-Core — Celestial, worth 15,000 GC)', '8 hours', 'You breathe a thin stream of silver vapor into the target''s eyes — the breath of an ancient dragon who saw the future and wept. For the duration, the target cannot be surprised and has advantage on attack rolls, ability checks, and saving throws. Additionally, other creatures have disadvantage on attack rolls against the target. The target is not truly seeing the future — they are seeing the INTENT of every creature around them as a ghost-image superimposed over the present moment, a fraction of a second ahead. When an enemy begins to swing a blade, the target has already moved. When a trap triggers, the target''s foot is already withdrawing. This is not reaction; it is prescience. The experience is disorienting — the target perceives themselves acting before they decide to act, watching their own body move with perfect, inhuman grace. Some develop a temporary detachment from their sense of self, as if they are a passenger in a body that knows exactly what to do. This spell was created by a dragon who wanted to teach her mortal lover what it felt like to be her — to experience time from outside it.', NULL, ARRAY['wizard', 'sovereign', 'cleric']::text[], ARRAY['solis-grave', 'srd-reflavor', 'foresight']::text[], FALSE, FALSE, 75, 'Catastrophic', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Rift Between Worlds', 9, 'Conjuration', '1 action', '60 feet', 'V, S, M (Sovereign-Fragment Aether-Core — Void, worth 50,000 GC — this core is consumed regardless of save)', 'Concentration, up to 1 minute', 'You speak the name of a planar destination and tear your hands apart. Reality splits. A shimmering portal, up to 20 feet in diameter, opens to a precise location on another plane of existence. The rift is framed by what appears to be dragon ribs — spectral bones that crackle with void-light. You may call this portal to the presence of a specific creature you name, or to a fixed location you have previously visited. The creature being called appears in an unoccupied space within 30 feet of the portal. If you call a deity or a creature of 100% purity, they may choose whether to answer; the portal opens, but nothing may emerge but silence and the faint sound of breathing from the other side. The portal is two-way — creatures from the destination plane can pass through to your location. This is not a summoning; this is a DOOR. If you open it to the domain of a hostile dragon, be prepared for what answers. The Aether-Core consumed in this casting is not shattered — it becomes the physical anchor that holds the rift open. When the spell ends, the core crumbles to inert dust.', NULL, ARRAY['sorcerer', 'wizard', 'sovereign', 'cleric']::text[], ARRAY['solis-grave', 'srd-reflavor', 'gate']::text[], FALSE, TRUE, 90, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sealed in the Dragon''s Hoard', 9, 'Abjuration', '1 minute', '30 feet', 'V, S, M (Sovereign-Fragment Aether-Core — Void, worth 35,000 GC, and a scale from the target''s progenitor dragon lineage — if the target has no lineage, a scale from any dragon will suffice)', 'Until dispelled', 'You draw the target''s bloodline sigil on the ground in powdered gemstone, place the dragon scale at its center, and recite the target''s full name — birth name, chosen name, and any titles earned. The target must make a Wisdom saving throw. On a failure, they are sealed away: entombed deep beneath the earth (as if in a dragon''s hoard-vault), chained with chains of crystallized aether in a state of suspended animation (minimus containment within a gemstone), bound to service for a year and a day (geas of absolute obedience), or simply locked into a form you choose — a beast, a statue, a tree, a fountain that weeps their memories. This imprisonment is permanent until dispelled by a 9th-level dispel magic, Wish, or the release condition you set at casting. The release condition may be as specific or as general as you like, but cannot be impossible (''when the sun rises in the west''). The target does not age, need food, drink, or air, and maintains full awareness throughout — a prisoner who can think but never move, never speak, never sleep. This spell was used by the Dragon-Gods to punish mortals who broke blood-oaths. The Citadel uses a sanitized version for high-value prisoners.', NULL, ARRAY['warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'imprisonment']::text[], FALSE, FALSE, 90, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon''s Mercy', 9, 'Evocation', '1 action', '60 feet', 'V, S, M (Sovereign-Fragment Aether-Core — Celestial, worth 20,000 GC)', 'Instantaneous', 'You speak the healing-name of the Celestial Wyrm — a sound that mortal throats were not designed to produce — and a wave of amber-gold light floods from you, washing over chosen creatures within range. Each target regains all of its hit points, all diseases and poisons affecting it are cured, and any conditions that could be ended by Greater Restoration are removed. Limbs severed within the past hour reattach as the wound rewinds; eyes burned out days ago regrow. Creatures of 50%+ purity feel the healing as warmth and gratitude — the embrace of an ancestor who has been waiting. Creatures of 0% purity (Blanks) feel it as burning, as violation, as something that should not be in their blood. They are healed regardless, but the experience leaves them shaken and distrustful of their own bodies. This spell bypasses any effect that would prevent healing, as it does not restore the body — it restores the BLOODLINE''s memory of what the body was meant to be. Undead and constructs are unaffected. The caster''s own wounds close last, as the spell always prioritizes others; it is the nature of a dragon''s mercy to protect the flock before the shepherd.', NULL, ARRAY['cleric', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'mass-heal']::text[], FALSE, FALSE, 75, 'Catastrophic', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Falling Star Cataclysm', 9, 'Evocation', '1 action', '1 mile', 'V, S, M (Sovereign-Fragment Aether-Core — Fire, worth 30,000 GC)', 'Instantaneous', 'You point to the sky and drag your finger downward, roaring a single syllable in the Old Tongue that means ''extinction.'' Four blazing meteors — each the size of a dragon''s skull, wreathed in white-hot fire and trailing streams of molten aether — scream down from the heavens and strike four points you can see. Each creature in a 40-foot-radius sphere centered on each impact point must make a Dexterity saving throw, taking 20d6 fire damage and 20d6 bludgeoning damage on a failure, or half as much on a success. A creature in overlapping spheres takes damage only once (the universe is cruel but not redundant). The impacts leave craters 30 feet deep and 60 feet wide, and each crater smolders with residual aether-flame that deals 2d6 fire damage per round to any creature that ends its turn there for the next minute. The sound is heard for 10 miles. This spell does not summon rocks from space — it calls down fragments of the Fire-dragon''s own hoard, burning jewels flung into orbit during the star-forging wars of the primordial age. Every casting permanently removes four stones from the heavens. Astronomers believe the night sky was once much brighter.', NULL, ARRAY['sorcerer', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'meteor-swarm']::text[], FALSE, FALSE, 90, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Death-Word of the Progenitor', 9, 'Enchantment', '1 action', '60 feet', 'V (must be spoken in the caster''s native form; shape-shifted casters revert to their true form for the duration of the word)', 'Instantaneous', 'You speak the final word of the Old Tongue — the word that was spoken to end the Dragon-Wars, the word that causes bloodlines to stop. Choose a creature you can see within range. If the target has 100 hit points or fewer, it dies. If it has 50 hit points or fewer, it dies instantly and its body crumbles to fine gray ash. There is no saving throw. There is no damage roll. The word unmakes the target''s bloodline connection to life — the draconic spark that animates all living things in Solis-Grave is commanded to extinguish. A creature killed by this word does not leave a corpse suitable for Raise Dead; their body is intact but the essence that animated it is gone, and only True Resurrection (or an equivalent 9th-level restoration) can return them. Undead, constructs, and creatures with 100% purity are immune — the pure dragon-blooded have passed beyond the authority of the spoken word. The word itself cannot be written down; those who attempt find their hands cramping, their pens breaking, their ink drying. It can only be learned by hearing it directly from a caster who already knows it. This spell has never been successfully countered.', NULL, ARRAY['warlock', 'sorcerer', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'power-word-kill']::text[], FALSE, FALSE, 90, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Wall of the Seven Scales', 9, 'Abjuration', '1 action', '60 feet', 'V, S, M (Sovereign-Fragment Aether-Core — Celestial, worth 40,000 GC)', '10 minutes', 'You trace a line in the air with your open palm and the light bends, shattering into seven distinct colors — one for each progenitor dragon: Cinder (crimson), Tempest (amber), Void (deep purple), Rime (pale blue), Flesh (green), Celestial (gold), and Law (silver-white). A shimmering, multicolored wall of light springs into existence at a point you choose, up to 90 feet long, 30 feet high, and 1 inch thick, oriented vertically. The wall consists of seven layers, each with a different color and effect. A creature that attempts to pass through the wall must pass through all seven layers, making a saving throw against each: Dexterity vs. 10d6 fire (red), Dexterity vs. 10d6 lightning (amber), Constitution vs. petrification for 1 minute (purple), Constitution vs. 10d6 cold (blue), Wisdom vs. 10d6 poison and restrained for 1 minute (green), Wisdom vs. blinded for 1 minute (gold), and Charisma vs. banished to a harmless demiplane for 1 minute on a failed save (silver-white). A creature that succeeds on all seven saves passes through; the layers destroyed by passage reform at the start of the caster''s next turn. The wall is opaque, but you can see through each layer as if it were tinted glass. Creatures of the same bloodline lineage as the caster have advantage on all seven saves.', NULL, ARRAY['wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'prismatic-wall']::text[], FALSE, FALSE, 90, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Assume the Ancient Form', 9, 'Transmutation', '1 action', 'Self', 'V, S, M (Sovereign-Fragment Aether-Core — Flesh, worth 30,000 GC)', 'Concentration, up to 1 hour', 'You draw your bloodline sigil across your own chest with a clawed hand — whether or not you have claws — and your body UNFOLDS. For the duration, you transform into any creature of CR 20 or lower that is not a construct or undead. Your game statistics, including mental ability scores, are replaced by the new form''s, though you retain your alignment, personality, and your bloodline purity. You may shift forms as a bonus action on each of your turns. When you transform, your equipment melds into the new form or is worn if the new form is capable. If you assume the form of a dragon, there is a 5% chance that your bloodline resonates so perfectly with the form that the transformation becomes permanent — the spell''s duration changes to ''until dispelled'' and you may remain a dragon indefinitely. This is how some ancient dragons came to be: not born, but BECOME, by a caster whose bloodline recognized its true shape. A caster slain while in dragon form who rolled the 5% leaves behind a true dragon corpse, Aether-Cores and all.', NULL, ARRAY['wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'shapechange']::text[], FALSE, TRUE, 90, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Heartbeat Suspension', 9, 'Transmutation', '1 action', 'Self', 'V (a single sharp inhalation — no exhalation follows for the duration)', 'Concentration, up to 1 minute (2d4 + 2 rounds)', 'You hold your breath, and the world stops holding its. Time freezes for every creature except you. For the duration, time ceases to flow for everyone but yourself — you take 1d4 + 1 consecutive turns while the rest of reality is suspended. Creatures are frozen in place, immune to damage, and unaffected by anything you do during the stopped time. You cannot target other creatures with spells or attacks, but you may move, interact with objects, and cast self-targeting spells. You cannot move a creature or an object worn or carried by another creature, but you may reposition yourself, set traps, read documents, or simply escape. The spell ends early if you move more than 1,000 feet from where you cast it, or if you attempt to affect a creature of 100% purity — such beings exist partially outside linear time and will notice the temporal distortion. To outside observers, your turns in stopped time appear to happen instantaneously. The physical strain of existing between heartbeats is extreme: when the spell ends, you take 4d6 psychic damage and cannot take reactions until the start of your next turn.', NULL, ARRAY['sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'time-stop']::text[], FALSE, TRUE, 90, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Bloodline Transmutation', 9, 'Transmutation', '1 action', '30 feet', 'V, S, M (Sovereign-Fragment Aether-Core — Flesh, worth 50,000 GC)', 'Concentration, up to 1 hour', 'You gesture at the target and speak the command to REWRITE — the word dragons use to shape their hoards, their lairs, their very progeny. The target must make a Wisdom saving throw. On a failure, they are permanently transformed into any creature or object you choose (CR 9 or lower for creatures, Large or smaller for objects). Their game statistics are fully replaced. They lose all class levels, spellcasting, and memories. They believe they have always been what they are now. If you transform them into a creature of a different bloodline than their own, their purity adjusts to the new form''s baseline. If you transform them into an object, they are a mundane item of your description, conscious but unable to act. A creature transformed into an object does not age, need sustenance, or perceive the passage of time in the same way — a year is a slow blink. This transformation is permanent until dispelled (requiring a 9th-level dispel or Wish), or until the target''s new form drops to 0 hit points, at which point they revert with their original hit points. The target retains its original alignment and, deep within, a nagging sense that something is wrong — dreams of scales, of fire, of a language they knew once but cannot quite remember. This spell cannot force a creature to act against its blood-oath.', NULL, ARRAY['wizard', 'warlock', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'true-polymorph']::text[], FALSE, TRUE, 90, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Second Breath of the Fallen', 9, 'Necromancy', '1 hour', 'Touch', 'V, S, M (Sovereign-Fragment Aether-Core — Celestial, worth 50,000 GC, and a body part from a dragon of at least 90% purity — the dragon need not have died recently)', 'Instantaneous', 'You touch the remains of a creature that died no more than 200 years ago and speak the name the dragon whose body-part you bear, asking them to lend their breath — their life-force — to the fallen. If the target''s soul is free and willing, it returns to its body, which is restored to full hit points, all missing parts regrown, all diseases and curses lifted. The target returns knowing exactly who called them back and what was sacrificed. The dragon body-part used in the casting is consumed — it crumbles to ash that smells faintly of the dragon''s element. This spell can restore a creature killed by Death-Word of the Progenitor (Power Word Kill equivalent), unlike standard resurrection. It cannot restore a creature that died of old age, a creature turned undead and then destroyed, or a creature whose soul was consumed by a Void-dragon. The returned creature does not suffer the usual resurrection penalties, as they are not being pulled from the afterlife by mortal magic — they are being breathed back into existence by a fragment of draconic will. The dragon whose body-part was used becomes aware of the resurrection and may choose to contact either the caster or the returned creature within the next 1d4 days.', NULL, ARRAY['cleric', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'true-resurrection']::text[], FALSE, FALSE, 75, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Nightmare Manifest', 9, 'Illusion', '1 action', '120 feet', 'V, S, M (Sovereign-Fragment Aether-Core — Void, worth 25,000 GC)', 'Concentration, up to 1 minute', 'You reach into the target''s mind, find their deepest fear — the face of the Inquisitor that killed their mother, the sound of their own bloodline being stripped, the dragon they dream about that always, always eats them — and you pull it OUT. Every creature of your choice within a 30-foot-radius sphere centered on a point within range must make a Wisdom saving throw. On a failure, the creature''s personal nightmare becomes physically real for 1 minute: visible, audible, tangible, and hostile to them alone. A creature frightened by the nightmare takes 4d10 psychic damage at the start of each of its turns. It may use its action to make a Wisdom check against your spell save DC to disbelieve the nightmare; on a success, the spell ends for that creature. A creature that succeeds on the initial save is instead frightened until the end of its next turn and takes 4d10 psychic damage once. Undead, constructs, and creatures with 0 Intelligence are immune. Creatures with 100% purity see the nightmare as a translucent shadow and feel mild curiosity. The nightmares do not vanish when the spell ends — they remain as faint afterimages in the corners of the targets'' vision for 1d4 days. Sleep becomes difficult. The dreams feel... rehearsed.', NULL, ARRAY['warlock', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'weird']::text[], FALSE, TRUE, 75, 'Catastrophic', 4, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sovereign''s Will', 9, 'Conjuration', '1 action', 'Self', 'V (a wish spoken in the Old Tongue — the words must be precise, as the Aether interprets literally)', 'Instantaneous', 'You speak a wish aloud, and reality reshapes itself around your words. This is the fundamental meta-spell of Solis-Grave — the ability to rewrite one moment, one fact, one outcome through the sheer authority of draconic blood. The basic use of this spell allows you to duplicate any other spell of 8th level or lower without material components or Spell Safety saves. But the true power lies in greater wishes: resurrecting the dead, creating wealth, altering history, granting permanent purity increases, or undoing events that have already occurred. The cost is commensurate. The caster suffers 10d10 necrotic damage that cannot be reduced or prevented (this is the Aether reclaiming what was borrowed). The caster''s Strength drops to 3 for 2d4 days (even a dragon''s muscle rebels at this violation). And there is a 33% cumulative chance — increasing by 10% for each Wish cast beyond the first in a given year — that the caster can never cast Wish again. Additionally, a Wish that attempts to affect a dragon of 95%+ purity or alter the fundamental nature of bloodlines (beyond what Bloodline Severance or Bloodline Awakening permit) will fail — the Aether recognizes the hierarchy of power and will not let a mortal overreach the gods. The Inquisition has captured only one scroll of this spell in its entire history. They burned it.', NULL, ARRAY['sorcerer', 'wizard', 'sovereign']::text[], ARRAY['solis-grave', 'srd-reflavor', 'wish']::text[], FALSE, FALSE, 90, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Bloodline Severance', 9, 'Necromancy', '1 minute', 'Touch', 'V, S, M (Sovereign-Fragment Aether-Core — Void, worth 50,000 GC)', 'Instantaneous', 'You place your palm against the target''s chest and speak the forbidden words of Unmaking — the syllables that existed before dragons, before bloodlines, before the world. The target''s bloodline sigil flares visible on their skin, then fractures and goes dark. Their blood purity is permanently reduced to 0%. They can never cast magic again. If the target is a Sovereign or possesses 75%+ purity, they may make a Constitution saving throw against your spell save DC. On a success, their purity is reduced to 10% instead. This spell cannot be countered, cannot be dispelled, and ignores Aether Burn immunity. The caster suffers 10d10 psychic damage when casting this spell (no save, no resistance). This damage ignores temporary hit points.', NULL, ARRAY['sovereign']::text[], ARRAY['solis-grave', 'homebrew', 'legendary']::text[], FALSE, FALSE, 90, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Dragon Apotheosis', 9, 'Transmutation', '1 action', 'Self', 'V, S, M (Sovereign-Fragment Aether-Core — Flesh, worth 50,000 GC, and a scale from an Ancient Dragon of the type you wish to become)', 'Concentration, up to 1 minute', 'You hold the dragon scale against your heart and it sinks into your chest like a stone into still water. Your body screams — not in pain, but in recognition. You transform into an Ancient Dragon of your bloodline''s element for 1 minute. Your size becomes Gargantuan. Your statistics are replaced by the Ancient Dragon''s (CR 20-24), though you retain your mental ability scores, alignment, personality, and class features that do not require a humanoid form. You gain the dragon''s breath weapon, legendary actions, frightful presence, and damage immunities. Your bloodline purity is treated as 100% for the duration, making all Spell Safety saves auto-succeed and granting immunity to Aether Burn. You are, for sixty seconds, what your ancestors were. When the spell ends, your body collapses back to its original form and you gain 3 levels of exhaustion. If you are reduced to 0 hit points while in dragon form, you revert and fall unconscious normally. The dragon scale used in casting is not consumed — it emerges from your chest when the spell ends, warmer than before, and pulses faintly with a heartbeat that matches yours. This spell can only be cast once per year; the bloodline needs that long to forget what it became and settle back into a mortal shape.', NULL, ARRAY['sovereign']::text[], ARRAY['solis-grave', 'homebrew', 'legendary']::text[], FALSE, TRUE, 100, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Citadel Sundering', 9, 'Evocation', '1 minute', '500 feet', 'V, S, M (Sovereign-Fragment Aether-Core — Fire, worth 40,000 GC)', 'Instantaneous', 'You raise both arms to the sky and inhale — a breath that goes on too long, drawing more air than your lungs can possibly hold, pulling aether from the air itself until your veins glow white-hot beneath your skin. Then you exhale. A beam of concentrated draconic fury — sixty feet wide, impossibly bright, the color of whatever element your bloodline carries — erupts from your mouth and slams into a structure within range. The target structure takes 500 force damage (this is not rolled; it is the minimum). Each creature inside the structure when the beam strikes must make a Dexterity saving throw, taking 20d10 damage of your bloodline''s element on a failure, or half on a success. Structures reduced to 0 hit points by this spell do not merely collapse — they are VAPORIZED, leaving a smoldering crater and scattered stones that glow with residual heat for 1 week. The blast is visible for 50 miles. The sound is heard for 100. The caster takes 8d10 fire damage from the sheer heat of channeling this much power and cannot speak (including verbal components) for 1d4 hours afterward as their throat heals. This spell was used exactly three times in recorded history: once by a dragon against a rival''s lair (the dragon died in the casting), once by a cabal of Archons against an Inquisitor citadel (two of the five casters died), and once by a Sovereign child who watched her family burn and did not scream — she exhaled. The Inquisitor citadel at Thornfield has never been rebuilt.', NULL, ARRAY['sovereign', 'sorcerer']::text[], ARRAY['solis-grave', 'homebrew', 'legendary']::text[], FALSE, FALSE, 90, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Aether Reckoning', 9, 'Conjuration', '1 action', 'Special (see description)', 'V, S, M (Sovereign-Fragment Aether-Core — Void, worth 35,000 GC, and a copy of your pact contract — written in your own blood on vellum made from the skin of a creature your patron slew)', 'Instantaneous', 'You hold your pact contract before you and speak the invocation of ultimate debt — the clause every patron buries in the fine print, the clause that says a Patron''s power is not a gift but a LOAN, and loans may be called due. You summon your patron — or a significant fragment of their power — to your location. The patron must answer. For the next 1 minute (no concentration required), your patron''s power manifests directly: you may cast any spell of 8th level or lower without expending a spell slot, without material components, and without making a Spell Safety save. You may do this once per round for 10 rounds. Your blood boils with borrowed power. Your patron cannot harm you during this minute — the contract forbids it. But when the reckoning ends, the debt comes due. Your patron names a task. It may be anything: retrieve an artifact, kill a target, protect a bloodline, destroy a faction. The task must be completable within one year and cannot directly violate your alignment. You are bound by your blood to complete it. If you fail, your pact is severed permanently — you lose all warlock levels, all Mystic Arcanum, and your purity drops to 0%. Some patrons, the kinder ones, will offer a second chance with interest. Most will not. This spell cannot be counter-offered or renegotiated. It is the final clause. Use it only when the alternative is death — because for a Penitent, death may be preferable to what comes after.', NULL, ARRAY['warlock']::text[], ARRAY['solis-grave', 'homebrew', 'legendary']::text[], FALSE, FALSE, 90, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Bloodline Awakening', 9, 'Transmutation', '1 hour', 'Touch', 'V, S, M (Sovereign-Fragment Aether-Core — Celestial, worth 50,000 GC, and 1 pint of the caster''s own blood)', 'Instantaneous', 'You cut your palm and let your blood flow into a ceremonial bowl carved from the core. The target — a willing creature with 0% purity (a Blank) — drinks. What follows is not gentle. The target''s body convulses as draconic essence floods their veins for the first time. Their eyes ignite. Their bloodline sigil — one they never knew they carried — burns into being on their skin. Their purity is permanently raised to 25%. They gain the ability to cast cantrips and may begin developing their bloodline as a Scion. The process is excruciating and takes the full hour, during which the target must succeed on three Constitution saving throws (DC 20) or die — their body simply cannot accept the gift. If they succeed all three, the awakening is complete. The caster''s blood used in the ritual is permanently lost — their maximum hit points are reduced by 10 until they complete a long rest in a dragon-touched location. A creature can only receive Bloodline Awakening once; a second attempt is fatal regardless of saves. The Inquisition considers this spell the ultimate heresy — it creates new bloodlines where none existed, directly defying the Citadel''s doctrine that purity is a fixed, divine inheritance. Any Blank who is discovered to have received this awakening is executed alongside the caster. The children of the awakened inherit their parent''s new purity — the gift echoes forward through generations.', NULL, ARRAY['sovereign', 'cleric']::text[], ARRAY['solis-grave', 'homebrew', 'legendary']::text[], FALSE, FALSE, 95, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Void Singularity', 9, 'Abjuration', '1 action', '150 feet', 'V, S, M (Sovereign-Fragment Aether-Core — Void, worth 45,000 GC)', 'Concentration, up to 1 minute', 'You hold the Void-core between your thumb and forefinger and squeeze. The core does not shatter — it IMPLODES, collapsing inward into a point of absolute nothing: a micro-singularity of anti-magic, a wound in the fabric of aether itself. The singularity appears at a point you choose within range and expands instantly to a 100-foot-radius sphere of dead magic. Within the sphere, all spells of 8th level or lower are suppressed, all ongoing magical effects are suspended, all summoned creatures vanish, and all magic items function as mundane objects. Spellcasters within the sphere cannot cast spells. Aether-Cores within the zone are rendered temporarily inert. There is no saving throw against this effect. No creature within the sphere can make a Spell Safety save — because no magic can be attempted. The sphere does not affect artifacts, spells of 9th level, or the innate physical properties of dragons (a dragon''s breath weapon still functions, though its magical enhancements do not). Creatures of 100% purity feel the singularity as pressure — unpleasant, like deep water — but are otherwise unaffected. When the spell ends, magic rushes back into the void with an audible CRACK heard within 500 feet, and all suspended effects resume as if nothing had occurred. The singularity itself is visible as a hovering, fist-sized sphere of absolute blackness at the center of the effect — not dark, but ABSENT, a hole in vision that the eye cannot focus on. Anyone who stares at it for more than 1 round must make a Wisdom saving throw or take 2d6 psychic damage from existential vertigo.', NULL, ARRAY['wizard', 'warlock', 'sovereign']::text[], ARRAY['solis-grave', 'homebrew', 'legendary']::text[], FALSE, TRUE, 90, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
INSERT INTO public.compendium_spells (name, level, school, casting_time, range, components, duration, description, higher_level, classes, source_tags, ritual, concentration, purity_requirement, aether_burn_risk, spell_safety_modifier, subclass) VALUES ('Sovereign''s Legacy', 9, 'Transmutation', '24 hours', 'Touch', 'V, S, M (Sovereign-Fragment Aether-Core — Celestial, worth 50,000 GC, and the object to be imbued — it must be masterwork quality and have personal significance to the caster)', 'Permanent (until destroyed)', 'You sit with the object for a full day and night, speaking to it. Not casting upon it — SPEAKING to it. You tell it your bloodline''s history. You tell it your fears. You tell it what you hope it will become. At the end of the 24 hours, you cut your palm and press your blood into the object, and it AWAKENS. The object becomes a sentient magic item, imbued with a fragment of your bloodline — less than 1% of your purity, but enough to grant it a mind, a personality, and a will of its own. Roll on the following table for its primary enchantment (or work with your DM to select one appropriate to your bloodline): 1 — Weapon becomes +3 with an elemental damage die (d6) matching your bloodline; 2 — Shield or armor grants resistance to your bloodline''s element; 3 — Ring or amulet allows the wearer to cast a 3rd-level spell of your choice once per day; 4 — Wondrous item grants +10% temporary purity for 1 minute, once per day; 5 — The item can transform into a CR 2 draconic creature (wyrmling or drake) for 1 hour per day; 6 — The item stores up to 5 spell levels of spells cast into it, releasing on command. The item''s personality reflects the caster''s at the moment of creation — a fearful caster creates a paranoid item; a vengeful caster creates a ruthless one. The item considers you its parent. It will not willingly harm you. If the item is destroyed, the caster immediately knows and takes 6d10 psychic damage from the severing. If the caster dies, the item goes dormant for 1d100 years, then reawakens seeking a new wielder worthy of the legacy. An artifact created this way can be passed down through generations, growing in legend and sometimes in power — the greatest Sovereign bloodlines are identified by their legacy items.', NULL, ARRAY['sovereign']::text[], ARRAY['solis-grave', 'homebrew', 'legendary']::text[], FALSE, FALSE, 95, 'Catastrophic', 5, NULL) ON CONFLICT (name) DO UPDATE SET level=EXCLUDED.level, school=EXCLUDED.school, casting_time=EXCLUDED.casting_time, range=EXCLUDED.range, components=EXCLUDED.components, duration=EXCLUDED.duration, description=EXCLUDED.description, higher_level=EXCLUDED.higher_level, classes=EXCLUDED.classes, source_tags=EXCLUDED.source_tags, ritual=EXCLUDED.ritual, concentration=EXCLUDED.concentration, purity_requirement=EXCLUDED.purity_requirement, aether_burn_risk=EXCLUDED.aether_burn_risk, spell_safety_modifier=EXCLUDED.spell_safety_modifier, subclass=EXCLUDED.subclass, updated_at=now();
